-- Poems batch 52
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('14c7275b-6c9d-44bc-80ca-84404009cb92','避寇山中作','貫休','唐','唐诗','tang','','[]','山翠碧嵯峨，攀牽去者多。',48,'全唐诗/poet.tang.45000.json','["山翠碧嵯峨，攀牽去者多。", "淺深俱得地，好惡未知他。", "有草皆爲戶，無人不荷戈。", "相逢空悵望，更有好時麽。"]'),
('74a252eb-e1c0-4cff-b958-872607a390ae','避寇上唐臺山','貫休','唐','唐诗','tang','','[]','蒼黃緣鳥道，峰脋見樓臺。',48,'全唐诗/poet.tang.45000.json','["蒼黃緣鳥道，峰脋見樓臺。", "檉桂香皆滴，煙霞濕不開。", "僧高眉半白，山老石多摧。", "莫問塵中事，如今正可哀。"]'),
('f3ec4742-6ae4-4c1b-ab2e-b3c0cb65bc23','題嶧桐律師院','貫休','唐','唐诗','tang','','[]','律中麟角者，高[淡]出塵埃。',50,'全唐诗/poet.tang.45000.json','["律中麟角者，高[淡]出塵埃。", "芳草不曾觸，幾生如此來。", "壑風吹磬斷，杉露滴花開。", "如結林中社，伊余亦願陪。"]'),
('3ff84338-4c67-4d21-a9ca-21fd8a7ce7ad','上馮使君渡水僧障子','貫休','唐','唐诗','tang','','[]','跣足拄巴藤，潺湲渡幾曾。',48,'全唐诗/poet.tang.45000.json','["跣足拄巴藤，潺湲渡幾曾。", "盡權無著印，不是登閑僧。", "熊耳應初到，牛頭始去登。", "畫來偏覺好，將寄柳吳興。"]'),
('f797c58f-66fc-4824-b457-fd739470ce47','秋夜翫月懷玉霄道士','貫休','唐','唐诗','tang','','[]','光異磨礱出，輪非雕斵成。',48,'全唐诗/poet.tang.45000.json','["光異磨礱出，輪非雕斵成。", "今宵剛道別，舉世勿人爭。", "征婦砧添怨，詩人哭到明。", "惟宜華頂叟，笙磬有餘聲。"]'),
('6d76477f-567b-4b3a-8429-eb2fb623096e','上杭州令狐使君','貫休','唐','唐诗','tang','','[]','顏冉德無鄰，分憂浙水濱。',48,'全唐诗/poet.tang.45000.json','["顏冉德無鄰，分憂浙水濱。", "愛山成大癖，求瘼似諸身。", "視事奸回盡，登樓海岳春。", "野人如有幸，應得見陶鈞。"]'),
('80109dd8-2d23-4f26-9f9c-af2f8ab30c97','懷諸葛珏二首 一','貫休','唐','唐诗','tang','','[]','諸葛子作者，詩曾我細看。',48,'全唐诗/poet.tang.45000.json','["諸葛子作者，詩曾我細看。", "出山因覓孟，踏雪去尋韓。", "謬獨哭不錯，常流飲實難。", "知音知便了，歸去舊江干。"]'),
('ffbb2dc3-d796-4db0-b4ca-86c979155601','懷諸葛珏二首 二','貫休','唐','唐诗','tang','','[]','羸馬與羸童，微吟冒北風。',48,'全唐诗/poet.tang.45000.json','["羸馬與羸童，微吟冒北風。", "店孤僧共歇，日落思無窮。", "囊草無非刺，魏人那識公。", "鶯花五陵道，去去與誰同。"]'),
('a0fab6ba-0410-41b9-b4df-e90573bc87d1','懷錢唐羅隱章魯封','貫休','唐','唐诗','tang','','[]','二子依公子，雞鳴狗盜徒。',48,'全唐诗/poet.tang.45000.json','["二子依公子，雞鳴狗盜徒。", "青雲十上苦，白髮一莖無。", "風澀潮聲惡，天寒角韻孤。", "別離千萬里，何以慰榮枯。"]'),
('8cb0d317-82e2-454a-8fb7-5596f03c26fd','送沈侍郎','貫休','唐','唐诗','tang','','[]','從知無遠近，木落去閩城。',48,'全唐诗/poet.tang.45000.json','["從知無遠近，木落去閩城。", "地入無諸俗，冠峨甲乙精。", "山多高興亂，江直好風生。", "儉府清無事，唯應薦禰衡。"]'),
('cd803d7e-c11b-455d-8586-97dd3fd5482a','題宿禪師院','貫休','唐','唐诗','tang','','[]','身閑心亦然，如此已多年。',48,'全唐诗/poet.tang.45000.json','["身閑心亦然，如此已多年。", "語淡不著物，茶香別有泉。", "古衣和蘚衲，新偈幾人傳。", "時說秋歸夢，孤峰在海邊。"]'),
('8fc62ffe-a9da-467e-ab7f-74427ac8722f','秋晚泊石頭驛有寄','貫休','唐','唐诗','tang','','[]','蕭索漳江北，何人慰寂寥。',48,'全唐诗/poet.tang.45000.json','["蕭索漳江北，何人慰寂寥。", "北風人獨立，南國信空遙。", "燒塢新雲白，漁家衆木凋。", "所思不可見，行雁在青霄。"]'),
('da1b470e-721b-44fa-a2a4-96d9be93a197','別盧使君','貫休','唐','唐诗','tang','','[]','杜宇聲聲急，行行楚水濆。',96,'全唐诗/poet.tang.45000.json','["杜宇聲聲急，行行楚水濆。", "道無裨政化，行處傲孤雲。", "幸到膺門下，頻蒙俸粟分。", "詩雖曾引玉，棊數中埋軍。", "山好還尋去，恩深豈易云。", "扇風千里泰，車雨九重聞。", "晴霧和花氣，危檣鼓浪文。", "終期陶鑄日，再見信陵君。"]'),
('72345f4c-bb4b-44cc-8070-0bbe44c532b6','秋夜吟','貫休','唐','唐诗','tang','','[]','如愚復愛詩，木落即眠遲。',48,'全唐诗/poet.tang.45000.json','["如愚復愛詩，木落即眠遲。", "思苦香消盡，更深筆尚隨。", "飢童舂赤黍，繁露灑烏椑。", "看却龍鍾也，歸山是底時。"]'),
('e4eb7117-8f24-4e2c-8c14-65738c975e89','桐江閑居作十二首 一','貫休','唐','唐诗','tang','','[]','木落雨翛翛，桐江古岸頭。',48,'全唐诗/poet.tang.45000.json','["木落雨翛翛，桐江古岸頭。", "擬歸仙掌去，剛被謝公留。", "猛燒侵茶塢，殘霞照角樓。", "坐來還有意，流水面前流。"]'),
('cc5d2a24-d230-4080-a9a7-8aa419da187a','桐江閑居作十二首 二','貫休','唐','唐诗','tang','','[]','香剎通真觀，樓臺倚郡城。',48,'全唐诗/poet.tang.45000.json','["香剎通真觀，樓臺倚郡城。", "陰森古樹氣，粗淡老僧情。", "壁畫連山潤，仙鐘扣月清。", "何須結西社，大道本無生。"]'),
('23a9a528-7aff-4962-8999-9d393ab433c0','桐江閑居作十二首 三','貫休','唐','唐诗','tang','','[]','靜室焚檀印，深爐燒鐵瓶。',48,'全唐诗/poet.tang.45000.json','["靜室焚檀印，深爐燒鐵瓶。", "茶和阿魏煖，火種柏根馨。", "數隻飛來鶴，成堆讀了經。", "何妨似支遁，騎馬入青冥。"]'),
('34ba63db-8003-44f6-8e52-3e422349a2b5','桐江閑居作十二首 四','貫休','唐','唐诗','tang','','[]','不問賡桑子，唯師妙吉祥。',48,'全唐诗/poet.tang.45000.json','["不問賡桑子，唯師妙吉祥。", "等閑眠片石，不覺到斜陽。", "獨自收櫧葉，教童探柏瓤。", "王孫莫指笑，淡泊味還長。"]'),
('2175d830-a5b5-4cf3-9256-861c224b55f7','桐江閑居作十二首 五','貫休','唐','唐诗','tang','','[]','詩琢冰成句，多將大道論。',48,'全唐诗/poet.tang.45000.json','["詩琢冰成句，多將大道論。", "人誰知此意，日日祗關門。", "乳鼠穿荒壁，溪龜上淨盆。", "因知無事貴，言外更無言。"]'),
('f95e0da2-9bf1-40d4-8259-8aff74f66bed','桐江閑居作十二首 六','貫休','唐','唐诗','tang','','[]','紅黍飯溪苔，清吟茗數杯。',48,'全唐诗/poet.tang.45000.json','["紅黍飯溪苔，清吟茗數杯。", "祗應唯道在，無意俟時來。", "樹疊藏仙洞，山蒸足爆雷。", "從他嫌復笑，門更不曾開。"]'),
('43491681-26bd-4df7-8847-eb0114f33d87','桐江閑居作十二首 七','貫休','唐','唐诗','tang','','[]','蟬急野蕭蕭，山中信屢招。',48,'全唐诗/poet.tang.45000.json','["蟬急野蕭蕭，山中信屢招。", "樹香烹菌朮，詩□□瓊瑤。", "諸境教人認，荒榛引燒燒。", "吾皇禮金骨，誰□美南朝。"]'),
('8dffe621-5c62-4f4f-a3d0-24db011ab579','桐江閑居作十二首 八','貫休','唐','唐诗','tang','','[]','露滴滴蘅茅，秋成爽氣交。',48,'全唐诗/poet.tang.45000.json','["露滴滴蘅茅，秋成爽氣交。", "霜椑如蜜裹，□□似鹽苞。", "浮蘚侵蛩穴，微陽落鶴巢。", "還如山裏日，門更絕人敲。"]'),
('859b171b-533d-4d04-8d1a-fd03b06d915b','桐江閑居作十二首 九','貫休','唐','唐诗','tang','','[]','壍鳥毛衣別，頻來似愛吟。',48,'全唐诗/poet.tang.45000.json','["壍鳥毛衣別，頻來似愛吟。", "蕭條秋病後，斑駁綠苔深。", "珠翠籠金像，風泉灑玉琴。", "孰知吾所適，終不是心心。"]'),
('da2eb8d9-4699-4a1d-b2fa-6aabe1a15c18','桐江閑居作十二首 十','貫休','唐','唐诗','tang','','[]','芙蓉峰裏居，關閉復何如。',48,'全唐诗/poet.tang.45000.json','["芙蓉峰裏居，關閉復何如。", "白玃兼花鹿，多年不見渠。", "紅泉香滴瀝，丹桂冷扶疎。", "唯有西溪叟，時時到弊廬。"]'),
('4c2b1379-b10f-401e-b172-8081c5044a01','桐江閑居作十二首 十一','貫休','唐','唐诗','tang','','[]','憶在山中日，爲僧鬢欲衰。',48,'全唐诗/poet.tang.45000.json','["憶在山中日，爲僧鬢欲衰。", "一燈常到曉，十載不離師。", "水汲冰溪滑，鐘撞雪閣危。", "從來多自省，不學擬何爲。"]'),
('cf25b759-79db-45d1-9b69-610f5d730ff4','桐江閑居作十二首 十二','貫休','唐','唐诗','tang','','[]','囊非撲滿器，門更絕人過。',48,'全唐诗/poet.tang.45000.json','["囊非撲滿器，門更絕人過。", "土井連岡冷，風簾迸葉多。", "村童頑似鐵，山菜硬如莎。", "唯有前山色，窗中無奈何。"]'),
('510ab4a1-3617-4cc0-a1f5-0e7e561f5448','寄馮使君','貫休','唐','唐诗','tang','','[]','山風與霜氣，浩浩滿松枝。',48,'全唐诗/poet.tang.45000.json','["山風與霜氣，浩浩滿松枝。", "永日燒杉子，無人共此時。", "爲文攀諷諫，得道在毫釐。", "唯有桐江守，常憐志不卑。"]'),
('98da9e6a-be05-4f84-b49c-41ea3b29ba17','經棲白舊院二首 一','貫休','唐','唐诗','tang','','[]','竺卿何處去，觸目盡淒涼。',48,'全唐诗/poet.tang.45000.json','["竺卿何處去，觸目盡淒涼。", "不見中秋月，空餘一炷香。", "殘花飄暮雨，枯葉蓋啼螿。", "誰禮新墳塔，蕭條渭水傍。"]'),
('3ae51901-884c-41b3-afab-24d227da488d','經棲白舊院二首 二','貫休','唐','唐诗','tang','','[]','國寶還亡一，時多李德林。',48,'全唐诗/poet.tang.45000.json','["國寶還亡一，時多李德林。", "故人卿相泣，承製渥恩深。", "舊藳誰收得，空堂影似吟。", "裴回不能去，寒日下西岑。"]'),
('25ea552e-e6e3-4c4a-9643-46313a813fb2','贈李祐道人','貫休','唐','唐诗','tang','','[]','闒茸復埃塵，難親復易親。',48,'全唐诗/poet.tang.45000.json','["闒茸復埃塵，難親復易親。", "皆疑有仙術，問著却愁人。", "祗是耽浮蟻，曾云見泣麟。", "相逢先合手，渾似有前因。"]'),
('cbe3e704-4cb1-42ce-8f08-1517e62a0a49','贈景和尚院','貫休','唐','唐诗','tang','','[]','藏經看幾徧，眉有數條霜。',48,'全唐诗/poet.tang.45000.json','["藏經看幾徧，眉有數條霜。", "萬境心都泯，深冬日亦長。", "窗虛花木氣，衲挂水雲鄉。", "時說秋歸夢，峰頭雪滿牀。"]'),
('cfb2a2fd-38b6-4c07-a1df-63ab004ec2ce','上宋使君','貫休','唐','唐诗','tang','','[]','折桂文如錦，分憂力若春。',48,'全唐诗/poet.tang.45000.json','["折桂文如錦，分憂力若春。", "位高空倚命，詩妙古無人。", "有感禾爭熟，無私吏盡貧。", "野人如有幸，應得見陶鈞。"]'),
('2bd335a8-d8f6-41ab-bf90-eb0c68a3c72d','離亂後寄九峰和尚二首 一','貫休','唐','唐诗','tang','','[]','亂後知深隱，菴應近石樓。',48,'全唐诗/poet.tang.45000.json','["亂後知深隱，菴應近石樓。", "異香因雪歇，仙果落池浮。", "詩老全拋格，心空未到頭。", "還應嫌笑我，世路獨悠悠。"]'),
('b935ca1c-a8d6-4181-bd4f-669a145fdf5d','離亂後寄九峰和尚二首 二','貫休','唐','唐诗','tang','','[]','蕭灑復蕭灑，松根獨據梧。',48,'全唐诗/poet.tang.45000.json','["蕭灑復蕭灑，松根獨據梧。", "瀑冰吟次折，遠燒坐來無。", "老𤣎寒披衲，孤雲靜入廚。", "不知知我否，已到不區區。"]'),
('2b198b1b-9ab1-44bb-9328-5f14fe6c4ea6','送黃賓于赴舉','貫休','唐','唐诗','tang','','[]','冬暮雨菲菲，行人喜可稀。',48,'全唐诗/poet.tang.45000.json','["冬暮雨菲菲，行人喜可稀。", "二階□夜雪，亞聖在春闈。", "馬疾頑童遠，山荒凍葉飛。", "□師無一事，應見麗龜歸。"]'),
('ee56384d-1331-4440-9bbc-06b173d75d9a','題靈溪暢公墅','貫休','唐','唐诗','tang','','[]','境清僧格冷，新斬古林開。',48,'全唐诗/poet.tang.45000.json','["境清僧格冷，新斬古林開。", "舊隱還如此，令人來又來。", "嵐飛黏似霧，茶好碧於苔。", "但使心清淨，從渠歲月催。"]'),
('04ffd72a-f1b3-4649-ad10-1515e6a583a0','送高九經赴舉','貫休','唐','唐诗','tang','','[]','回也曾言志，明君則事之。',72,'全唐诗/poet.tang.45000.json','["回也曾言志，明君則事之。", "中興今若此，須去更何疑。", "志列秋霜好，忠言劇諫奇。", "陸機遊洛日，文舉薦衡時。", "虎跡商山雪，雲痕岳廟碑。", "夫君將潦倒，一說向深知。"]'),
('1d984c45-4fc0-4a41-b4cf-89b60352f152','東西二林寺流水','貫休','唐','唐诗','tang','','[]','水爾何如此，區區矻矻流。',120,'全唐诗/poet.tang.45000.json','["水爾何如此，區區矻矻流。", "牆牆邊瀝瀝，砌砌下啾啾。", "味不卑於乳，聲常占得秋。", "崩騰成大瀑，落托出深溝。", "遠歷神仙窟，高淋竹樹頭。", "數家舂碓磑，幾處浴猿猴。", "共月穿峰罅，喧僧睡石樓。", "派通天宇闊，霤入楚江浮。", "爲潤知何極，無邊始自由。", "好歸江海裏，長負濟川舟。"]'),
('d7ecbd4c-aa8d-42a8-ab02-e79733151163','送王貞白重試東歸','貫休','唐','唐诗','tang','','[]','心苦酬心了，東歸謝所知。',48,'全唐诗/poet.tang.45000.json','["心苦酬心了，東歸謝所知。", "可鄰重試者，如折兩三枝。", "雨毒逢花少，山多愛馬遲。", "此行三可羨，正值倒戈時。"]'),
('4fafd02d-6d57-4fa9-88db-067a89caa8ba','早秋即事寄馮使君','貫休','唐','唐诗','tang','','[]','金脈火初微，開門竹杖隨。',48,'全唐诗/poet.tang.45000.json','["金脈火初微，開門竹杖隨。", "此身全是病，今日更嗔誰。", "落葉崢嶸處，諸峰爽拔時。", "唯思棠樹下，高論入圓伊。"]'),
('550739a8-64b7-4a4f-b24f-132835de272e','贈景和尚院','貫休','唐','唐诗','tang','','[]','貌古眉如雪，看經二十霜。',48,'全唐诗/poet.tang.45000.json','["貌古眉如雪，看經二十霜。", "尋常對詩客，祗勸療心瘡。", "炭火邕湖瀅，山晴紫竹涼。", "怡然無一事，流水自湯湯。"]'),
('b009a1a1-c9fa-444d-bb75-1df42230400c','寄西山胡汾','貫休','唐','唐诗','tang','','[]','待價欲要君，山前獨灌園。',48,'全唐诗/poet.tang.45000.json','["待價欲要君，山前獨灌園。", "雖然不識面，要且已消魂。", "鹿睡紅霞影，泉淋白石門。", "伊余心更苦，何日共深論。"]'),
('72f3ee07-8164-48ef-b151-a89213c368f8','題師頴和尚院','貫休','唐','唐诗','tang','','[]','師院清無敵，師心智不知。',48,'全唐诗/poet.tang.45000.json','["師院清無敵，師心智不知。", "臘高清眼細，閑甚白雲卑。", "煮茗然楓枿，泥牆札祖碑。", "愛師終不及，謾住許多時。"]'),
('4b955db8-1d3d-4dc7-bb07-c05213bfb067','遊雲頂山晚望','貫休','唐','唐诗','tang','','[]','雲頂聊一望，山靈草木奇。',48,'全唐诗/poet.tang.45000.json','["雲頂聊一望，山靈草木奇。", "黔南在何處，堪笑復堪悲。", "菊歇香未歇，露繁蟬不飢。", "明朝又西去，錦水與峨眉。"]'),
('54eba643-8818-4d0e-b957-8f245334d9da','劉相公見訪','貫休','唐','唐诗','tang','','[]','千騎擁朱輪，香塵豈是塵。',96,'全唐诗/poet.tang.45000.json','["千騎擁朱輪，香塵豈是塵。", "如何補衮服，來看衲衣人。", "莊叟因先覺，空王有宿因。", "對花無俗態，愛竹見天真。", "欹枕松窗迥，題牆道意新。", "戒師慙匪什，都講更勝詢。", "桃熟多紅璺，茶香有碧筋。", "高宗多不寐，終是夢中人。"]'),
('aebf17e6-ad83-4325-84a7-68e85ed85208','寄赤松舒道士二首 一','貫休','唐','唐诗','tang','','[]','不見高人久，空令鄙恡多。',48,'全唐诗/poet.tang.45000.json','["不見高人久，空令鄙恡多。", "遙思青嶂下，無那白雲何。", "子愛寒山子，歌惟樂道歌。", "會應陪太守，一日到煙蘿。"]'),
('def6beb6-726d-417c-a6d9-2ed535e096f4','寄赤松舒道士二首 二','貫休','唐','唐诗','tang','','[]','余亦如君也，詩魔不敢魔。',48,'全唐诗/poet.tang.45000.json','["余亦如君也，詩魔不敢魔。", "一餐兼午睡，萬事不如他。", "雨陣衝溪月，蛛絲罥砌莎。", "近知山果熟，還擬寄來麽。"]'),
('eb3c873c-6348-4d31-b01b-9595fd065cfd','鄂渚逢楊贊禹','貫休','唐','唐诗','tang','','[]','流浪兵荒苦，相思歲月闌。',48,'全唐诗/poet.tang.45000.json','["流浪兵荒苦，相思歲月闌。", "理惟通至道，人或謂無端。", "燒猛湖煙赤，窗空雪月寒。", "知音不可見，始爲一吟看。"]'),
('700ca29d-82f7-4c3a-8a66-0ff0c4a163a4','別性空禪師','貫休','唐','唐诗','tang','','[]','積翠迸一瀑，紅霞碧霧開。',48,'全唐诗/poet.tang.45000.json','["積翠迸一瀑，紅霞碧霧開。", "方尋此境去，莫問幾時迴。", "盪槳入檐石，思詩聞早雷。", "唯師心似我，欲近不然灰。"]'),
('c58e3397-685a-4acd-8409-1c7d675c6014','送胡處士','貫休','唐','唐诗','tang','','[]','不名兼不利，相遇海西濆。',48,'全唐诗/poet.tang.45000.json','["不名兼不利，相遇海西濆。", "白字未干髮，清時錯愛雲。", "頭巾多酒氣，竹杖有苔文。", "久積希顏意，林中又送君。"]'),
('64d9609b-53d8-4eef-986a-64c6f645b180','寄瀾公二首 一','貫休','唐','唐诗','tang','','[]','小一頭應白，孤高住歙城。',48,'全唐诗/poet.tang.45000.json','["小一頭應白，孤高住歙城。", "不知安樂否，何以近無生。", "燒逼鴻行側，風乾雪朕清。", "途中逢此信，珍重未精誠。"]'),
('3f60045a-4d04-430c-ae97-69454af2a690','寄瀾公二首 二','貫休','唐','唐诗','tang','','[]','荒亂拋深隱，飄零遠寓居。',48,'全唐诗/poet.tang.45000.json','["荒亂拋深隱，飄零遠寓居。", "片雲無定所，得力是逢渠。", "瀑灂羣公社，江崩古帝墟。", "終期再相見，招手復何如。"]'),
('0339c075-3dce-4d7d-8854-c9de165977ca','寄棲一上人','貫休','唐','唐诗','tang','','[]','花塹接滄洲，陰雲閑楚丘。',48,'全唐诗/poet.tang.45000.json','["花塹接滄洲，陰雲閑楚丘。", "雨聲雖到夜，吟味不如秋。", "古屋藏花鴿，荒園聚亂流。", "無機心便是，何用話歸休。"]'),
('89ada22b-c8fd-4f32-9766-b51d896d7de3','送僧之湖南','貫休','唐','唐诗','tang','','[]','湘水萬餘里，師遊芳草生。',36,'全唐诗/poet.tang.45000.json','["湘水萬餘里，師遊芳草生。", "登山乞食後，無伴入雲行。", "宿雨和花落，春牛擁霧耕。"]'),
('3dc3720c-f1fc-4a11-8cc6-097cfe626633','秋末寄張侍郎','貫休','唐','唐诗','tang','','[]','靜坐黔城北，離仁半歲彊。',48,'全唐诗/poet.tang.45000.json','["靜坐黔城北，離仁半歲彊。", "霧中紅黍熟，燒後白雲香。", "多病如何好，無心去始長。", "寂寥還得句，溪上寄三張。"]'),
('4f49601d-f757-4cd2-b8f0-4b8d6f05bb9d','古塞曲三首 一','貫休','唐','唐诗','tang','','[]','單于烽火動，都護去天涯。',48,'全唐诗/poet.tang.45000.json','["單于烽火動，都護去天涯。", "別賜黃金甲，親臨白玉除。", "塞垣須靜謐，師旅審安危。", "定遠條支寵，如今勝古時。"]'),
('516fbe77-eee2-4a8c-a982-6d0548f33e0f','古塞曲三首 二','貫休','唐','唐诗','tang','','[]','方見將軍貴，分明[對]冕旒。',50,'全唐诗/poet.tang.45000.json','["方見將軍貴，分明[對]冕旒。", "聖恩如遠被，狂虜不難收。", "臣節唯期死，功勳敢望侯。", "終辭脩里第，從此出皇州。"]'),
('d71efae1-1556-4efc-83e4-500de066aa44','古塞曲三首 三','貫休','唐','唐诗','tang','','[]','百萬精兵動，參差便渡遼。',48,'全唐诗/poet.tang.45000.json','["百萬精兵動，參差便渡遼。", "如何好白日，亦照此天驕。", "遠樹深疑賊，驚蓬迥似鵰。", "凱歌何日唱，磧路共天遙。"]'),
('7e385d41-7a71-4829-905d-bd7f1e806c99','古塞下曲七首 一','貫休','唐','唐诗','tang','','[]','下營依遁甲，分帥把河隍。',48,'全唐诗/poet.tang.45000.json','["下營依遁甲，分帥把河隍。", "地使人心惡，風吹旗燄荒。", "搜山得探卒，放火獵黃羊。", "唯有南飛雁，聲聲斷客腸。"]'),
('b12b7929-807e-4c85-bf63-961b810df9c3','古塞下曲七首 二','貫休','唐','唐诗','tang','','[]','歸去是何年，山連邏逤川。',48,'全唐诗/poet.tang.45000.json','["歸去是何年，山連邏逤川。", "蒼黃曾戰地，空闊養鵰天。", "旗插蒸沙堡，槍擔卓槊泉。", "蕭條寒日落，號令徹窮邊。"]'),
('6917c039-5787-4737-afbe-960f9d8123ce','古塞下曲七首 三','貫休','唐','唐诗','tang','','["\u9ec4\u6cb3"]','虜寇日相持，如龍馬不肥。',48,'全唐诗/poet.tang.45000.json','["虜寇日相持，如龍馬不肥。", "突圍金甲破，趂賊鐵槍飛。", "漢月堂堂上，胡雲慘慘微。", "黃河冰已合，猶未送征衣。"]'),
('4b785cad-7bd9-4a1e-86bd-5118ea86eeea','古塞下曲七首 四','貫休','唐','唐诗','tang','','[]','南北惟堪恨，東西實可嗟。',48,'全唐诗/poet.tang.45000.json','["南北惟堪恨，東西實可嗟。", "常飛侵夏雪，何處有人家？", "風刮陰山薄，河推大岸斜。", "祗應寒夜夢，時見故園花。"]'),
('f1ee72d0-3426-41ff-9681-25376a1dce20','古塞下曲七首 五','貫休','唐','唐诗','tang','','[]','不是將軍勇，胡兵豈易當。',48,'全唐诗/poet.tang.45000.json','["不是將軍勇，胡兵豈易當。", "雨曾淋火陣，箭又中金瘡。", "鐵嶺全無土，豺羣亦有狼。", "因思無戰日，天子是陶唐。"]'),
('c1bd78c1-45dd-4000-a6a0-f5fd0f95fffd','古塞下曲七首 六','貫休','唐','唐诗','tang','','[]','榆葉飄蕭盡，關防烽寨重。',48,'全唐诗/poet.tang.45000.json','["榆葉飄蕭盡，關防烽寨重。", "寒來知馬疾，戰後覺人兇。", "燒逐飛蓬死，沙生毒霧濃。", "誰能奏明主，功業已堪封。"]'),
('601d8e9a-142c-4dfa-a390-8f422ac68e79','古塞下曲七首 七','貫休','唐','唐诗','tang','','[]','萬戰千征地，蒼茫古塞門。',48,'全唐诗/poet.tang.45000.json','["萬戰千征地，蒼茫古塞門。", "陰兵爲客祟，惡酒發刀痕。", "風落崑崙石，河崩苜蓿根。", "將軍更移帳，日日近西蕃。"]'),
('db2e6b95-1383-4d00-8fa6-ff3ac7779bf7','古塞上曲七首 一','貫休','唐','唐诗','tang','','[]','幽幷兒百萬，百戰未曾輸。',48,'全唐诗/poet.tang.45000.json','["幽幷兒百萬，百戰未曾輸。", "蕃界已深入，將軍仍遠圖。", "月明風拔帳，磧暗鬼騎狐。", "但有東歸日，甘從筋力枯。"]'),
('e3d253d8-25c2-474e-b0c8-dc2bf199bef9','古塞上曲七首 二','貫休','唐','唐诗','tang','','[]','中軍殺白馬，白日祭蒼蒼。',48,'全唐诗/poet.tang.45000.json','["中軍殺白馬，白日祭蒼蒼。", "號變旗幡亂，鼙乾草木黃。", "朔雲含凍雨，枯骨放妖光。", "故國今何處，參差近鬼方。"]'),
('74e6902f-8152-4c25-84e3-b6dc1965eb78','古塞上曲七首 三','貫休','唐','唐诗','tang','','[]','白雁兼羌笛，幾年垂淚聽。',48,'全唐诗/poet.tang.45000.json','["白雁兼羌笛，幾年垂淚聽。", "陰風吹殺氣，永日在青冥。", "遠戍秋添將，邊烽夜雜星。", "嫖姚頭半白，猶自看兵經。"]'),
('81687455-4367-4bec-9567-2b973766009e','古塞上曲七首 四','貫休','唐','唐诗','tang','','[]','久雨始無塵，邊聲四散聞。',48,'全唐诗/poet.tang.45000.json','["久雨始無塵，邊聲四散聞。", "浸河荒寨柱，吹角白頭軍。", "戰馬齕𦎬草，烏鳶識陣雲。", "征人心力盡，枯骨更遭焚。"]'),
('061e8cbe-c05c-48b2-ab99-786946dc247d','古塞上曲七首 五','貫休','唐','唐诗','tang','','[]','帳幕侵奚界，憑陵未可涯。',48,'全唐诗/poet.tang.45000.json','["帳幕侵奚界，憑陵未可涯。", "擒生行別路，尋箭向平沙。", "赤落蒲桃葉，香微甘草花。", "不堪登隴望，白日又西斜。"]'),
('f42235ee-d4d1-4139-a8fc-599f139dd27d','古塞上曲七首 六','貫休','唐','唐诗','tang','','[]','地角天涯外，人號鬼哭邊。',48,'全唐诗/poet.tang.45000.json','["地角天涯外，人號鬼哭邊。", "大河流敗卒，寒日下蒼煙。", "殺氣諸蕃動，軍書一箭傳。", "將軍莫惆悵，高處是燕然。"]'),
('a412022b-2965-4ddb-bb76-ea59af9e74db','古塞上曲七首 七','貫休','唐','唐诗','tang','','[]','山接胡奴水，河連勃勃城。',48,'全唐诗/poet.tang.45000.json','["山接胡奴水，河連勃勃城。", "數州今已伏，此命豈堪輕。", "磧吼旄頭落，風乾刁斗清。", "因嗟李陵苦，祗得沒蕃名。"]'),
('53b39de2-aa4e-420a-b55d-d4b3c6a423e7','古出塞曲三首 一','貫休','唐','唐诗','tang','','[]','掃盡狂胡迹，迴頭望故關。',48,'全唐诗/poet.tang.45000.json','["掃盡狂胡迹，迴頭望故關。", "相逢惟死鬬，豈易得生還。", "縱宴參胡樂，收兵過雪山。", "不封十萬戶，此事亦應閑。"]'),
('d7614674-e17b-427d-a0c5-9e26147f16d2','古出塞曲三首 二','貫休','唐','唐诗','tang','','[]','玉帳將軍意，殷勤把酒論。',48,'全唐诗/poet.tang.45000.json','["玉帳將軍意，殷勤把酒論。", "功高寧在我，陣沒與招魂。", "塞色干戈束，軍容喜氣屯。", "男兒今始是，譀出玉關門。"]'),
('866e6de8-31cf-4772-8078-50e5c00f708a','古出塞曲三首 三','貫休','唐','唐诗','tang','','[]','回首隴山頭，連天草木秋。',48,'全唐诗/poet.tang.45000.json','["回首隴山頭，連天草木秋。", "聖君應入夢，半路遣封侯。", "水不擔陰雪，柴令倒戍樓。", "歸來麟閣上，春色滿皇州。"]'),
('df764d09-6970-4b94-ab8d-1bf5cc159c79','聞赤松舒道士下世','貫休','唐','唐诗','tang','','[]','地變賢人喪，瘡痍不可觀。',240,'全唐诗/poet.tang.45000.json','["地變賢人喪，瘡痍不可觀。", "一聞消息苦，千種破除難。", "陰騭那虛擲，深山近始安。", "玄關評兔角，玉器琢雞冠。", "傲野高難狎，融怡美不殫。", "冀迎新渥澤，遽逐逝波瀾。", "蛻殼埋金隧，飛精駕錦鸞。", "傾摧千仞壁，枯歇一株蘭。", "仙廟詩雖繼，苔牆篆必鞔。", "煙霞成片黯，松桂著行乾。", "影拄溪流咽，堂扃隟月寒。", "寂寥遺藥犬，縹緲想瓊竿。", "伊昔相尋遠，留連幾盡歡。", "論詩花作席，炙菌葉爲盤。", "彭伉心相似，承禎趣一般。", "琴彈溪月側，棊次砌雲殘。", "儵忽成千古，飄零見百端。", "荆囊春浩浩，吳越浪漫漫。", "已矣紅霞子，空留白石壇。", "無弦亦須絕，回首一長歎。"]'),
('2cd6df86-e9e8-4c18-8117-3b7ea20163d2','贈抱麻劉舍人','貫休','唐','唐诗','tang','','[]','郡政今良吏，門風古縉紳。',216,'全唐诗/poet.tang.45000.json','["郡政今良吏，門風古縉紳。", "萬年唐社稷，一箇哭麻人。", "憤烈身先死，敷敭氣益貞。", "天乎資大寶，泰矣見忠臣。", "得罪鍾多故，投荒豈是迍。", "玉寒方重澀，松古更青皴。", "鵬𪄚寧唯白，龍多豈止荀。", "道孤梳有雪，恩重淚盈巾。", "喻蜀須憑草，成周必仗仁。", "三峰宵旰切，萬里渥恩新。", "賦鵩言無累，依劉德有鄰。", "風期仁祖帽，鼠訝史雲塵。", "禪叟知何幸，玄談有宿因。", "雙溪逢陸海，荆渚遇平津。", "落日愁聞笛，何人爲吐茵。", "生徒希匠化，寰海仰經綸。", "疾愈蟬聲老，年豐雨滴頻。", "劉虬師弟子，時喜一相親。"]'),
('3f3d56f2-c049-40d4-8349-c4c108be013f','夜寒寄盧給事二首 一','貫休','唐','唐诗','tang','','[]','刻羽流商否，霜風動地吹。',48,'全唐诗/poet.tang.45000.json','["刻羽流商否，霜風動地吹。", "邇來唯自惜，知合是誰知。", "塹雪消難盡，鄰僧睡太奇。", "知音不可得，始爲一吟之。"]'),
('8b1bd2ac-136b-4a81-bef8-b8b6e7c3029e','夜寒寄盧給事二首 二','貫休','唐','唐诗','tang','','[]','心苦味不苦，世衰吾道微。',48,'全唐诗/poet.tang.45000.json','["心苦味不苦，世衰吾道微。", "清如吞雪雹，誰把比珠璣。", "作者相收拾，常人任是非。", "舊居滄海上，歸去即應歸。"]'),
('3ad3a5bb-70bb-4bc2-8911-b2a6992baa33','送葉蒙赴舉','貫休','唐','唐诗','tang','','[]','年年屈復屈，惆悵曲江湄。',48,'全唐诗/poet.tang.45000.json','["年年屈復屈，惆悵曲江湄。", "自古身榮者，多非年少時。", "空囊投刺遠，大雪入關遲。", "來歲還公道，平人不用疑。"]'),
('f0416605-ce3a-4e92-80db-2bd29c632882','聞王慥常侍卒三首 一','貫休','唐','唐诗','tang','','[]','世亂君巡狩，清賢又告亡。',48,'全唐诗/poet.tang.45000.json','["世亂君巡狩，清賢又告亡。", "星辰皆有角，日月略無光。", "金柱連天折，瑤階被賊荒。", "令人轉惆悵，無路問蒼蒼。"]'),
('5fbe45d0-4760-4422-87b2-96df7becce86','聞王慥常侍卒三首 二','貫休','唐','唐诗','tang','','[]','宗社運微衰，山摧甘井枯。',48,'全唐诗/poet.tang.45000.json','["宗社運微衰，山摧甘井枯。", "不知千載後，更有此人無。", "政入龔黃甲，詩輕沈宋徒。", "受恩酬未得，不覺祗長吁。"]'),
('ab574363-6946-4118-af09-3671cf4fca1f','聞王慥常侍卒三首 三','貫休','唐','唐诗','tang','','[]','儻在扶天步，重興古國風。',48,'全唐诗/poet.tang.45000.json','["儻在扶天步，重興古國風。", "還如齊晏子，再見狄梁公。", "棠樹梅溪北，佳城舜廟東。", "誰修循吏傳，對此莫悤悤。"]'),
('61e320ab-c0d5-41a3-a836-ead8b94564f3','秋晚野步','貫休','唐','唐诗','tang','','[]','藤屨兼閩竹，吟行一水傍。',48,'全唐诗/poet.tang.45000.json','["藤屨兼閩竹，吟行一水傍。", "樹涼蟬不少，溪斷路多荒。", "燒岳陰風起，田家濁酒香。", "登高吟更苦，微月出蒼茫。"]'),
('f25f808d-b3dc-46a3-94f1-27d63e18543a','聞大願和尚順世三首 一','貫休','唐','唐诗','tang','','[]','王室今如燬，仍聞喪我師。',48,'全唐诗/poet.tang.45000.json','["王室今如燬，仍聞喪我師。", "古容圖得否，內院去無疑。", "岳鬼月中哭，松龕雪次隳。", "直須文五色，始可立高碑。"]'),
('b672cb2d-0d41-4ee4-8a20-f78d899df704','聞大願和尚順世三首 二','貫休','唐','唐诗','tang','','[]','鄴衛松杉外，芝蘭季孟間。',48,'全唐诗/poet.tang.45000.json','["鄴衛松杉外，芝蘭季孟間。", "盡希重詔出，祗待六龍還。", "不疾成千古，令焚動四山。", "感恩終有淚，遙寄水潺潺。"]'),
('2e07d818-f8e9-4ecd-ad9a-9e96b6ff1301','聞大願和尚順世三首 三','貫休','唐','唐诗','tang','','[]','師稟盡名卿，孤峰老稱情。',48,'全唐诗/poet.tang.45000.json','["師稟盡名卿，孤峰老稱情。", "若遊三點外，爭把七賢平。", "苦霧埋空室，啼猨有咽聲。", "今朝益惆悵，曾沐下牀迎。"]'),
('a5400d94-a37f-4b08-9198-37ba84d6bb2c','聞葉蒙及第','貫休','唐','唐诗','tang','','[]','憶昨送君詩，平人不用疑。',48,'全唐诗/poet.tang.45000.json','["憶昨送君詩，平人不用疑。", "吾徒若不得，天道即應私。", "塵土茫茫曉，麟龍草草騎。", "相思不可見，又是落花時。"]'),
('3f6aaf57-b3d9-4c03-a172-c1b300641f67','送僧之靈夏','貫休','唐','唐诗','tang','','[]','舊識爲邊帥，師遊勝事兼。',51,'全唐诗/poet.tang.45000.json','["舊識爲邊帥，師遊勝事兼。", "連天唯白草，野餅有紅鹽。", "蕃近風多{孛支}，河渾磧半淹。", "因知心似月，處處有人瞻。"]'),
('3ab6673b-d3b3-498d-be60-a1adfd4858f4','書無相道人菴','貫休','唐','唐诗','tang','','[]','造化太茫茫，端居紫石房。',48,'全唐诗/poet.tang.45000.json','["造化太茫茫，端居紫石房。", "心遺無句句，頂處有霜霜。", "白鹿眠枯葉，清泉灑毳囊。", "寄言疑未決，須道雪溪旁。"]'),
('8d511214-d634-4647-a5f8-822a6080a045','明進士北齋避暑','貫休','唐','唐诗','tang','','[]','相訪多衝雨，由來德有鄰。',48,'全唐诗/poet.tang.45000.json','["相訪多衝雨，由來德有鄰。", "卷簾繁暑退，濕樹一蟬新。", "道在誰爲主，吾衰自有因。", "祗應江海上，還作狎鷗人。"]'),
('7ba3d33d-418b-40da-87ff-6836c230ac78','晚春寄吳融于競二侍郎','貫休','唐','唐诗','tang','','[]','白頭爲遠客，常憶白雲間。',48,'全唐诗/poet.tang.45000.json','["白頭爲遠客，常憶白雲間。", "祗覺老轉老，不知閑是閑。", "花含宜細雨，室冷是深山。", "唯有霜臺客，依依是往還。"]'),
('e15231ea-e011-4af2-a471-d93536cf93ce','喜不思上人來','貫休','唐','唐诗','tang','','[]','沃州那不住，一別許多時。',48,'全唐诗/poet.tang.45000.json','["沃州那不住，一別許多時。", "幾度懷君夜，相逢出夢遲。", "瓶擔千丈瀑，偈是七言詩。", "若向羅浮去，伊余亦願隨。"]'),
('2e4e8c4e-9f12-407c-8ad7-055d61527087','秋懷赤松道士','貫休','唐','唐诗','tang','','[]','仙觀在雲端，相思星斗寒。',48,'全唐诗/poet.tang.45000.json','["仙觀在雲端，相思星斗寒。", "常憐呼鶴易，却恨見君難。", "石罅青虵濕，風榸白菌乾。", "終期花月下，壇上聽君彈。"]'),
('316bb760-a73a-4ae5-a498-a604d2526270','送劉逖赴閩辟','貫休','唐','唐诗','tang','','[]','離亂生涯盡，依劉是見機。',48,'全唐诗/poet.tang.45000.json','["離亂生涯盡，依劉是見機。", "從來吟太苦，不得力還稀。", "路入閩山熟，江浮瘴雨肥。", "何須折楊柳，相送已依依。"]'),
('16e05dff-217a-4b95-b122-042cc9fd1250','苦雨中作','貫休','唐','唐诗','tang','','[]','通宵復連夕，其狀祗如傾。',48,'全唐诗/poet.tang.45000.json','["通宵復連夕，其狀祗如傾。", "却遣思山者，忽然嫌水聲。", "好花飄草盡，古壁欲雲生。", "不奈天難問，迢迢遠客情。"]'),
('409fb19a-ee56-4158-88a1-d52bd7f9710f','送僧歸日本','貫休','唐','唐诗','tang','','["\u9ec4\u5c71"]','焚香祝海靈，開眼夢中行。',48,'全唐诗/poet.tang.45000.json','["焚香祝海靈，開眼夢中行。", "得達即便是，無生可作輕。", "流黃山火著，碇石索雷鳴。", "想到夷王禮，還爲上寺迎。"]'),
('d6d4be1a-303f-426e-918a-c1208bb1066b','贈信安鄭道人','貫休','唐','唐诗','tang','','[]','貌古似蒼鶴，心清如鼎湖。',48,'全唐诗/poet.tang.45000.json','["貌古似蒼鶴，心清如鼎湖。", "仍聞得新義，便欲註陰符。", "點化金常有，閑行影漸無。", "杳兮中便是，應不食菖蒲。"]'),
('292b47cc-a1bc-4c6a-aab1-bf808b3b459d','送吏部劉相公除東川','貫休','唐','唐诗','tang','','[]','帝念梓州民，年年戰仗頻。',144,'全唐诗/poet.tang.45000.json','["帝念梓州民，年年戰仗頻。", "山川無草木，烽火沒煙塵。", "政亂皆因亂，安人必藉仁。", "皇天開白日，殷鼎輟誠臣。", "一日離君側，千官送渭濱。", "酒傾紅琥珀，馬控白騏驎。", "渥澤番番降，壺漿處處陳。", "旌幢山色濕，邛僰鳥啼新。", "帟幕還名儉，良醫始姓秦。", "軍雄城似岳，地變物含春。", "白必侵雙鬢，清應誡四鄰。", "吾皇重命相，更合是何人。"]'),
('9db4b8ed-970a-46c8-8236-aa920d6c5cc4','送智光禪伯','貫休','唐','唐诗','tang','','[]','萬事歸一衲，曹溪初去尋。',48,'全唐诗/poet.tang.45000.json','["萬事歸一衲，曹溪初去尋。", "從來相狎輩，盡不是知音。", "乞食林花落，穿雲翠巘深。", "終希重一見，示我祖師心。"]'),
('7c4f55cf-9f7a-4779-9d4d-04909ce6bd0b','夜對雪寄杜使君','貫休','唐','唐诗','tang','','[]','片片含天意，紛紛勢莫拘。',96,'全唐诗/poet.tang.45000.json','["片片含天意，紛紛勢莫拘。", "灑於諸瑞後，憂恐一冬無。", "鶴凚聲偏密，風焦片益粗。", "冷牽人夢轉，清逼瘴根徂。", "掃徑僧傾笠，爲詩士棄爐。", "橋高銀螮蝀，峰峻玉浮圖。", "盈尺何須問，豐年已可□。", "遙思郢中曲，句句出冰壺。"]'),
('39815561-8fff-46bd-8a48-adaa57c7e7ef','送王轂及第後歸江西','貫休','唐','唐诗','tang','','[]','太宗羅俊彥，桂玉比光輝。',48,'全唐诗/poet.tang.45000.json','["太宗羅俊彥，桂玉比光輝。", "難得終須得，言歸始是歸。", "風帆天際吼，金鶚月中飛。", "五府如交辟，魚書莫便稀。"]'),
('2cb6681d-abba-4cbd-9e5d-cd9307c60621','送盧瞻罷廬陵幕歸閿鄉','貫休','唐','唐诗','tang','','[]','文行成身事，從知貴得仁。',48,'全唐诗/poet.tang.45000.json','["文行成身事，從知貴得仁。", "歸來還寂寞，何以慰交親。", "芳草色似動，胡桃花又新。", "昌朝有知己，好作諫垣臣。"]'),
('89dbb1ab-0373-435a-862c-366a73b016f4','避寇白沙驛作','貫休','唐','唐诗','tang','','[]','避亂無深淺，蒼黃古驛東。',48,'全唐诗/poet.tang.45000.json','["避亂無深淺，蒼黃古驛東。", "草枯牛尚齕，霞濕燒微紅。", "□□時時□，人愁處處同。", "猶逢好時否，孤坐雪濛濛。"]'),
('20ddb6ca-d910-4a35-8f78-f7206e28b12d','聞李頻員外卒','貫休','唐','唐诗','tang','','[]','蒼蒼難可問，問荅亦難聞。',48,'全唐诗/poet.tang.45000.json','["蒼蒼難可問，問荅亦難聞。", "落葉平津岸，愁人李使君。", "文章應力竭，茅土始天分。", "又逐東風去，迢迢隔嶺雲。"]'),
('3de94bff-c805-4a0b-8756-c7aa6ac9e8df','江陵寄翰林韓偓學士','貫休','唐','唐诗','tang','','[]','久住荆溪北，禪關挂綠蘿。',48,'全唐诗/poet.tang.45000.json','["久住荆溪北，禪關挂綠蘿。", "風清閑客去，睡美落花多。", "萬事皆妨道，孤峰謾憶他。", "新詩舊知己，始爲味如何。"]'),
('8bbc7fb7-5814-4ba0-932a-b9f8b7a50d7c','閑居作','貫休','唐','唐诗','tang','','[]','閑門微雪下，慵惰計全成。',48,'全唐诗/poet.tang.45000.json','["閑門微雪下，慵惰計全成。", "默作便終日，孤峰祗此清。", "身心閑少夢，杉竹冷多聲。", "唯有西峰叟，相逢眼最明。"]'),
('82d82ab1-d18d-496b-b0f7-7931ce75bf6f','和韋相公見示閑臥','貫休','唐','唐诗','tang','','[]','刻形求得相，事事未嘗眠。',240,'全唐诗/poet.tang.45000.json','["刻形求得相，事事未嘗眠。", "霖雨方爲雨，非煙豈是煙。", "童收庭樹果，風曳案頭牋。", "仲虺專爲誥，何充雅愛禪。", "靜嫌山色遠，病是酒杯偏。", "蜩響初穿壁，蘭芽半出甎。", "堂懸金粟像，門枕御溝泉。", "旦沐雖頻握，融帷孰敢褰。", "德高羣彥表，善植幾生前。", "脩補烏皮几，深藏子敬氈。", "扶持千載聖，瀟灑一聲蟬。", "棊陣連殘月，僧交似大顛。", "常知生似幻，維重直如弦。", "餅憶蓴羹美，茶思岳瀑煎。", "祗聞溫樹譽，堪鄙竹林賢。", "脫穎三千士，馨香四十年。", "寬平開義路，淡泞潤清田。", "哲后知如子，空王夙有緣。", "對歸香滿袖，吟次月當川。", "休說慙如揵，堯天即梵天。"]'),
('01b15546-2895-456b-81eb-459360c705f8','寄山中伉禪師','貫休','唐','唐诗','tang','','[]','舉世遭心使，吾師獨使心。',48,'全唐诗/poet.tang.45000.json','["舉世遭心使，吾師獨使心。", "萬緣冥目盡，一句不言深。", "野火燒禪石，殘霞照栗林。", "秋風溪上路，終願一相尋。"]'),
('55b70b6e-b2ee-4df6-b76c-dc99a5043c06','秋寄栖一','貫休','唐','唐诗','tang','','[]','一別一公後，相思時一吁。',48,'全唐诗/poet.tang.45000.json','["一別一公後，相思時一吁。", "眼中瘡校未，般若偈持無。", "卷句冰團大，爐煙櫪橛粗。", "勸君君記取，不用更他圖。"]'),
('b350d17b-8e23-4042-bf63-9f5900f59be1','懷匡山山長二首 一','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','白石峰之半，先生好在麽。',48,'全唐诗/poet.tang.45000.json','["白石峰之半，先生好在麽。", "捲簾當大瀑，常恨不如他。", "杉罅龍涎溢，潭㘭石髮多。", "吾皇搜草澤，爭奈謝安何。"]'),
('baae70d6-9e7c-4062-aec3-1f8731f72c6d','懷匡山山長二首 二','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','見說面前峰，尋常醉亦登。',48,'全唐诗/poet.tang.45000.json','["見說面前峰，尋常醉亦登。", "雨餘多菌出，燒甚古崖崩。", "覓句曾衝虎，耕田半爲僧。", "聞名多歲也，常恨不飛騰。"]'),
('519ac77d-8fe5-4c79-ac5c-091cf9b44d65','懷高真動二首 一','貫休','唐','唐诗','tang','','[]','知爾今何處，孤高獨不羣。',48,'全唐诗/poet.tang.45000.json','["知爾今何處，孤高獨不羣。", "論詩唯許我，窮易到無文。", "貰酒兒穿雪，尋僧月照雲。", "何時再相見，兵寇尚紛紛。"]'),
('7aaa3ebd-bc84-4314-93b4-58bbe8e1d6c8','懷高真動二首 二','貫休','唐','唐诗','tang','','[]','久別無消息，今秋忽得書。',48,'全唐诗/poet.tang.45000.json','["久別無消息，今秋忽得書。", "諸孤婚嫁苦，求己世情疎。", "亂甚無喬木，溪多不釣魚。", "祗應金岳色，如爾復如余。"]'),
('98010ad5-bc2c-472a-851b-98f809fc9fcc','秋末入匡山船行八首 一','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','楚國茱萸月，吳吟梨栗船。',48,'全唐诗/poet.tang.45000.json','["楚國茱萸月，吳吟梨栗船。", "遠遊無定所，高臥是何年。", "浪卷紛紛葉，檣衝澹澹煙。", "去心還自喜，廬岳倚青天。"]'),
('23391358-ea11-49ab-abf8-a0a209374a39','秋末入匡山船行八首 二','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','蘆葦深花裏，漁歌一曲長。',48,'全唐诗/poet.tang.45000.json','["蘆葦深花裏，漁歌一曲長。", "人心雖憶越，帆態似浮湘。", "石獺銜魚白，汀茅浸浪黃。", "等閑千萬里，道在亦無妨。"]'),
('d9806351-cd2a-48e7-a159-16e7b7913be8','秋末入匡山船行八首 三','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','島上離家化，茅茨竹戶開。',48,'全唐诗/poet.tang.45000.json','["島上離家化，茅茨竹戶開。", "黃桑雙鵲喜，白日有誰來。", "擔浪澆秋芋，緣灘取淨苔。", "回頭深自媿，舊業本蒿萊。"]'),
('3552e2ed-e071-4302-b7e7-8386a6b19ef5','秋末入匡山船行八首 四','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','匡阜層層翠，修江疊疊波。',48,'全唐诗/poet.tang.45000.json','["匡阜層層翠，修江疊疊波。", "從來未曾到，此去復如何。", "水廟寒鴉集，沙村夕照多。", "誰如垂釣者，孤作鬢皤皤。"]'),
('ac838a0f-0402-4cb5-ba7a-d6b0fd752771','秋末入匡山船行八首 五','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','晚泊蒼茫浦，風微浪亦粗。',48,'全唐诗/poet.tang.45000.json','["晚泊蒼茫浦，風微浪亦粗。", "估喧如亥合，檣密似林枯。", "地峻湖無□，潮寒蚌有珠。", "東西無定所，何用問前途。"]'),
('db49702e-d89b-414b-b414-f354afee3fc2','秋末入匡山船行八首 六','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','島香思賈島，江碧憶清江。',48,'全唐诗/poet.tang.45000.json','["島香思賈島，江碧憶清江。", "囊橐誰相似，饞慵世少雙。", "鼉驚入窟月，燒到繫船樁。", "謾有歸鄉夢，前頭是楚邦。"]'),
('f7bce7a2-640c-4e38-b17c-45b4319ff6e3','秋末入匡山船行八首 七','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','南北雖無適，東西亦似萍。',48,'全唐诗/poet.tang.45000.json','["南北雖無適，東西亦似萍。", "霞根生石片，象跡壞沙汀。", "莽莽蒹葭赤，微微蜃蛤腥。", "因思范蠡輩，未免亦飄零。"]'),
('c8a79701-1203-4814-8657-c7aa5a0c55b6','秋末入匡山船行八首 八','貫休','唐','唐诗','tang','','["\u5e90\u5c71", "\u957f\u6c5f"]','曉色千檣去，長江八月時。',48,'全唐诗/poet.tang.45000.json','["曉色千檣去，長江八月時。", "雨淙山骨出，橰擉岸形卑。", "野水畬田黑，荒汀獨鳥癡。", "如今是清世，誰道出山遲。"]'),
('ed50c044-aa14-4cee-a88e-de5772498fd1','送僧歸華山','貫休','唐','唐诗','tang','','[]','心枯衲亦枯，歸岳揭空盂。',48,'全唐诗/poet.tang.45000.json','["心枯衲亦枯，歸岳揭空盂。", "七貴留不住，孤雲出更孤。", "燒灰猶湯足，雪片似黏鬚。", "他日如相覓，還應道到吳。"]'),
('0f0b0e46-8b1f-4557-b7bd-1ce97285f332','送友人之嶺外','貫休','唐','唐诗','tang','','[]','五嶺難爲客，君遊早晚回。',48,'全唐诗/poet.tang.45000.json','["五嶺難爲客，君遊早晚回。", "一囊秋課苦，萬里瘴雲開。", "金柱根應動，風雷舶欲來。", "明時好□進，莫滯長卿才。"]'),
('a39823b3-e3f9-4bde-8e3b-ff85d3203d98','送盧舍人朝覲','貫休','唐','唐诗','tang','','[]','羶行無爲日，垂衣帝道亨。',144,'全唐诗/poet.tang.45000.json','["羶行無爲日，垂衣帝道亨。", "聖真千載聖，明必萬年明。", "重德須朝覲，流年不可輕。", "洪才傳出世，清甲得高名。", "罕玉藏無映，嵇松畫不成。", "起銜軒后勅，醉別亞夫營。", "燒闊荆州熟，霞新峴首晴。", "重重堯雨露，去去漢公卿。", "白髮應從白，清貧但更清。", "夢緣丹陛險，春傍綵衣生。", "既握鍾繇筆，須調傅說羹。", "倘因星使出，一望問支鏗。"]'),
('bc61a33f-cf3a-4ad6-9d4f-8f5bb083cf6d','上馮使君山水障子','貫休','唐','唐诗','tang','','[]','憶山歸未得，畫出亦堪憐。',144,'全唐诗/poet.tang.45000.json','["憶山歸未得，畫出亦堪憐。", "崩岸全隳路，荒村半有煙。", "筆句岡勢轉，墨搶燒痕顛。", "遠浦深通海，孤峰冷倚天。", "柴棚坐逸士，露茗煮紅泉。", "繡與蓮峰競，威如劒閣牽。", "石門關麈鹿，氣候有神仙。", "茅屋書窗小，苔堦滴瀑圓。", "松根擊石朽，桂葉蝕霜鮮。", "畫出欺王墨，擎將獻惠連。", "新詩寧妄說，舊隱實如然。", "願似窗中列，時聞大雅篇。"]'),
('d6a74210-3717-4c21-9671-5e2184e494c6','送令狐煥赴闕','貫休','唐','唐诗','tang','','[]','渚宮遙落日，相送碧江湄。',48,'全唐诗/poet.tang.45000.json','["渚宮遙落日，相送碧江湄。", "陟也須爲相，天乎更贊誰。", "風高檣力出，霞熱鳥行遲。", "此去多來客，無忘慰所思。"]'),
('5a637488-2e87-493c-a1e4-ddd736108bd1','送吳融員外赴闕','貫休','唐','唐诗','tang','','[]','漢文思賈傅，賈傅遂生還。',48,'全唐诗/poet.tang.45000.json','["漢文思賈傅，賈傅遂生還。", "今日又如此，送君非等閑。", "雲寒猶惜雪，燒猛似烹山。", "應笑無機者，騰騰天地間。"]'),
('e76674fe-695e-4691-8155-2c5712e5405b','送姚洎拾遺自江陵幕赴京','貫休','唐','唐诗','tang','','[]','捧詔動征輪，分飛楚水濱。',120,'全唐诗/poet.tang.45000.json','["捧詔動征輪，分飛楚水濱。", "由來真廟器，多作伏蒲人。", "捨魯知非願，朝天不話貧。", "沙頭千騎送，島上一蟬新。", "莫使身侵貴，無矜貴逼身。", "玉階凝正色，蘭苑漲芳塵。", "鑾輅方離華，車書漸似秦。", "流年飄儵忽，書札莫因循。", "涼雨鳴紅葉，非煙閉紫宸。", "憑將西社意，一說向荀陳。"]'),
('19061181-fe35-49d8-b79b-c76b545d4936','送僧人入石霜','貫休','唐','唐诗','tang','','[]','舉世祗堪吁，空知與道俱。',215,'全唐诗/poet.tang.45000.json','["舉世祗堪吁，空知與道俱。", "論心齊至聖，對鏡破凡夫。", "業王如雲合，頭低似箭驅。", "三清徒妄想，千載亦須臾。", "唯我流陽叟，深雲領毳徒。", "盡騎香白象，皆握月明珠。", "寂寞排松榻，斕斑半雪鬚。", "苔侵長者論，嵐蝕祖師圖。", "翠巘金鐘曉，香林寶月孤。", "兟兟齊白趾，赫赫共洪爐。", "山色鋤難盡，松根踏欲無。", "難評傳的的，須到不區區。", "撩舍新羅瘦，爐煙榾柮粗。", "燒畬平虎窟，分瀑入香廚。", "師去情何切，人間事莫拘。", "穿林宿古冢，踏葉揭空盂。", "無事終無事，令枯便合枯他年相覓在，亦不是生蘇。"]'),
('52cc3857-5a5a-48f6-ae74-643bcdf26fe1','送僧歸南康','貫休','唐','唐诗','tang','','[]','殼殼學得律，還鄉見苦情。',48,'全唐诗/poet.tang.45000.json','["殼殼學得律，還鄉見苦情。", "遠思芳草盛，不入楚山行。", "帆入汀煙健，經吟戍月清。", "到鄉同學輩，應到贛江迎。"]'),
('549bc28c-406c-4398-a205-e2b12036405b','送陳秀才赴舉兼寄韓舍人','貫休','唐','唐诗','tang','','[]','主聖臣賢日，求名莫等閑。',48,'全唐诗/poet.tang.45000.json','["主聖臣賢日，求名莫等閑。", "直須詩似玉，不用力如山。", "草白兵初息，年豐駕已還。", "憑將安養意，一說向曾顏。"]'),
('6472c949-4888-4320-9fb5-958fc3d5d01b','送友人及第後歸台州','貫休','唐','唐诗','tang','','[]','得桂爲邊辟，翩翩頗合宜。',48,'全唐诗/poet.tang.45000.json','["得桂爲邊辟，翩翩頗合宜。", "嫖姚留不住，晝錦已歸遲。", "島側花藏虎，湖心浪撼棊。", "終期華頂下，共禮淥身師。"]'),
('014cd916-3921-4e8c-b8dc-2f4e6cb6079c','晚春寄張侍郎','貫休','唐','唐诗','tang','','[]','遐想涪陵岸，山花半已殘。',48,'全唐诗/poet.tang.45000.json','["遐想涪陵岸，山花半已殘。", "人心何以遣，天步正艱難。", "鳥聽黃袍小，城臨白帝寒。", "應知窗下夢，日日到江干。"]'),
('2b2fe4c1-3983-49b0-845f-55daed7373e1','寄景判官兼思州葉使君','貫休','唐','唐诗','tang','','[]','獨住西峰半，尋常欲下難。',48,'全唐诗/poet.tang.45000.json','["獨住西峰半，尋常欲下難。", "石多桐屐齾，香甚藥花乾。", "荏苒新鶯老，窮通亦自寬。", "髯參與短簿，始爲一吟看。"]'),
('c2101a4d-5354-48a5-8ac8-9af19521caff','送盧秀才應舉','貫休','唐','唐诗','tang','','[]','幾載阻兵荒，一名終不忘。',48,'全唐诗/poet.tang.45000.json','["幾載阻兵荒，一名終不忘。", "還衝猛風雪，如畫冷朝陽。", "句好慵將出，囊空却不忙。", "明年公道日，去去必穿楊。"]'),
('ebe9157b-aa85-4210-b319-51c686e3c00f','聞新蟬寄桂雍','貫休','唐','唐诗','tang','','[]','新蟬終夜呌，嘒嘒隔溪濆。',48,'全唐诗/poet.tang.45000.json','["新蟬終夜呌，嘒嘒隔溪濆。", "杜宇仍相雜，故人聞不聞。", "捲簾花動月，冥目砌生雲。", "終共謝時去，西山鸞鶴羣。"]'),
('fb9130e8-b244-43a3-9033-39b7a9b55ad6','寄懷楚和尚二首 一','貫休','唐','唐诗','tang','','[]','吾師師子兒，而復貌瓌奇。',48,'全唐诗/poet.tang.45000.json','["吾師師子兒，而復貌瓌奇。", "何得文明代，不爲王者師。", "鐵盂湯雪早，石炭煮茶遲。", "謾有參尋意，因循到亂時。"]'),
('1d0c9d29-c64d-4afe-938d-3f0140e7c606','寄懷楚和尚二首 二','貫休','唐','唐诗','tang','','[]','跳躑諸峰險，回翔萬里空。',48,'全唐诗/poet.tang.45000.json','["跳躑諸峰險，回翔萬里空。", "爭將金鎖鎖，那把玉籠籠。", "印缺香崩火，窗疎蝎喫風。", "永懷今已矣，吟坐雪濛濛。"]'),
('42388f80-e8cb-49c8-a042-7e60afbf8fe3','和韋相公話婺州陳事','貫休','唐','唐诗','tang','','[]','昔事堪惆悵，談玄愛白牛。',48,'全唐诗/poet.tang.45000.json','["昔事堪惆悵，談玄愛白牛。", "千場花下醉，一片夢中遊。", "耕避初平石，燒殘沈約樓。", "無因更重到，且副濟川舟。"]'),
('f2a56c12-67ee-469c-89bb-1dfdbddaec70','遇五天僧入五臺五首 一','貫休','唐','唐诗','tang','','[]','十萬里到此，辛勤詎可論。',48,'全唐诗/poet.tang.45000.json','["十萬里到此，辛勤詎可論。", "唯云吾上祖，見買給孤園。", "一月行沙磧，三更到鐵門。", "白頭鄉思在，迴首一銷魂。"]'),
('07f008b2-1cd4-464b-ae9a-9e2ea4c67c32','遇五天僧入五臺五首 二','貫休','唐','唐诗','tang','','[]','雪嶺頂危坐，乾坤四顧低。',48,'全唐诗/poet.tang.45000.json','["雪嶺頂危坐，乾坤四顧低。", "河橫于闐北，日落月支西。", "水石香多白，猨猱老不啼。", "空餘忍辱草，相對色萋萋。"]'),
('f9105eaa-3461-4932-9137-c3f66fdd5d54','遇五天僧入五臺五首 三','貫休','唐','唐诗','tang','','[]','遠禮清涼寺，尋真似善才。',48,'全唐诗/poet.tang.45000.json','["遠禮清涼寺，尋真似善才。", "身心無所得，日月不將來。", "白疊還圖象，滄溟亦汎杯。", "唐人亦何幸，處處覺花開。"]'),
('0808fe0f-f916-434e-9374-12d7e32e73ac','遇五天僧入五臺五首 四','貫休','唐','唐诗','tang','','[]','塗足油應盡，乾陀帔半隳。',48,'全唐诗/poet.tang.45000.json','["塗足油應盡，乾陀帔半隳。", "辟支迦狀貌，剎利帝家兒。", "結印魔應哭，遊心聖不知。", "深嗟頭已白，不得遠相隨。"]'),
('c989e9a7-0805-417c-96af-c548044a37fe','遇五天僧入五臺五首 五','貫休','唐','唐诗','tang','','[]','送迎經幾國，多化帝王心。',48,'全唐诗/poet.tang.45000.json','["送迎經幾國，多化帝王心。", "電激青蓮目，環垂紫磨金。", "眉根霜入細，梵夾蠹難侵。", "必似陀波利，他年不可尋。"]'),
('90b68d61-57ca-4beb-894d-f66a8c00e276','經普化禪師影院','貫休','唐','唐诗','tang','','[]','大一今何處，登堂似昔時。',48,'全唐诗/poet.tang.45000.json','["大一今何處，登堂似昔時。", "曾蒙金印印，得異野干兒。", "影束龍神在，門荒桐竹衰。", "誰云續僧史，別位著吾師。"]'),
('33b52e4a-b40b-46db-914f-75d6d757ceb5','秋寄李頻使君二首 一','貫休','唐','唐诗','tang','','[]','爲郎須塞詔，當路亦驅驅。',48,'全唐诗/poet.tang.45000.json','["爲郎須塞詔，當路亦驅驅。", "貴不因人得，清還似句無。", "燒煙連野白，山藥拶階枯。", "想得徵黃詔，如今已在途。"]'),
('385e6970-ac1e-4aac-89a9-3d31c49b981a','秋寄李頻使君二首 二','貫休','唐','唐诗','tang','','[]','務簡趣難陪，清吟共綠苔。',48,'全唐诗/poet.tang.45000.json','["務簡趣難陪，清吟共綠苔。", "葉和秋蟻落，僧帶野香來。", "留客朝嘗酒，憂民夜畫灰。", "終期冒風雪，江上見宗雷。"]'),
('e6791481-45a7-4c10-a119-22c2963708f1','上東林和尚','貫休','唐','唐诗','tang','','[]','讓紫歸青壁，高名四海聞。',48,'全唐诗/poet.tang.45000.json','["讓紫歸青壁，高名四海聞。", "雖然無一事，得不是要君。", "道祗傳伊字，詩多笑碧雲。", "應憐門下客，餘力亦爲文。"]'),
('d60762fd-8b7e-41fb-922c-c1e2bc5e70f9','江邊道士','貫休','唐','唐诗','tang','','[]','獨住大江濱，不知何代人。',50,'全唐诗/poet.tang.45000.json','["獨住大江濱，不知何代人。", "藥罏生紫氣，肌肉似紅銀。", "酒釅竹屋[爛]，符收山鬼仁。", "何妨將我去，一看武陵春。"]'),
('e484cc34-6bcd-463b-ae30-f8415b448932','送僧之湖外','貫休','唐','唐诗','tang','','[]','去旨趣非常，春風爾莫狂。',48,'全唐诗/poet.tang.45000.json','["去旨趣非常，春風爾莫狂。", "惟擎一鐵鉢，舊亦講金剛。", "午飯孤煙裏，宵禪大石旁。", "羨師終不及，湘浪淥茫茫。"]'),
('2003d1a4-829a-4952-904d-72b1ed0d7e58','懷謬獨一','貫休','唐','唐诗','tang','','[]','常憶蘭陵子，瓌奇皴渴才。',48,'全唐诗/poet.tang.45000.json','["常憶蘭陵子，瓌奇皴渴才。", "思還如我苦，時不爲伊來。", "岳霞猱擲雪，湖月浪翻杯。", "未聞霑寸祿，此事亦堪哀。"]'),
('aba94546-a2d9-425d-b4a5-6468bb951fe5','送廬山衲僧','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','飛錫下崆㟅，清高世少雙。',50,'全唐诗/poet.tang.45000.json','["飛錫下崆㟅，清高世少雙。", "凍天方篩雪，別我去何邦。", "燒繞赤烏亥，雲漫白蚌江。", "路人爭得識，空仰鬢眉[龐]。"]'),
('17d6e480-90d2-4c24-a800-0192028a812e','寄西山胡汾吳樵','貫休','唐','唐诗','tang','','[]','帶經鋤隴者，何止手胼胝。',48,'全唐诗/poet.tang.45000.json','["帶經鋤隴者，何止手胼胝。", "覓句句句好，慙予筋力衰。", "雲塠臨案冷，鹿隊過門遲。", "相憶空回首，江頭日暮時。"]'),
('7f90985a-7b30-4196-85a7-d3da41c8d351','休糧僧','貫休','唐','唐诗','tang','','[]','不食更何憂，自由中自由。',48,'全唐诗/poet.tang.45000.json','["不食更何憂，自由中自由。", "身輕嫌衲重，天旱爲民愁。", "應器誰將去，生臺蟻不遊。", "會須傳此術，相共老山丘。"]'),
('08aa7e3f-58d0-45a0-9002-eb138c62d0c5','送杜使君朝覲','貫休','唐','唐诗','tang','','[]','借寇借不得，清聲徹帝聰。',96,'全唐诗/poet.tang.45000.json','["借寇借不得，清聲徹帝聰。", "坐來千里泰，歸去一囊空。", "遺愛封疆熟，扳轅草木同。", "路遙山不少，江靜思無窮。", "花舸衝煙濕，朱衣照浪紅。", "援毫兩岸曉，欹枕滿旗風。", "道罕將人合，心難與聖通。", "從茲林下客，應□代天功。"]'),
('10c9b064-44ca-457e-b31d-3ab1197a5354','送人之嶺外','貫休','唐','唐诗','tang','','[]','見說還南去，迢迢有侶無。',48,'全唐诗/poet.tang.45000.json','["見說還南去，迢迢有侶無。", "時危須早轉，親老莫他圖。", "小店虵羹黑，空山象糞枯。", "三閭遺廟在，爲我一鳴呼。"]'),
('2c23b5ff-e9d9-4a9a-9b3e-f0da181099da','題弘式和尚院兼呈杜使君','貫休','唐','唐诗','tang','','[]','二雅兼二密，愔愔祗自怡。',48,'全唐诗/poet.tang.45000.json','["二雅兼二密，愔愔祗自怡。", "臘高雲屐朽，貌古畫師疑。", "壍蟻緣金錫，罏煙惹雪眉。", "仍聞有新作，祗是寄相思。"]'),
('fadf4f2d-bd6b-430a-8b9b-1640ef60fa26','湖頭別墅三首 一','貫休','唐','唐诗','tang','','[]','梨栗鳥啾啾，高歌若自由。',48,'全唐诗/poet.tang.45000.json','["梨栗鳥啾啾，高歌若自由。", "人誰知此意，舊業在湖頭。", "飢鼠掀菱殻，新蟬避栗皺。", "不知江海上，戈甲幾時休。"]'),
('501c51d6-24d7-40dc-a8a7-ab633840e336','湖頭別墅三首 二','貫休','唐','唐诗','tang','','[]','桑柘參桐竹，陰陰一徑苔。',48,'全唐诗/poet.tang.45000.json','["桑柘參桐竹，陰陰一徑苔。", "更無他事出，祗有衲僧來。", "壍蟻爭生食，窗經卷燒灰。", "可憐門外路，日日起塵埃。"]'),
('19e2d254-3069-4354-a543-e5b00f8ca82b','湖頭別墅三首 三','貫休','唐','唐诗','tang','','[]','南北如仙境，東西似畫圖。',48,'全唐诗/poet.tang.45000.json','["南北如仙境，東西似畫圖。", "園飛青啄木，簷挂白蜘蛛。", "鄰叟教修廢，牛童與納租。", "寄言來往客，不用問榮枯。"]'),
('0c88819f-1fce-4552-837d-8cdb25f47c80','三峽聞猨','貫休','唐','唐诗','tang','','[]','歷歷數聲猨，寥寥渡白煙。',48,'全唐诗/poet.tang.45000.json','["歷歷數聲猨，寥寥渡白煙。", "應栖多月樹，況是下霜天。", "萬里客危坐，千山境悄然。", "更深仍不住，使我欲移船。"]'),
('55f96160-fe72-45d8-89a6-4a5cb058eb86','聞知聞赴成都辟請','貫休','唐','唐诗','tang','','[]','文翁還化蜀，帟幕列鵷鸞。',48,'全唐诗/poet.tang.45000.json','["文翁還化蜀，帟幕列鵷鸞。", "飲水臨人易，燒山覓士難。", "錦機花正合，椶蕈火初乾。", "知己相思否，如何借羽翰。"]'),
('f1bdf665-ca76-48fc-a04c-39b87dcba3c1','題淮南惠照寺律師院','貫休','唐','唐诗','tang','','[]','儀冠凝寒玉，端居似沃州。',48,'全唐诗/poet.tang.45000.json','["儀冠凝寒玉，端居似沃州。", "學徒梧有鳳，律藏目無牛。", "茗滑香黏齒，鐘清雪滴樓。", "還須結西社，來往悉諸侯。"]'),
('d4ab7baf-95ea-4e7f-8058-f66e84bcef28','秋末長興寺作','貫休','唐','唐诗','tang','','[]','荒寺古江濱，莓苔地絕塵。',48,'全唐诗/poet.tang.45000.json','["荒寺古江濱，莓苔地絕塵。", "長廊飛亂葉，寒雨更無人。", "栗不和皺落，僧多到骨貧。", "行行行未得，孤坐更誰親。"]'),
('df1a116f-fae6-4ba5-83ed-19b06b28e4c2','寄杭州靈隱寺宋震使君','貫休','唐','唐诗','tang','','[]','罷郡歸侵夏，仍聞靈隱居。',48,'全唐诗/poet.tang.45000.json','["罷郡歸侵夏，仍聞靈隱居。", "僧房謝朓語，寺額葛洪書。", "月樹獮猴睡，山池菡萏疎。", "吾皇愛清靜，莫便結吾廬。"]'),
('69b92e14-b8e7-450c-b2ad-6dc1eb640c6e','送人歸夏口','貫休','唐','唐诗','tang','','[]','鴈鴈葉紛紛，行人豈易聞。',48,'全唐诗/poet.tang.45000.json','["鴈鴈葉紛紛，行人豈易聞。", "千山與萬水，何處更逢君？", "貌不長如玉，人生祗似雲。", "倘經三祖寺，一爲禮龕墳。"]'),
('bb81fe79-0e09-4ff1-863e-f7a3fa6ee49c','送新羅僧歸本國','貫休','唐','唐诗','tang','','[]','忘身求至教，求得却東歸。',48,'全唐诗/poet.tang.45000.json','["忘身求至教，求得却東歸。", "離岸乘空去，終年無所依。", "月衝陰火出，帆拶大鵬飛。", "想得還鄉後，多應著紫衣。"]'),
('9ba76ba7-23d1-4762-a9f7-2050c3a228da','避寇入銀山','貫休','唐','唐诗','tang','','[]','草草穿銀峽，崎嶇路未諳。',48,'全唐诗/poet.tang.45000.json','["草草穿銀峽，崎嶇路未諳。", "傍山爲店戍，永日繞溪潭。", "燒地生芚蕨，人家煮僞蠶。", "翻如歸舊隱，步步入煙嵐。"]'),
('37bc4a26-3b08-424c-9267-a4615ff8ef97','聞友人駕前及第','貫休','唐','唐诗','tang','','[]','見心知命好，一別隔煙波。',48,'全唐诗/poet.tang.45000.json','["見心知命好，一別隔煙波。", "世亂無全士，君方掇大科。", "早隨鑾輅轉，莫戀蜀山多。", "必貢安時策，忠言奈爾何。"]'),
('480e4f20-0fd6-4a06-97bf-2b5d4bd7b2f3','避地毘陵上王慥使君','貫休','唐','唐诗','tang','','[]','至理至昭昭，心通即不遙。',240,'全唐诗/poet.tang.45000.json','["至理至昭昭，心通即不遙。", "聖威無遠近，吾道太孤標。", "辛苦蘇氓俗，端貞荅盛朝。", "氣高吞海岳，貧甚似漁樵。", "庾亮風流澹，劉寬政事超。", "清須遭貴遇，隱已被誰招。", "栗塢修禪寺，仙香寄石橋。", "風雷巡稼穡，魚鳥合歌謠。", "視事私終殺，憂民態亦彫。", "道高無不及，恩甚固難消。", "大寇山難隔，孤城數合燒。", "烽煙終日起，湯沐用心燋。", "勇義排千陣，誅鋤擬一朝。", "誓盟違日月，旌斾過寒潮。", "古驛江雲入，荒宮海雨飄。", "仙松添瘦碧，天驥減豐臕。", "似在陳兼衛，終爲宋與姚。", "已觀雲似鹿，即報首皆梟。", "盡願迴清鏡，重希在此條。", "應憐千萬戶，禱祝向唐堯。"]'),
('58f3543a-d635-47bd-b91b-692e092c5b64','送崔尚書朝覲','貫休','唐','唐诗','tang','','[]','至理契穹旻，方生甫與申。',144,'全唐诗/poet.tang.45000.json','["至理契穹旻，方生甫與申。", "一麾歌政正，三相賀仁人。", "叵似盧懷慎，全如邵信臣。", "澄渟消宿蠹，煦愛劇陽春。", "對客煙花拆，焚香渥澤新。", "徵黃還有自，挽鄧住無因。", "峽水全輸潔，巫娥却訝神。", "宋均顏未老，劉寵骨應貧。", "大醉辭王翦，含香望紫宸。", "三峰初有雪，萬里正無塵。", "伊昔林中社，多招席上珍。", "終期仙掌下，香火一相親。"]'),
('2b8602c2-0ace-4c49-a762-6de52f3353a0','寒夜有懷同志','貫休','唐','唐诗','tang','','[]','永夜殊不寐，懷君正寂寥。',48,'全唐诗/poet.tang.45000.json','["永夜殊不寐，懷君正寂寥。", "疎鐘寒徧郭，微雪靜鳴條。", "南省鴈孤下，西林鶴屢招。", "終當謝時去，與子住山椒。"]'),
('7ac5f2fa-46a7-4b33-bd8b-13100b40e885','寄新定桂雍','貫休','唐','唐诗','tang','','[]','獨自住烏龍，應憐是衲僧。',48,'全唐诗/poet.tang.45000.json','["獨自住烏龍，應憐是衲僧。", "句須人未道，君此事偏能。", "塢濕雲埋觀，溪寒月照罾。", "相思不可見，江上立騰騰。"]'),
('4ad0983d-f474-4449-b5f0-e461259a328c','贈靈鷲山道潤禪師院','貫休','唐','唐诗','tang','','[]','常恨煙波隔，聞名二十年。',48,'全唐诗/poet.tang.45000.json','["常恨煙波隔，聞名二十年。", "結爲清氣引，來到法堂前。", "薪拾紛紛葉，茶烹滴滴泉。", "莫嫌來又去，天道本泠然。"]'),
('c33be971-5cf6-4bed-bf73-7901c46f32fb','干霄亭晚望懷王棨侍郎','貫休','唐','唐诗','tang','','[]','霜打汀島赤，孤煙生池塘。',48,'全唐诗/poet.tang.45000.json','["霜打汀島赤，孤煙生池塘。", "清吟倚大樹，瑤草何馨香。", "久別青雲士，常思白石房。", "誰能共歸去，流水似鳴璫。"]'),
('25318673-4aef-42c4-89d9-7aed97ab6781','海邊見羅鄴','貫休','唐','唐诗','tang','','[]','清世詩聲出，誰人得似君。',48,'全唐诗/poet.tang.45000.json','["清世詩聲出，誰人得似君。", "命通須有日，天未喪斯文。", "楚木寒連寺，修江碧入雲。", "相思喜相見，庭葉正紛紛。"]'),
('7ddf9ef4-0fcd-47b0-87ae-045488e02c88','送僧之東都','貫休','唐','唐诗','tang','','["\u9ec4\u6cb3"]','之子之東洛，囊中有偈新。',48,'全唐诗/poet.tang.45000.json','["之子之東洛，囊中有偈新。", "紅塵誰不入，獨鶴自難親。", "定鼎門連岳，黃河凍過春。", "憑師將遠意，說似社中人。"]'),
('c9a02462-e7d8-40d1-a13a-b1c674e72353','送于兢補闕赴京','貫休','唐','唐诗','tang','','[]','亂離吾道在，不覺到清時。',48,'全唐诗/poet.tang.45000.json','["亂離吾道在，不覺到清時。", "得句下雪岳，送君登玉墀。", "冷驚蟬韻斷，涼觸火雲隳。", "倘遇南來使，無忘問所之。"]'),
('e6649508-3b80-4317-8d12-524ab291beab','送鄭準赴舉','貫休','唐','唐诗','tang','','[]','兩河兵火後，西笑見吾曹。',48,'全唐诗/poet.tang.45000.json','["兩河兵火後，西笑見吾曹。", "海靜三山出，天空一鶚高。", "賃居槐拶屋，行卷雪埋袍。", "他日如相覓，栽桃近海濤。"]'),
('c9b1c5b3-00a4-4bde-81ab-0c181431baff','寄拄杖上王使君','貫休','唐','唐诗','tang','','[]','拄杖鄰僧與，殊常不可名。',48,'全唐诗/poet.tang.45000.json','["拄杖鄰僧與，殊常不可名。", "一條黳玉重，百兩紫金輕。", "有乳盤春力，無心合道情。", "惟宜高處著，將寄謝宣城。"]'),
('1aee28e7-c254-4226-a065-259f79739f55','秋望寄王使君','貫休','唐','唐诗','tang','','[]','靜躡紅蘭徑，憑高曠望時。',48,'全唐诗/poet.tang.45000.json','["靜躡紅蘭徑，憑高曠望時。", "無端求句苦，永日壑風吹。", "大月生峰角，殘霞在樹枝。", "祗應劉越石，清嘯正相宜。"]'),
('e3acec7e-0989-4819-b308-5b2b950e0720','送緣有禪師與雷處士入武夷山','貫休','唐','唐诗','tang','','[]','師與雷居士，尋山道入閩。',48,'全唐诗/poet.tang.45000.json','["師與雷居士，尋山道入閩。", "應將熊耳印，別授武夷君。", "崖𥕕仙棺出，江垠毒草分。", "他年相覓在，莫苦入深雲。"]'),
('3a8af7dd-5c98-4550-a85f-fe712c9fe2b6','送友生入越投知己','貫休','唐','唐诗','tang','','[]','才大終難住，東浮景漸暄。',48,'全唐诗/poet.tang.45000.json','["才大終難住，東浮景漸暄。", "知將刖足恨，去擊李膺門。", "宿霧開花塢，春潮入苧村。", "預思秋薦後，一鶚出乾坤。"]'),
('086f8ae0-fcf0-4896-a691-940c0ed9af92','寄烏龍山賈泰處士','貫休','唐','唐诗','tang','','[]','庭果色如丹，相思夕照殘。',48,'全唐诗/poet.tang.45000.json','["庭果色如丹，相思夕照殘。", "雲邊踏燒去，月下把書看。", "澗水仙居共，窗風漆樹寒。", "吾君方側席，未可便懷安。"]'),
('e903cd38-5bef-4aaa-a44a-3d15f5112e1f','題大安寺通禪師院','貫休','唐','唐诗','tang','','[]','應行諸岳徧，象屣半無綱。',48,'全唐诗/poet.tang.45000.json','["應行諸岳徧，象屣半無綱。", "一法尋常說，此機仍未忘。", "窗閑藤影老，衲厚瀑痕荒。", "寄語迷津者，來茲問不妨。"]'),
('e51c9044-4a5c-4e8c-b14e-0824e8659302','春晚寄盧使君','貫休','唐','唐诗','tang','','[]','滿郭春如畫，空堂心自澄。',48,'全唐诗/poet.tang.45000.json','["滿郭春如畫，空堂心自澄。", "禪拋金鼎藥，詩和玉壺冰。", "白雨飄花盡，晴霞向閣凝。", "寂寥還得句，因寄柳吳興。"]'),
('a3017902-5140-4f2b-b704-c536a55f22ee','武昌縣與晝公兼寄邑宰','貫休','唐','唐诗','tang','','[]','小一何人識，騰騰天地間。',48,'全唐诗/poet.tang.45000.json','["小一何人識，騰騰天地間。", "尋常如一鶴，亦不愛青山。", "鐵鉢年多赤，麻衣帶毳斑。", "祗聞尋五柳，時到月中還。"]'),
('08b913a3-fb24-4395-a44c-a9795fd9d811','別東林僧','貫休','唐','唐诗','tang','','[]','大士宅裏宿，芙蓉龕畔遊。',48,'全唐诗/poet.tang.45000.json','["大士宅裏宿，芙蓉龕畔遊。", "自憐□□在，子莫苦相留。", "燥葉飄山席，孤雲傍茗甌。", "裴回不能去，房在好峰頭。"]'),
('9df5f97c-9dee-4e73-bcb2-956c8c82c23c','避地寄高蟾','貫休','唐','唐诗','tang','','[]','荒寺雨微微，空堂獨掩扉。',48,'全唐诗/poet.tang.45000.json','["荒寺雨微微，空堂獨掩扉。", "高吟多忤俗，此貌若爲飢。", "旅夢遭鴻喚，家山被賊圍。", "空餘老萊子，相見獨依依。"]'),
('9a934608-a290-4a63-bb24-9ff3cbab2041','懷武夷山禪師','貫休','唐','唐诗','tang','','[]','萬疊仙山裏，無緣見有緣。',48,'全唐诗/poet.tang.45000.json','["萬疊仙山裏，無緣見有緣。", "紅心蕉繞屋，白額虎同禪。", "古木苔封菌，深崖乳雜泉。", "終期還此去，世事祗如然。"]'),
('d04414d4-52fb-4fec-8656-2f23daa1ccd4','秋末閑居作','貫休','唐','唐诗','tang','','[]','幽居山不別，落葉與階平。',48,'全唐诗/poet.tang.45000.json','["幽居山不別，落葉與階平。", "盡日吟詩坐，無端箇病成。", "徑苔因旱赤，池水入冬清。", "惟有東峰叟，相尋月下行。"]'),
('d2ac2cfe-b74c-4df3-ad73-ca86567911d3','贈許徵君','貫休','唐','唐诗','tang','','[]','晝公友秦奚，來往踏溪雲。',48,'全唐诗/poet.tang.45000.json','["晝公友秦奚，來往踏溪雲。", "如今又到我，還愛許徵君。", "落花鳥銜來，永日香氤氳。", "終期將爾曹，歸去麋鹿羣。"]'),
('e8612de4-9a77-40dc-ac0c-59078aa156fb','秋夜作因懷天台道者','貫休','唐','唐诗','tang','','[]','萬事何須問，良時即此時。',48,'全唐诗/poet.tang.45000.json','["萬事何須問，良時即此時。", "高秋半夜雨，落葉滿前池。", "靜怕龍神識，貧從草木欺。", "平生無限事，祗有道人知。"]'),
('b27ab0cb-2e3e-4f65-aef8-7f8d226b5492','偶作因懷大同道友','貫休','唐','唐诗','tang','','[]','蠻木葉不落，微吟漳水濱。',48,'全唐诗/poet.tang.45000.json','["蠻木葉不落，微吟漳水濱。", "二毛空有雪，萬事不如人。", "壍水平芳草，山花落淨巾。", "天童好真伴，何日更相親。"]'),
('525e545e-5080-4ec2-8ea9-123c757d3df7','邊上行','貫休','唐','唐诗','tang','','[]','黑松林外路，風角遠嗈嗈。',48,'全唐诗/poet.tang.45000.json','["黑松林外路，風角遠嗈嗈。", "朔氣生荒堡，秋塵滿病容。", "豺掊沙底骨，人上月邊烽。", "休作西行計，西行地漸兇。"]'),
('1b836181-12f9-4517-9bc5-fd3ec578ed69','江西再逢周璉','貫休','唐','唐诗','tang','','[]','六七年不見，相逢鬢已蒼。',48,'全唐诗/poet.tang.45000.json','["六七年不見，相逢鬢已蒼。", "交情終淡薄，詩語更清狂。", "未得丹霄便，依前四壁荒。", "但令吾道在，晚達亦何妨。"]'),
('f95e49cd-8338-42a1-ac92-e89688fe4b3a','登鄱陽寺閣','貫休','唐','唐诗','tang','','[]','寺樓閑縱望，不覺到斜暉。',48,'全唐诗/poet.tang.45000.json','["寺樓閑縱望，不覺到斜暉。", "故國在何處，多年未得歸。", "寒江平楚外，細雨一鴻飛。", "終斅於陵子，吳山有綠薇。"]'),
('30aec185-4eff-4542-a328-d3702dcf8e54','秋晚野居','貫休','唐','唐诗','tang','','[]','僻居人不到，吾道本來孤。',48,'全唐诗/poet.tang.45000.json','["僻居人不到，吾道本來孤。", "山色園中有，詩魔象外無。", "霜禾連島赤，煙草倚橋枯。", "何必求深隱，門前似畫圖。"]'),
('13a138cd-8e8c-4334-9cc8-03c4149e2ad8','酬杜使君見寄','貫休','唐','唐诗','tang','','[]','軋軋復軋軋，更深門未關。',48,'全唐诗/poet.tang.45000.json','["軋軋復軋軋，更深門未關。", "心疼無所得，詩債若爲還。", "露灑一鶴睡，鐘餘萬象閑。", "慙將此時意，明日寄東山。"]'),
('9c4b0f6c-bd0e-4270-bbb4-9629acbaaf38','湖上作','貫休','唐','唐诗','tang','','[]','我竟胡爲者，嘮嘮但愛吟。',48,'全唐诗/poet.tang.45000.json','["我竟胡爲者，嘮嘮但愛吟。", "身中多病在，湖上住年深。", "山霤穿苔壁，風鐘度雪林。", "近來心更苦，誰復是知音。"]'),
('c047d8a4-35fa-4b1d-9244-4e32dd842048','送僧歸天台寺','貫休','唐','唐诗','tang','','[]','天台四絕寺，歸去見師真。',48,'全唐诗/poet.tang.45000.json','["天台四絕寺，歸去見師真。", "莫折枸杞葉，令他十得嗔。", "天空聞聖磬，瀑細落花巾。", "必若雲中老，他時得有鄰。"]'),
('7cbe66fe-efd2-4132-9383-71b3e8318a1b','壽春節進','貫休','唐','唐诗','tang','','[]','聖運關天紀，龍飛古帝基。',288,'全唐诗/poet.tang.45000.json','["聖運關天紀，龍飛古帝基。", "振搖三蜀地，聳發萬年枝。", "出震同中古，承乾動四夷。", "恩頒新命廣，淚向舊朝垂。", "大寶歸玄讖，殊祥出遠池。", "法天深罔測，體聖妙難知。", "儉德爲全德，無思契十思。", "丕圖非力至，英武悉天資。", "正直方親切，回邪豈敢窺。", "將排頗與牧，相得稷兼夔。", "鹽出符真主，麟來合大規。", "賡歌隨羽籥，奕葉斅伊祁。", "寡欲情雖泰，憂民色未怡。", "盛如唐創業，宛勝晉朝儀。", "旰食宮鶯囀，宵衣禁漏遲。", "多於湯土地，還有禹胼胝。", "視物如傷日，勝殘去殺時。", "守文情的的，無逸戒孜孜。", "軒頊風重振，皇唐鼎創移。", "始聞呈瑞石，又報產靈芝。", "覆幬高緣大，包容妙在卑。", "兄呼春赫日，師指佛牟尼。", "佳氣宸居合，淳風樂府吹。", "急賢彰帝業，解網見天慈。"]'),
('71cf5a48-286d-4038-ab39-a3753fb48425','送僧之安南','貫休','唐','唐诗','tang','','[]','安南千萬里，師去趣何長。',48,'全唐诗/poet.tang.45000.json','["安南千萬里，師去趣何長。", "鬢有炎州雪，心爲異國香。", "退牙山象惡，過海布帆荒。", "早作歸吳計，無忘父母鄉。"]'),
('e5390c99-dbb3-4082-b090-a2993accba44','送僧歸剡山','貫休','唐','唐诗','tang','','[]','遠逃爲亂處，寺與石城連。',48,'全唐诗/poet.tang.45000.json','["遠逃爲亂處，寺與石城連。", "木落歸山路，人初刈剡田。", "荒林猴咬栗，戰地鬼多年。", "好去楞伽子，精修莫偶然。"]'),
('6bfb6de0-ca15-4efb-a45d-a40f1000ed32','送僧入幽州','貫休','唐','唐诗','tang','','[]','高士高無敵，騰騰話入燕。',48,'全唐诗/poet.tang.45000.json','["高士高無敵，騰騰話入燕。", "無人知爾意，向我道非禪。", "栗逕穿蕃冢，狼聲隔遠煙。", "槃山多道侶，應未有歸年。"]'),
('66717e3a-7e92-4e45-866d-1b3040663704','送僧遊五臺','貫休','唐','唐诗','tang','','[]','羨師遊五頂，乞食值年豐。',48,'全唐诗/poet.tang.45000.json','["羨師遊五頂，乞食值年豐。", "去去誰爲侶，栖栖力已充。", "濁河高岸拆，衰草古城空。", "必到華嚴寺，憑師問辨公。"]'),
('dd159603-2350-4133-ae6d-5c348aba8c25','送僧入五洩','貫休','唐','唐诗','tang','','[]','五洩江山寺，禪林境最奇。',48,'全唐诗/poet.tang.45000.json','["五洩江山寺，禪林境最奇。", "九年喫菜粥，此事少人知。", "山響僧擔穀，林香豹乳兒。", "伊余頭已白，不去更何之。"]'),
('aa4c2d7c-010e-4cf1-98b2-dd230dbfe621','題令宣和尚院','貫休','唐','唐诗','tang','','[]','軒窗領嵐翠，師得世情忘。',48,'全唐诗/poet.tang.45000.json','["軒窗領嵐翠，師得世情忘。", "惟愛談諸祖，曾經宿大荒。", "泉聲淹臥榻，雲片犯鑪香。", "寄語題門者，看經在上方。"]'),
('771a895b-913a-415f-a75e-8b4112333e61','寄四明閭丘道士二首 一','貫休','唐','唐诗','tang','','[]','淮海兵荒日，分飛直至今。',48,'全唐诗/poet.tang.45000.json','["淮海兵荒日，分飛直至今。", "知擔諸子出，却入四明深。", "衣必編仙草，僧應共栗林。", "秋風溪上路，應得一相尋。"]'),
('a5007e8b-4da7-4ec3-8c63-07bb32b86b76','寄四明閭丘道士二首 二','貫休','唐','唐诗','tang','','[]','三千功未了，大道本無程。',48,'全唐诗/poet.tang.45000.json','["三千功未了，大道本無程。", "好共禪師好，牆將藥犬行。", "石門紅蘚剝，柘塢白雲生。", "莫認無名是，無名已是名。"]'),
('3f216211-6e9e-4ca8-b22f-6309fabbe25c','經士馬中作','貫休','唐','唐诗','tang','','[]','偷兒成大寇，處處起煙塵。',48,'全唐诗/poet.tang.45000.json','["偷兒成大寇，處處起煙塵。", "黃葉滿空宅，青山見俗人。", "妖星芒刺越，鬼哭勢連秦。", "惆悵還惆悵，茫茫江海濱。"]'),
('37087c5a-4952-4cac-addd-29b4f2369899','士馬後見赤松舒道士','貫休','唐','唐诗','tang','','[]','滿眼盡瘡痍，相逢相對悲。',48,'全唐诗/poet.tang.45000.json','["滿眼盡瘡痍，相逢相對悲。", "亂階猶未已，一柱若爲支。", "堰茗蒸紅棗，看花似好時。", "不知今日後，吾道竟何之。"]'),
('522876a2-be3b-4275-a0ea-b3238c20e796','題方公院寄夏侯明府','貫休','唐','唐诗','tang','','[]','銀地有餘光，方公道益芳。',48,'全唐诗/poet.tang.45000.json','["銀地有餘光，方公道益芳。", "誰分修藏力，頂有剃頭霜。", "經勘松風燥，簷垂塢茗香。", "終須結西社，此縣似柴桑。"]'),
('b89c776e-a8ff-4142-89bb-ad7eb1607de8','與劉象正字','貫休','唐','唐诗','tang','','[]','獨居三島上，花竹映柴關。',48,'全唐诗/poet.tang.45000.json','["獨居三島上，花竹映柴關。", "道廣羣仙惜，名成萬事閑。", "病多唯縱酒，靜極不思山。", "唯有逍遙子，時時自往還。"]'),
('8aee9d96-68d9-4f98-8e8c-7398592228ad','懷智體道人','貫休','唐','唐诗','tang','','[]','栖碧思吾友，庭鶯百囀時。',48,'全唐诗/poet.tang.45000.json','["栖碧思吾友，庭鶯百囀時。", "唯應一處住，方得不相思。", "雲水淹門閫，春雷在樹枝。", "平生無限事，不獨白雲知。"]'),
('4fbc473c-0e44-4473-a652-e2d492942c4c','贈晦公禪人','貫休','唐','唐诗','tang','','[]','流陽爲役者，相訪葉紛紛。',48,'全唐诗/poet.tang.45000.json','["流陽爲役者，相訪葉紛紛。", "有句雖如我，無心未似君。", "搆林青及竹，茆屋暖於雲。", "何日相將去，千山麋鹿羣。"]'),
('175506e9-c38f-4ce1-be8a-f4622fe46631','寄靜林別墅胡進士兄弟','貫休','唐','唐诗','tang','','[]','見說山居好，書樓被翠侵。',48,'全唐诗/poet.tang.45000.json','["見說山居好，書樓被翠侵。", "燒熛汀島境，月色弟兄吟。", "犬吠黃椑落，牛歸紅樹深。", "仍聞多白菌，應許一相尋。"]'),
('4273dd44-be33-493c-8b2a-8e56844c678a','懷赤松故舒道士','貫休','唐','唐诗','tang','','[]','可惜復可惜，如今何所之。',48,'全唐诗/poet.tang.46000.json','["可惜復可惜，如今何所之。", "信來堪大慟，余復用生爲。", "亂世今交鬬，玄宮玉柱隳。", "春風五陵道，迴首不勝悲。"]'),
('9462fbdb-3e82-4c66-9664-4a9a48f26145','偶作','貫休','唐','唐诗','tang','','[]','無端爲五字，字字鬢星星。',48,'全唐诗/poet.tang.46000.json','["無端爲五字，字字鬢星星。", "祗覺人情薄，空餘鶴眼青。", "砌莎藏墜果，窗雪浸殘經。", "祗有歸山計，茫茫何所營。"]'),
('96febb86-fd57-4d6f-a5fe-eff5eb405508','春日許徵君見訪','貫休','唐','唐诗','tang','','[]','龍鍾多病後，日望遇昇平。',48,'全唐诗/poet.tang.46000.json','["龍鍾多病後，日望遇昇平。", "遠念穿嵩雪，前林囀早鶯。", "廚香烹瓠葉，道友扣門聲。", "還似青溪上，微吟踏葉行。"]'),
('252eeb01-543e-4090-92d0-ee1e07104815','經先主廟作','貫休','唐','唐诗','tang','','[]','古廟積煙蘿，威靈及物多。',48,'全唐诗/poet.tang.46000.json','["古廟積煙蘿，威靈及物多。", "因知曹孟德，爭奈此公何。", "樹古雷痕剝，碑荒篆畫訛。", "今朝冥禱祝，祗望息干戈。"]'),
('fc2dae4f-0088-4da7-b321-684daa48de3e','寄中條道者','貫休','唐','唐诗','tang','','[]','柏梯杉影裏，頭白藥山孫。',48,'全唐诗/poet.tang.46000.json','["柏梯杉影裏，頭白藥山孫。", "今古管不得，是非爭肯論。", "虎鬚懸瀑滴，禪衲帶苔痕。", "常恨龍鍾也，無因接話言。"]'),
('d9b20a13-863b-4ef4-b123-acf03a25c13c','夏日晚望','貫休','唐','唐诗','tang','','[]','登臨聊一望，不覺意恞然。',48,'全唐诗/poet.tang.46000.json','["登臨聊一望，不覺意恞然。", "陶侃寒溪寺，如今何處邊。", "汀沙生旱霧，山火照平川。", "終事東歸去，干戈滿許田。"]'),
('96f2b887-08cf-48cd-bf65-e6ca0804651c','送僧歸山','貫休','唐','唐诗','tang','','[]','眼青禪帔赤，氣岸出塵埃。',48,'全唐诗/poet.tang.46000.json','["眼青禪帔赤，氣岸出塵埃。", "霞外終須去，人間作麽來。", "崖香泉吐乳，塢燥燒□靁。", "他日終相覓，山門何處開。"]'),
('4d149d11-0994-4c0e-ac02-5e83fe7326ee','覽皎然渠南鄉集','貫休','唐','唐诗','tang','','[]','學力不相敵，清還彷彿同。',48,'全唐诗/poet.tang.46000.json','["學力不相敵，清還彷彿同。", "高于寶月月，誰得射鵰弓。", "至鑒封姚監，良工遇魯公。", "如斯深可慕，千古共清風。"]'),
('ad271a01-f877-47f3-ae99-62dd84891260','覽姚合極玄集','貫休','唐','唐诗','tang','','[]','至覽如日月，今時即古時。',48,'全唐诗/poet.tang.46000.json','["至覽如日月，今時即古時。", "髮如邊草白，誰念射聲□。", "好鳥挨花落，清風出院遲。", "知音郭有道，始爲一吟之。"]'),
('51dc8948-fd9c-45fd-a69d-fb15c8e59589','大駕西幸秋日聞雷','貫休','唐','唐诗','tang','','[]','軍書日日催，處處起塵埃。',48,'全唐诗/poet.tang.46000.json','["軍書日日催，處處起塵埃。", "黎庶何由泰，鑾輿早晚回。", "夏租方減食，秋日更聞雷。", "莫道蒼蒼意，蒼蒼眼甚開。"]'),
('6a2d484d-209e-44ba-82b2-1967f8adcb1e','詩','貫休','唐','唐诗','tang','','[]','經天緯地物，動必計仙才。',48,'全唐诗/poet.tang.46000.json','["經天緯地物，動必計仙才。", "幾處覓不得，有時還自來。", "真風含素髮，秋色入靈臺。", "吟向霜蟾下，終須神鬼哀。"]'),
('0255decc-b5bb-4da3-98a0-a4cb948840a8','秋末江上望','貫休','唐','唐诗','tang','','[]','莽莽古江濱，紛紛墜葉頻。',48,'全唐诗/poet.tang.46000.json','["莽莽古江濱，紛紛墜葉頻。", "煙霞誰是主，丘隴自傷神。", "吞併寧唯漢，淒涼莫問陳。", "盡隨流水去，寂寞野花春。"]'),
('00a6ca5c-3e98-4fda-a295-c362713e692b','乞食僧','貫休','唐','唐诗','tang','','[]','擎鉢貌清羸，天寒出寺遲。',48,'全唐诗/poet.tang.46000.json','["擎鉢貌清羸，天寒出寺遲。", "朱門當大路，風雪立多時。", "似月心常淨，如麻事不知。", "行人莫輕誚，古佛盡如斯。"]'),
('f254cac9-e2dc-4085-af8b-e40a895c0032','寒望九峰作','貫休','唐','唐诗','tang','','[]','九朵碧芙蕖，王維圖未圖。',48,'全唐诗/poet.tang.46000.json','["九朵碧芙蕖，王維圖未圖。", "層層皆有瀑，一一合吾居。", "雨歇如爭出，霜嚴不例枯。", "世猶多事在，爲爾久躊躇。"]'),
('49741534-bb7c-488a-8d2a-be1507a461b3','薊北寒月作','貫休','唐','唐诗','tang','','[]','薊門寒到骨，戰磧鴈相悲。',48,'全唐诗/poet.tang.46000.json','["薊門寒到骨，戰磧鴈相悲。", "古屋不勝雪，嚴風欲斷髭。", "清吟得冷句，遠念失佳期。", "寂莫誰相問，迢迢天一涯。"]'),
('61bf19ab-bb91-4333-a986-aea3dc04b191','新猨','貫休','唐','唐诗','tang','','[]','尋常看不見，花落樹多苔。',48,'全唐诗/poet.tang.46000.json','["尋常看不見，花落樹多苔。", "忽向高枝發，又從何處來？", "風清聲更揭，月苦意彌哀。", "多少求名者，年年被爾催。"]'),
('c900276a-a8ca-4dea-866a-478a565f5fb2','懷南岳隱士二首 一','貫休','唐','唐诗','tang','','[]','千峰映碧湘，真隱此中藏。',48,'全唐诗/poet.tang.46000.json','["千峰映碧湘，真隱此中藏。", "餅不煮石喫，眉應似髮長。", "風榸支酒甕，鶴蝨落琴床。", "雖斅忘機者，斯人尚未忘。"]'),
('29ae6173-c0a7-48eb-9389-93a839d8a133','懷南岳隱士二首 二','貫休','唐','唐诗','tang','','[]','見說祝融峰，擎天勢似騰。',48,'全唐诗/poet.tang.46000.json','["見說祝融峰，擎天勢似騰。", "藏千尋瀑布，出十八高僧。", "古路無人跡，新霞出石稜。", "終期將爾叟，一一月中登。"]'),
('ab617656-3109-4691-8035-bb1c072e35b2','追憶馮少常','貫休','唐','唐诗','tang','','[]','盛德方清貴，旋聞逐逝波。',48,'全唐诗/poet.tang.46000.json','["盛德方清貴，旋聞逐逝波。", "令人翻不會，積善合如何。", "直道登朝晚，分憂及物多。", "至今新定郡，猶詠袴襦歌。"]'),
('0d5769b1-7767-4a07-bd05-fbc09bef304b','聞閔廷言周璉下第','貫休','唐','唐诗','tang','','[]','前牓年年見，高名日日聞。',48,'全唐诗/poet.tang.46000.json','["前牓年年見，高名日日聞。", "常因不平事，便欲見吾君。", "兄弟居清島，園林生白雲。", "相思空悵望，庭葉赤紛紛。"]'),
('8edf0d94-af14-4e33-bee9-b72de300b828','寄景地判官','貫休','唐','唐诗','tang','','[]','渚宮江上別，倏忽十餘年。',48,'全唐诗/poet.tang.46000.json','["渚宮江上別，倏忽十餘年。", "舉世唯攻說，多君即不然。", "浦珠爲履重，園柳助詩玄。", "勉力酬知己，昌朝正急賢。"]'),
('5f4709ba-359c-4c74-af9a-2723ea82799b','讀賈區賈島集','貫休','唐','唐诗','tang','','[]','區終不下島，島亦不多區。',48,'全唐诗/poet.tang.46000.json','["區終不下島，島亦不多區。", "冷格俱無敵，貧根亦似愚。", "青雲終歎命，白閣久圍鑪。", "今日成名者，還堪爲爾吁。"]'),
('b5b63a09-77d3-43e3-bd65-ff0b6aa43843','送衲僧之江西','貫休','唐','唐诗','tang','','[]','索索復索索，無憑却有憑。',48,'全唐诗/poet.tang.46000.json','["索索復索索，無憑却有憑。", "過溪遭惡雨，乞食得乾菱。", "祗有山相伴，終無事可仍。", "如逢梅嶺旦，向道祗寧馨。"]'),
('4c9f354c-2295-4388-9f19-4b5921e744fc','故林偶作','貫休','唐','唐诗','tang','','[]','朗吟無一事，孤坐瀔江濆。',48,'全唐诗/poet.tang.46000.json','["朗吟無一事，孤坐瀔江濆。", "媚世非吾道，良圖有白雲。", "蠹魚開卷落，啄木隔花聞。", "唯寄壺中客，金丹許共分。"]'),
('add5fcf7-82bd-47c4-aba9-706a2dfce502','寄栖白大師二首 一','貫休','唐','唐诗','tang','','[]','流浪江湖久，攀緣歲月闌。',48,'全唐诗/poet.tang.46000.json','["流浪江湖久，攀緣歲月闌。", "高名當世重，好句逼人寒。", "月苦蟬聲嗄，鐘清柿葉乾。", "龍鍾千萬里，擬欲訪師難。"]'),
('70e0bd29-19cc-47be-9c51-656fb0cccdf6','寄栖白大師二首 二','貫休','唐','唐诗','tang','','[]','蒼蒼龍闕晚，九陌雜香塵。',48,'全唐诗/poet.tang.46000.json','["蒼蒼龍闕晚，九陌雜香塵。", "方外無他事，僧中有近臣。", "青門玉露滴，紫閣錦霞新。", "莫話三峰去，澆風正蕩淳。"]'),
('e890fa8f-ef38-4559-bf37-41f23fbb986f','送人之渤海','貫休','唐','唐诗','tang','','[]','國之東北角，有國每朝天。',48,'全唐诗/poet.tang.46000.json','["國之東北角，有國每朝天。", "海力浸不盡，夷風常宛然。", "山藏羅剎宅，水雜巨鼇涎。", "好去吳鄉子，歸來莫隔年。"]'),
('3243f69c-2781-43db-94fc-80d9ff2619f2','寄李道士','貫休','唐','唐诗','tang','','[]','常見高人說，猶來不偶然。',48,'全唐诗/poet.tang.46000.json','["常見高人說，猶來不偶然。", "致身同槁木，話道出忘詮。", "長嘯仙鐘外，眠楂海月邊。", "倘修陰奼奼，一望寄余焉。"]'),
('285410fe-e0ee-4048-8da3-ea16725ce326','秋送夏郢歸錢塘','貫休','唐','唐诗','tang','','[]','歸客指吳國，風帆幾日程。',48,'全唐诗/poet.tang.46000.json','["歸客指吳國，風帆幾日程。", "新詩陶雪字，玄髮有霜莖。", "微月生滄海，殘濤傍石城。", "從茲江島意，應續子陵名。"]'),
('80ebb584-ba83-444f-88ae-08edaf422888','送僧歸翠微','貫休','唐','唐诗','tang','','[]','祗衲一箇衲，翠微歸舊岑。',48,'全唐诗/poet.tang.46000.json','["祗衲一箇衲，翠微歸舊岑。", "不知何歲月，即得到師心。", "逕遶千峰細，菴開亂木深。", "倘然雲外老，他日亦相尋。"]'),
('6e66327a-4ad6-4149-9049-0a3a16707d17','經友生墳','貫休','唐','唐诗','tang','','[]','多君墳在此，令我過悲涼。',48,'全唐诗/poet.tang.46000.json','["多君墳在此，令我過悲涼。", "可惜爲人好，剛須被數將。", "白雲從冢出，秋草爲誰荒。", "不覺頻回首，西風滿白楊。"]'),
('5c433894-b8ad-4808-b9d0-7969988a6c80','懷洛下盧縉雲','貫休','唐','唐诗','tang','','[]','一減三張價，幽居少室前。',48,'全唐诗/poet.tang.46000.json','["一減三張價，幽居少室前。", "豈應貧似我，不得信經年。", "木落多詩藁，山枯見墨煙。", "何時深夜坐，共話草堂禪。"]'),
('df6803fd-a80d-436f-8843-8805fbfacfff','送李鉶赴舉','貫休','唐','唐诗','tang','','[]','詩業務經綸，新皆意外新。',48,'全唐诗/poet.tang.46000.json','["詩業務經綸，新皆意外新。", "因知登第牓，不著不平人。", "句得孤舟月，心飛九陌塵。", "明年相賀日，應到曲江濱。"]'),
('fe6b97eb-7117-4ef1-948c-0e09955607a8','寶禪師見訪','貫休','唐','唐诗','tang','','[]','山兄心似我，岸谷亦難交。',48,'全唐诗/poet.tang.46000.json','["山兄心似我，岸谷亦難交。", "不見還相憶，來唯添寂寥。", "茶煙黏衲葉，雲水透蘅茆。", "因話流年事，斯須不可拋。"]'),
('a93b2ba2-9953-44b2-bfec-d3eb0443bb92','觀碁','貫休','唐','唐诗','tang','','[]','逸格格難及，半先相遇稀。',48,'全唐诗/poet.tang.46000.json','["逸格格難及，半先相遇稀。", "落花方滿地，一局到斜暉。", "褚胤死不死，將軍飛已飛。", "今朝慙一行，無以造玄微。"]'),
('cf79bf91-0526-4cf8-b359-acfab4c88ea1','題一上人經閣','貫休','唐','唐诗','tang','','[]','鳥外何須去，衣如蘚亦從。',48,'全唐诗/poet.tang.46000.json','["鳥外何須去，衣如蘚亦從。", "但能無一事，即是住孤峰。", "雨歇雲埋閣，月明霜灑松。", "師心多似我，所以訪師重。"]'),
('60ba02ca-1661-4bcc-8c0a-81f1ff06cc42','和毛學士舍人早春','貫休','唐','唐诗','tang','','[]','陋巷冬將盡，東風細雜籃。',144,'全唐诗/poet.tang.46000.json','["陋巷冬將盡，東風細雜籃。", "解牽窗夢遠，先是澗梅諳。", "茶癖金鐺快，松香玉露含。", "書齋山帚撅，盤饌藥花甘。", "雅得琴中妙，常挼臉似酣。", "雪消聞苦蟄，氣候似宜蠶。", "密勿須清甲，朝歸遶碧潭。", "丹心空拱北，新作繼周南。", "竹杖無斑點，紗巾不著簪。", "大朝名益重，後進力皆覃。", "至理雖亡一，臣時亦說三。", "不知門下客，誰上晏嬰驂。"]'),
('be4ea984-34ba-4689-b7b4-3846ca440d03','壽春進祝聖七首 千載降祥','貫休','唐','唐诗','tang','','[]','九天宮上聖，降世共昭回。',48,'全唐诗/poet.tang.46000.json','["九天宮上聖，降世共昭回。", "萬彙須亭毓，羣仙送下來。", "承乾當否極，庶事盡康哉。", "祗有羲軒比，其餘不可陪。"]'),
('fb48b6a9-020f-4bb7-a038-8c4178f14a3d','壽春進祝聖七首 文有武備','貫休','唐','唐诗','tang','','[]','武宿與文星，常如掌上擎。',48,'全唐诗/poet.tang.46000.json','["武宿與文星，常如掌上擎。", "孫吳機不動，周邵事多行。", "旰食爐煙細，宵衣隙月明。", "還聞夔進曲，吹出泰階平。"]'),
('dcb629c4-f793-4628-94d7-f75c5dea1f44','壽春進祝聖七首 從諫如流','貫休','唐','唐诗','tang','','[]','及霤龍鱗動，君臣道義深。',48,'全唐诗/poet.tang.46000.json','["及霤龍鱗動，君臣道義深。", "萬年軒后鏡，一片漢高心。", "北狄皆輸欵，南夷盡貢琛。", "從茲千萬歲，枝葉玉森森。"]'),
('d4b31556-2fae-40ca-9409-359c7793c986','壽春進祝聖七首 搜揚草澤','貫休','唐','唐诗','tang','','[]','俟時兼待價，垂棘出塵埃。',48,'全唐诗/poet.tang.46000.json','["俟時兼待價，垂棘出塵埃。", "仄席三旌切，移山萬里來。", "煙霞衣上落，閶闔雪中開。", "壽酒今朝進，無非出世才。"]'),
('02db6361-eca2-424a-807a-0c1b7861f39e','壽春進祝聖七首 守在四夷','貫休','唐','唐诗','tang','','[]','天將興大蜀，有道遂君臨。',48,'全唐诗/poet.tang.46000.json','["天將興大蜀，有道遂君臨。", "四塞同諸子，三邊共一心。", "闍婆香似雪，迴鶻馬如林。", "曾讀前皇傳，巍巍冠古今。"]'),
('a717cfb6-f815-42d1-bd45-761be72bb35d','壽春進祝聖七首 大興三教','貫休','唐','唐诗','tang','','[]','曈曈懸佛日，天俁動雲韶。',48,'全唐诗/poet.tang.46000.json','["曈曈懸佛日，天俁動雲韶。", "縫掖諸生集，麟洲羽客朝。", "非煙生玉砌，御柳吐金條。", "擊壤翁知否，吾皇即帝堯。"]'),
('0d543fc0-87fd-4499-b023-e7b9ec10a29a','壽春進祝聖七首 山呼萬歲','貫休','唐','唐诗','tang','','[]','聲教無爲日，山呼萬歲聲。',48,'全唐诗/poet.tang.46000.json','["聲教無爲日，山呼萬歲聲。", "隆隆如谷響，合合似雷鳴。", "翠拔爲天柱，根盤倚鳳城。", "恭唯千萬歲，歲歲致昇平。"]'),
('7d1c3b2f-07c9-45d9-9bf7-fbc564e38a07','早秋夜坐','貫休','唐','唐诗','tang','','[]','微涼砧滿城，林下石牀平。',48,'全唐诗/poet.tang.46000.json','["微涼砧滿城，林下石牀平。", "髮豈無端白，詩須出世清。", "鄰僧同樹影，砌月浸蛩聲。", "獨自更深坐，無人知此情。"]'),
('5a462560-cf31-4b31-8ee4-750840065796','早起','貫休','唐','唐诗','tang','','[]','夜坐還早起，寂寥多病身。',48,'全唐诗/poet.tang.46000.json','["夜坐還早起，寂寥多病身。", "神清尋夢在，香極覺花新。", "樹露繁於雨，溪雲動似人。", "又知何處客，軋軋轉征輪。"]'),
('087be504-e02f-456d-9862-961c7dc55a9d','秋晚野步','貫休','唐','唐诗','tang','','[]','閑步不覺遠，蕭蕭木落初。',48,'全唐诗/poet.tang.46000.json','["閑步不覺遠，蕭蕭木落初。", "詩情拋閫閾，江影動襟裾。", "閣北鴻行出，霞西雨脚疎。", "金峰秋更好，乞取又何如。"]'),
('b26cd082-0c0b-41cb-98a1-2a13389b22ea','晚望','貫休','唐','唐诗','tang','','[]','曠望危橋上，微吟落照前。',48,'全唐诗/poet.tang.46000.json','["曠望危橋上，微吟落照前。", "煙霞濃浸海，川岳闊連天。", "白鳥格不俗，孤雲態可憐。", "終期將爾輩，歸去舊江邊。"]'),
('586f5ce1-3b73-4d88-8bbc-de3891ad2e48','寄翰林陸學士','貫休','唐','唐诗','tang','','[]','顏冉商參甲，鸞凰密勿才。',48,'全唐诗/poet.tang.46000.json','["顏冉商參甲，鸞凰密勿才。", "簾垂仙鳥下，吟次聖人來。", "寶輦千官捧，宮花九色開。", "何時重一見，爲我話蓬萊。"]'),
('3f66ede0-1e60-49d0-82d4-c007469decd1','贈造微禪師院','貫休','唐','唐诗','tang','','[]','薝蔔氣雍雍，門深聖澤重。',48,'全唐诗/poet.tang.46000.json','["薝蔔氣雍雍，門深聖澤重。", "七絲奔小蟹，五字逼雕龍。", "藥轉紅金鼎，茶開紫閣封。", "圭峰爭去得，卿相日憧憧。"]'),
('c92b7f80-2183-45e3-8b19-2209b4a9be24','南海晚望','貫休','唐','唐诗','tang','','[]','海上聊一望，舶帆天際飛。',48,'全唐诗/poet.tang.46000.json','["海上聊一望，舶帆天際飛。", "狂蠻莫挂甲，聖主正垂衣。", "風惡巨魚出，山昏羣獠歸。", "無人知此意，吟到月騰輝。"]'),
('b15167ff-7ef9-43e4-879b-4e5d66447f56','寄廬山大願和尚','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','石上桂成叢，師菴在桂中。',48,'全唐诗/poet.tang.46000.json','["石上桂成叢，師菴在桂中。", "皆云習鑿齒，未可扣真風。", "雪洗香鑪碧，霞藏瀑布紅。", "何時甘露偈，一寄剡山東。"]'),
('4b68df73-e583-47ce-ac8b-ff76445646f8','懷薛尚書兼呈東陽王使君','貫休','唐','唐诗','tang','','[]','得力未得力，高吟夏又殘。',48,'全唐诗/poet.tang.46000.json','["得力未得力，高吟夏又殘。", "二毛非自出，萬事到詩難。", "蟬見木葉落，雷將雨氣寒。", "何妨槌琢後，更獻至公看。"]'),
('fb0322ad-df37-4932-b240-3dbb7b36ad88','上馮使君水晶數珠','貫休','唐','唐诗','tang','','[]','泠泠瀑滴清，貫串有規程。',48,'全唐诗/poet.tang.46000.json','["泠泠瀑滴清，貫串有規程。", "將諷觀空偈，全勝照乘明。", "龍神多共惜，金玉比終輕。", "願在玄暉手，常資物外情。"]'),
('79e090ac-1376-4d6c-adec-6069b28da39d','送明覺大師兼寄鄭山人','貫休','唐','唐诗','tang','','[]','去去楞伽子，春深道路長。',48,'全唐诗/poet.tang.46000.json','["去去楞伽子，春深道路長。", "鳥啼青嶂險，花落紫衣香。", "此去非餘事，還歸內道場。", "憑師將老倒，一向說滎陽。"]'),
('0a4e4d59-759d-4007-8025-2ab7f56716b5','廬山尋靈紀不遇','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','久別稀相見，深山道益孤。',48,'全唐诗/poet.tang.46000.json','["久別稀相見，深山道益孤。", "葉全離大朴，君尚在新吳。", "鐘嗄聲飄驛，山頑氣噴湖。", "留詩如和得，一望寄前途。"]'),
('3f449a6b-eb57-4303-9220-5313d7846672','題曹溪祖師堂','貫休','唐','唐诗','tang','','[]','皎潔曹溪月，嵯峨七寶林。',48,'全唐诗/poet.tang.46000.json','["皎潔曹溪月，嵯峨七寶林。", "空傳智藥記，豈見祖禪心。", "信衣非苧麻，白雲無知音。", "大哉雙峰溪，萬古青沈沈。"]'),
('73480f2d-300a-455f-9a5c-777d6f40f3a6','懷匡山道侶','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','常憶將吾友，穿雲過瀑西。',48,'全唐诗/poet.tang.46000.json','["常憶將吾友，穿雲過瀑西。", "有碑皆讀徹，無處不相攜。", "檉桂株株濕，猨猱箇箇啼。", "等閑成遠別，窗月又如珪。"]'),
('553f082e-b6b0-4583-8296-1902d013a9ba','懷盧延讓','貫休','唐','唐诗','tang','','[]','冥搜忍飢凍，嗟爾不能休。',48,'全唐诗/poet.tang.46000.json','["冥搜忍飢凍，嗟爾不能休。", "幾歎不得力，到頭還白頭。", "姓名歸紫府，妻子在滄洲。", "又是蟬聲也，如今何處遊。"]'),
('7f1f4e41-ea61-4c6c-9d42-6c5e769d8ede','春晚訪鏡湖方干','貫休','唐','唐诗','tang','','[]','幽居湖北濱，相訪值殘春。',48,'全唐诗/poet.tang.46000.json','["幽居湖北濱，相訪值殘春。", "路遠諸峰雨，時多擉鼈人。", "蒸花初釀酒，漁艇劣容身。", "莫訝頻來此，伊余亦隱淪。"]'),
('3b852117-3c03-433f-9c8e-1d3b7c9ee392','秋過相思寺','貫休','唐','唐诗','tang','','[]','見說相思寺，今來似有期。',48,'全唐诗/poet.tang.46000.json','["見說相思寺，今來似有期。", "瘴鄉終有出，天意固難欺。", "晝雨先花島，秋雲挂戍旗。", "故人多在蜀，不去更何之。"]'),
('ff97bdaf-a4d5-40a5-b55b-53e233cd4beb','蜀王入大慈寺聽講','貫休','唐','唐诗','tang','','[]','玉節金珂響似雷，水晶宮殿步裴回。',192,'全唐诗/poet.tang.46000.json','["玉節金珂響似雷，水晶宮殿步裴回。", "祗緣支遁談經妙，所以許詢都講來。", "帝釋鏡中遙仰止，魔軍殿上動崔巍。", "千重香擁龍鱗立，五種風生錦繡開。", "寬似大溟生日月，秀如四岳出塵埃。", "一條紫氣隨高步，九色仙花落古臺。", "謝太傅須同八凱，姚梁公可並三台。", "登樓喜色禾將熟，望國誠明首不迴。", "駕馭英雄如赤子，雌黃賢哲貢瓊瑰。", "六條消息心常苦，一劒晶熒敵盡摧。", "木鐸聲中天降福，景星光裏地無災。", "百千民擁聽經座，始見重天社稷才。"]'),
('38257a71-72af-4dd8-8120-cee65750abf7','蜀王登福感寺塔三首 一','貫休','唐','唐诗','tang','','[]','天資忠孝佐金輪，香火空王有宿因。',64,'全唐诗/poet.tang.46000.json','["天資忠孝佐金輪，香火空王有宿因。", "此世喜登金骨塔，前生應是育王身。", "封疆歲暮笙歌合，襦袴正初錦繡新。", "釋子沾恩無以報，祗擎章句貢平津。"]'),
('58774bdc-c259-487e-8897-587a215626d1','蜀王登福感寺塔三首 二','貫休','唐','唐诗','tang','','[]','似聖悲增道不窮，憂民憂國契堯聰。',64,'全唐诗/poet.tang.46000.json','["似聖悲增道不窮，憂民憂國契堯聰。", "兩髯有雪丹霄外，萬里無塵一望中。", "南照微明連莽蒼，峨嵋擁秀接崆峒。", "林僧歲月知何幸，還似支公見謝公。"]'),
('c383e645-eb47-40e1-b5e5-1471574063e5','蜀王登福感寺塔三首 三','貫休','唐','唐诗','tang','','[]','步步層層孰可陪，相輪邊日照三台。',64,'全唐诗/poet.tang.46000.json','["步步層層孰可陪，相輪邊日照三台。", "喜歡烝庶皆相逐，惆悵鑾輿尚未迴。", "金鐸撼風天樂近，仙花含露瑞煙開。", "一年一度常如此，願見文翁百度來。"]'),
('7f732099-b457-4858-905d-eeda486117f3','少監三首 一','貫休','唐','唐诗','tang','','[]','器琢仙珪美有餘，席珍國寶比難如。',64,'全唐诗/poet.tang.46000.json','["器琢仙珪美有餘，席珍國寶比難如。", "銜花乳燕看調瑟，衣錦佳人侍讀書。", "荀氏門風龍變化，謝家庭樹玉扶疎。", "即期寰海隆平日，歸佐吾皇侍玉除。"]'),
('91d5945e-454b-43ad-9f48-7b44430b5b12','少監三首 二','貫休','唐','唐诗','tang','','[]','益友相隨益自強，趨庭問禮日昭彰。',64,'全唐诗/poet.tang.46000.json','["益友相隨益自強，趨庭問禮日昭彰。", "袍新宮錦千人目，馬駿桃花一巷香。", "偏愛曾顏終必及，或如韓白亦無妨。", "八龍三虎森如也，萬古千秋瑞聖唐。"]'),
('7e859272-53c0-4bd2-814f-9e5551983999','少監三首 三','貫休','唐','唐诗','tang','','[]','具體而微太少年，鳳毛五色帶非煙。',64,'全唐诗/poet.tang.46000.json','["具體而微太少年，鳳毛五色帶非煙。", "倚天長劒看無敵，遶樹號猨已應弦。", "接士開襟清聖熟，分題得句落花前。", "即應出將傳家法，聖澤恩波浩浩然。"]'),
('fc53e776-58ad-4b45-99d6-1798cade7a04','再到鍾陵作','貫休','唐','唐诗','tang','','[]','六七年來到豫章，舊遊知己半凋傷。',64,'全唐诗/poet.tang.46000.json','["六七年來到豫章，舊遊知己半凋傷。", "春風還有花千樹，往事都如夢一場。", "無限丘墟侵郭路，幾多臺榭浸湖光。", "祗應唯有西山色，依舊崔巍上寺牆。"]'),
('b5ee3dc2-2581-413e-ac6e-643033f074d5','經弟妹墳','貫休','唐','唐诗','tang','','[]','淚不曾垂此日垂，山前弟妹塚離離。',64,'全唐诗/poet.tang.46000.json','["淚不曾垂此日垂，山前弟妹塚離離。", "年長於吾未得力，家貧拋爾去多時。", "鴻衝□□霜中斷，蕙雜黃蒿冢上衰。", "恩愛苦情拋未得，不堪回首步遲遲。"]'),
('d85496ee-d568-44d2-a8c8-edd45f16bcca','到蜀與鄭中丞相遇','貫休','唐','唐诗','tang','','[]','深隱猶爲未死灰，遠尋知己遇三台。',64,'全唐诗/poet.tang.46000.json','["深隱猶爲未死灰，遠尋知己遇三台。", "如何麋鹿群中出，又見鵷鸞天上來。", "劒閣霞黏殘雪在，錦江香甚百花開。", "謾期王謝來相訪，不是支公出世才。"]'),
('4c7c7ccf-328c-402f-b249-1e1bdd418372','別馮使君','貫休','唐','唐诗','tang','','[]','瓦礫文章豈有媒，兩三年祗在金臺。',64,'全唐诗/poet.tang.46000.json','["瓦礫文章豈有媒，兩三年祗在金臺。", "本師頭白須歸去，太守門清願再來。", "皓皓玉霜孤鴈遠，蕭蕭松島片帆開。", "從茲林下終無事，唯祗焚香祝上台。"]'),
('86928a21-0110-4362-9446-47d22a7290e3','上新定宋使君','貫休','唐','唐诗','tang','','[]','禪坐吟行誰與同，杉松共在寂寥中。',64,'全唐诗/poet.tang.46000.json','["禪坐吟行誰與同，杉松共在寂寥中。", "碧雲詩裏終難到，白藕花經講始終。", "水疊山層擎草疏，砧清月苦立霜風。", "十年勤苦今酬了，得句桐江識謝公。"]'),
('56f08311-ac21-4463-9892-c25b72fbeef8','和李判官見新榜爲兄下第','貫休','唐','唐诗','tang','','[]','失意荆枝滴淚頻，陟岡何翅不知春。',64,'全唐诗/poet.tang.46000.json','["失意荆枝滴淚頻，陟岡何翅不知春。", "心中岐路平如砥，天上文章妙入神。", "休說宋風迴鷁首，即看雷火燎龍鱗。", "從茲相次紅霞裏，留取方書與世人。"]'),
('1f61dd74-db33-4bea-88a8-f8f6f1ce640d','送羅鄴赴許昌辟','貫休','唐','唐诗','tang','','[]','方得論心又別離，黯然江上步遲遲。',64,'全唐诗/poet.tang.46000.json','["方得論心又別離，黯然江上步遲遲。", "不堪迴首崎嶇路，正是寒風皴錯時。", "美似郄超終有日，去依劉表更何疑。", "前程不少南飛鴈，聊寄新詩慰所思。"]'),
('a3e65314-b712-4f10-9886-d9b22f0363ae','酬韋相公見寄','貫休','唐','唐诗','tang','','[]','鹽梅金鼎美調和，詩寄空林問訊多。',64,'全唐诗/poet.tang.46000.json','["鹽梅金鼎美調和，詩寄空林問訊多。", "秦客弈棊拋已久，楞嚴禪髓更無過。", "萬般如幻希先覺，一丈臨山且奈何。", "空諷平津好珠玉，不知更得及門麽。"]'),
('2ba5041b-9af1-48f4-bfff-bafa8a9fccb3','酬張相公見寄','貫休','唐','唐诗','tang','','[]','周郎懷抱好知音，常愛山僧物外心。',64,'全唐诗/poet.tang.46000.json','["周郎懷抱好知音，常愛山僧物外心。", "閉戶不知芳草歇，無能唯擬住山深。", "感通未合三生石，騷雅歡擎九轉金。", "但似前朝蕭與蔣，老僧風雪亦相尋。"]'),
('7d3ec8cc-4c6c-4b3b-9bf1-a308e25e44b5','酬王相公見贈','貫休','唐','唐诗','tang','','[]','孤拙將來豈偶然，不能爲漏滴青蓮。',64,'全唐诗/poet.tang.46000.json','["孤拙將來豈偶然，不能爲漏滴青蓮。", "一從麟筆題牆後，常祗冥心古像前。", "九德陶鎔空有跡，六窗清淨始通禪。", "今朝幸捧瓊瑤贈，始見玄中更有玄。"]'),
('fb6e48a5-51b8-4e70-ae3e-e4f916e1ce26','酬周相公見贈','貫休','唐','唐诗','tang','','[]','三界無家是出家，豈宜拊鳳覩新麻。',64,'全唐诗/poet.tang.46000.json','["三界無家是出家，豈宜拊鳳覩新麻。", "幸生白髮逢今聖，曾夢青蓮映玉沙。", "境陟名山烹錦水，睡忘東白洞平茶。", "喜擎繡段攀金鼎，謝朓餘霞始是霞。"]'),
('1dd0b5f7-7d20-430f-9c63-929fbfce0f3b','道情偈三首 一','貫休','唐','唐诗','tang','','[]','崆峒老人專一一，黃梅真叟却無無。',32,'全唐诗/poet.tang.46000.json','["崆峒老人專一一，黃梅真叟却無無。", "獨坐松根石頭上，四溟無限月輪孤。"]'),
('93a1ed0f-23ff-4e61-809e-d70932a8999f','道情偈三首 二','貫休','唐','唐诗','tang','','[]','非色非空非不空，空中真色不玲瓏。',32,'全唐诗/poet.tang.46000.json','["非色非空非不空，空中真色不玲瓏。", "可憐盧大擔柴者，拾得驪珠橐籥中。"]'),
('817d2135-66c1-49c6-87ee-e350e6309e6f','道情偈三首 三','貫休','唐','唐诗','tang','','[]','優鉢羅花萬劫春，頻犂田地絕纖塵。',32,'全唐诗/poet.tang.46000.json','["優鉢羅花萬劫春，頻犂田地絕纖塵。", "道吾道者相招好，不是香林採葉人。"]'),
('f7b5502a-a589-4039-b865-9284dd01a693','馬上作','貫休','唐','唐诗','tang','','[]','柳岸花堤夕照紅，風清襟袖轡璁瓏。',32,'全唐诗/poet.tang.46000.json','["柳岸花堤夕照紅，風清襟袖轡璁瓏。", "行人莫訝頻迴首，家在凝嵐一點中。"]'),
('5399642f-0c00-4bcd-96d7-8108ae7f9a0b','道中逢乞食老僧','貫休','唐','唐诗','tang','','[]','赤椶櫚笠眉毫垂，拄楖栗杖行遲遲。',32,'全唐诗/poet.tang.46000.json','["赤椶櫚笠眉毫垂，拄楖栗杖行遲遲。", "時人祗施盂中飯，心似白蓮那得知。"]'),
('c29e31f6-eb93-4bbf-a61b-9a192baf9ae0','秋末寄武昌一公','貫休','唐','唐诗','tang','','[]','見說武昌江上住，柏枯槐朽戰時風。',32,'全唐诗/poet.tang.46000.json','["見說武昌江上住，柏枯槐朽戰時風。", "知師詩癖難醫也，霜灑蘆花明月中。"]'),
('e5d91570-6811-4b44-9bcc-84fd8a3e3817','陋巷','貫休','唐','唐诗','tang','','[]','墜葉如花欲滿溝，破籬荒井一蟬幽。',32,'全唐诗/poet.tang.46000.json','["墜葉如花欲滿溝，破籬荒井一蟬幽。", "亦知希驥無希者，作麽令人強轉頭。"]'),
('eabbb105-ed66-40ed-8d2d-c1b4b9e14c49','終南僧','貫休','唐','唐诗','tang','','[]','聲利掀天竟不聞，草衣木食度朝昏。',32,'全唐诗/poet.tang.46000.json','["聲利掀天竟不聞，草衣木食度朝昏。", "遙思山雪深一丈，時有仙人來打門。"]'),
('ad89a50f-b5b7-4342-b3e7-609eb2687613','聽僧彈琴','貫休','唐','唐诗','tang','','[]','家近吳王古戰城，海風終日打牆聲。',32,'全唐诗/poet.tang.46000.json','["家近吳王古戰城，海風終日打牆聲。", "今朝鄉思渾堆積，琴上聞師大蟹行。"]'),
('0ad54d0c-1041-463d-8c8f-d3877fb1792f','漁者','貫休','唐','唐诗','tang','','[]','風惡波狂身似閑，滿頭霜雪背青山。',32,'全唐诗/poet.tang.46000.json','["風惡波狂身似閑，滿頭霜雪背青山。", "相逢略問家何在，回指蘆花滿舍間。"]'),
('b42bdc79-8105-4556-8ef6-fad6d1d7ac82','大蜀皇帝潛龍日述聖德詩五首 一','貫休','唐','唐诗','tang','','[]','嶽瀆殊祥日月精，入堯金鏡佐休明。',64,'全唐诗/poet.tang.46000.json','["嶽瀆殊祥日月精，入堯金鏡佐休明。", "衣嚴黻黼皇恩重，劒折芙蓉紫氣橫。", "玉甃金湯山岳峻，花藏臺榭管弦清。", "已聞圖上凌煙閣，寵渥穹窿玉不名。"]'),
('5ea2d1b3-cb59-4206-bc94-eb0ffa6f1377','大蜀皇帝潛龍日述聖德詩五首 二','貫休','唐','唐诗','tang','','[]','扶持社稷似齊桓，百萬雄師貴可觀。',64,'全唐诗/poet.tang.46000.json','["扶持社稷似齊桓，百萬雄師貴可觀。", "神智發中真莫測，貢輸天下學應難。", "風清鼙角□□□，□肅神龍草木寒。", "堪羨蜀民恆有福，太平時節一般般。"]'),
('2a901d11-ad9f-4c89-8677-c2423625f016','大蜀皇帝潛龍日述聖德詩五首 三','貫休','唐','唐诗','tang','','[]','珠履三千侍玉除，宮花飄錦早鶯初。',64,'全唐诗/poet.tang.46000.json','["珠履三千侍玉除，宮花飄錦早鶯初。", "雖然周孔心相似，其奈龔黃政不如。", "浩浩歌謠聞禁掖，重重襦袴滿樵漁。", "若論朝野艱難日，第一之功美有餘。"]'),
('b150e9a4-ca5e-49de-add0-95699f47b394','大蜀皇帝潛龍日述聖德詩五首 四','貫休','唐','唐诗','tang','','[]','紫髯青眼代天才，韓白孫吳稍可陪。',64,'全唐诗/poet.tang.46000.json','["紫髯青眼代天才，韓白孫吳稍可陪。", "祗見赤心堯日下，豈知真氣梵天來。", "聽經瑞雪時時落，登塔天花步步開。", "盡祝莊椿同壽考，人間歲月豈能催。"]'),
('c8a389cf-4094-41d4-ab89-0c4d5efa24b4','大蜀皇帝潛龍日述聖德詩五首 五','貫休','唐','唐诗','tang','','[]','丈夫勛業正乾坤，麟鳳龜龍盡在門。',64,'全唐诗/poet.tang.46000.json','["丈夫勛業正乾坤，麟鳳龜龍盡在門。", "西伯最憐耕讓畔，曹參空愛酒盈樽。", "心慈爲受金仙囑，髮白緣酬玉砌恩。", "從此于門轉高大，可憐子子與孫孫。"]'),
('1e4bb2c4-aa18-4a7e-8600-f459d9933dcf','陳情獻蜀皇帝','貫休','唐','唐诗','tang','','[]','河北江東處處災，唯聞全蜀勿塵埃。',64,'全唐诗/poet.tang.46000.json','["河北江東處處災，唯聞全蜀勿塵埃。", "一缾一鉢垂垂老，千水千山得得來。", "奈菀幽棲多勝景，巴歈陳貢媿非才。", "自慙林藪龍鍾者，亦得親登郭隗臺。"]'),
('2bcec78a-c7c4-4d02-ab9e-0afa04f290ed','壽春節進大蜀皇帝五首 一','貫休','唐','唐诗','tang','','[]','上玄大帝降坤維，箕尾爲臣副聖期。',64,'全唐诗/poet.tang.46000.json','["上玄大帝降坤維，箕尾爲臣副聖期。", "豈比赤光盈室日，全同白象下天時。", "文經武緯包三古，日角龍顏遏四夷。", "今日降神天上會，願將天福比須彌。"]'),
('fcf8b768-0c7a-42ad-9470-e1a5b10b55d7','壽春節進大蜀皇帝五首 二','貫休','唐','唐诗','tang','','[]','異香滴露降紛紛，紫電環樞照禁門。',64,'全唐诗/poet.tang.46000.json','["異香滴露降紛紛，紫電環樞照禁門。", "先冠百王臨億兆，後稱十號震乾坤。", "羲軒之道方爲道，草木沾恩始是恩。", "今以謏才歌睿德，猶如飲海妙難論。"]'),
('4288f550-33e5-4ae8-99aa-5db9976c067d','壽春節進大蜀皇帝五首 三','貫休','唐','唐诗','tang','','[]','茂祉遐宣勝事幷，薰風微入舜弦清。',64,'全唐诗/poet.tang.46000.json','["茂祉遐宣勝事幷，薰風微入舜弦清。", "四洲不必歸王化，一統那能計聖情。", "合合鼓鐘膏雨滴，峨峨宮闕瑞煙橫。", "西逾昆岳東連海，誰不梯山賀聖明。"]'),
('d6fb92d5-4635-447d-b8d9-91bec5b341d0','壽春節進大蜀皇帝五首 四','貫休','唐','唐诗','tang','','[]','遠人玉帛盡來歸，及物天慈物物肥。',64,'全唐诗/poet.tang.46000.json','["遠人玉帛盡來歸，及物天慈物物肥。", "春力遍時皆甲拆，王言聞者盡光輝。", "家家錦繡香醪熟，處處笙歌乳燕飛。", "爲報蜀皇勤禱祝，聖明天子古今稀。"]'),
('d21a3e31-5782-409b-aea0-4f978a64de1b','壽春節進大蜀皇帝五首 五','貫休','唐','唐诗','tang','','[]','積劫修來似煉金，爲皇爲帝萬靈欽。',64,'全唐诗/poet.tang.46000.json','["積劫修來似煉金，爲皇爲帝萬靈欽。", "能當濁世爲清世，始見君心是佛心。", "九野黎民耕浩浩，百蠻朝騎日駸駸。", "今朝獻壽將何比，願似莊椿一萬尋。"]'),
('f4bbb7b1-783a-4766-a175-baf5d41ae7bc','對雪寄新定馮使君二首 一','貫休','唐','唐诗','tang','','[]','仙掌空思歸未能，焚香冥目對殘燈。',64,'全唐诗/poet.tang.46000.json','["仙掌空思歸未能，焚香冥目對殘燈。", "豈知瑞雪千山合，空覺春寒半夜增。", "翳月素雲埋粉堞，堆巢孤鶴下金繩。", "因思太守憂民切，吟對瓊枝喜不勝。"]'),
('37ad7074-b7ac-4a3d-9e06-dbdb29b4fd40','對雪寄新定馮使君二首 二','貫休','唐','唐诗','tang','','[]','政化由來通上靈，豐年祥瑞滿窗明。',64,'全唐诗/poet.tang.46000.json','["政化由來通上靈，豐年祥瑞滿窗明。", "氣嚴坐久燈凝燄，片大更深屋作聲。", "飄掩煙霞何處去，欹斜杉竹向簾傾。", "雪林中客雖無事，還有新詩半夜成。"]'),
('d4cdbedc-53b2-48d8-ab71-3f428ee8728d','送劉相公朝覲二首 一','貫休','唐','唐诗','tang','','[]','九苞仙瑞曜垂衣，一品高標百辟師。',64,'全唐诗/poet.tang.46000.json','["九苞仙瑞曜垂衣，一品高標百辟師。", "魏相十思常自切，曹溪一句幾生知。", "久交玉帳雖難別，須佐金輪去已遲。", "唯杜荆州最惆悵，柳門迴首落花時。"]'),
('f734d6d5-611d-452a-a638-354e2555cbba','送劉相公朝覲二首 二','貫休','唐','唐诗','tang','','[]','急徵祗是再登庸，生意人心萬國同。',64,'全唐诗/poet.tang.46000.json','["急徵祗是再登庸，生意人心萬國同。", "燮理久徵殷傅說，譚真欲過李玄通。", "程穿峴首春光老，馬速商於曙色紅。", "從此龍顏又應瘦，寰瀛俱荷代天功。"]'),
('ba3bf248-f778-4836-8541-71389aed9d6a','避寇遊成福山院','貫休','唐','唐诗','tang','','[]','成福僧留不擬歸，獼猴菌嫩豆苗肌。',64,'全唐诗/poet.tang.46000.json','["成福僧留不擬歸，獼猴菌嫩豆苗肌。", "那堪蠶月偏多雨，況復衢城未解圍。", "翠擁槿籬泉亂入，雲開花島雉雙飛。", "堪嗟大似悠悠者，祗向詩中話息機。"]'),
('d85b30b5-a548-45c0-ae43-d0f1ed57cd45','別李常侍','貫休','唐','唐诗','tang','','[]','楚水和煙海浪通，又擎杯錫去山東。',64,'全唐诗/poet.tang.46000.json','["楚水和煙海浪通，又擎杯錫去山東。", "道情雖擬攀孤鶴，詩業那堪至遠公。", "夢入深雲香雨滴，吟搜殘雪石林空。", "朱門再到知何日，一片征帆萬里風。"]'),
('71ba0446-36d4-4537-ad19-1497eff98180','送鄭閣赴閩辟','貫休','唐','唐诗','tang','','[]','便便書腹德無鄰，健筆從知又入閩。',64,'全唐诗/poet.tang.46000.json','["便便書腹德無鄰，健筆從知又入閩。", "鸚鵡才須歸紫禁，真珠履不稱清貧。", "武夷山夾仙霞薄，螺女潭通海樹春。", "從此應多好消息，莫忘江上一閑人。"]'),
('604ec555-b453-4d51-ad01-dda96a0012ee','寄信州張使君','貫休','唐','唐诗','tang','','[]','水壇檉殿地含煙，領鶴行吟積翠間。',64,'全唐诗/poet.tang.46000.json','["水壇檉殿地含煙，領鶴行吟積翠間。", "數閣涼颸終日去，滿懷明月上方還。", "時來自有鵷鸞識，道在從如草木閑。", "唯羨靈溪賢太守，一麾清坐似深山。"]'),
('99af7127-342b-4ed6-a7e5-28037397cad2','春末寄周璉','貫休','唐','唐诗','tang','','[]','暮角[含]風雨氣曛，寂寥莓翠上衣巾。',66,'全唐诗/poet.tang.46000.json','["暮角[含]風雨氣曛，寂寥莓翠上衣巾。", "道情不向鶯花薄，詩意自如天地春。", "夢入亂峰仍履雪，吟看芳草祗思人。", "手中孤桂月中在，來聽泉聲莫厭頻。"]'),
('97bfe5b2-80fb-405a-b843-931d3bc7d632','讀吳越春秋','貫休','唐','唐诗','tang','','[]','猶來吳越盡須慙，背德違盟又信讒。',64,'全唐诗/poet.tang.46000.json','["猶來吳越盡須慙，背德違盟又信讒。", "宰嚭一言終殺伍，大夫七事祗須三。", "功成獻壽歌飄雪，誰愛扁舟水似藍。", "今日雄圖又何在，野花香徑鳥喃喃。"]'),
('552d7977-f7c8-4c32-9291-596c7f6190b1','春遊靈泉寺','貫休','唐','唐诗','tang','','[]','水蹴危梁翠擁沙，鐘聲微徑入深花。',64,'全唐诗/poet.tang.46000.json','["水蹴危梁翠擁沙，鐘聲微徑入深花。", "嘴紅澗鳥啼芳草，頭白山僧自扞茶。", "松色摧殘遭賊火，水聲幽咽落人家。", "因尋古跡空惆悵，滿袖香風白日斜。"]'),
('671383d6-8372-4465-9b59-ced99aad4d1a','歸東陽臨岐上杜使君七首 一','貫休','唐','唐诗','tang','','[]','小謝清高大謝才，聖君令泰此方來。',32,'全唐诗/poet.tang.46000.json','["小謝清高大謝才，聖君令泰此方來。", "一從到後常無事，鈴閣公庭滿綠苔。"]'),
('e1c2e8c9-08fa-4b1a-9348-f976a3f13bac','歸東陽臨岐上杜使君七首 二','貫休','唐','唐诗','tang','','[]','紅錦帳中歌白雪，烏皮几畔撫青英。',32,'全唐诗/poet.tang.46000.json','["紅錦帳中歌白雪，烏皮几畔撫青英。", "不知何物爲心地，賽却澄江徹底清。"]'),
('39590d50-ca69-4826-b31b-7021a509798b','歸東陽臨岐上杜使君七首 三','貫休','唐','唐诗','tang','','[]','誰報田中有黑蟲，一家齋戒減仙容。',32,'全唐诗/poet.tang.46000.json','["誰報田中有黑蟲，一家齋戒減仙容。", "分憂若也皆如此，天下家家有剩舂。"]'),
('9e3b7a62-8616-4d44-a738-a072f74fe6a9','歸東陽臨岐上杜使君七首 四','貫休','唐','唐诗','tang','','[]','憂民心切出衝炎，禾稼如雲喜氣兼。',32,'全唐诗/poet.tang.46000.json','["憂民心切出衝炎，禾稼如雲喜氣兼。", "林下閑人亦何幸，也隨旌斾到銀尖。"]'),
('9b687322-23b5-4f5f-8826-dd5766026a62','歸東陽臨岐上杜使君七首 五','貫休','唐','唐诗','tang','','[]','方恐獄中桃樹出，忽聞枯木却生煙。',32,'全唐诗/poet.tang.46000.json','["方恐獄中桃樹出，忽聞枯木却生煙。", "褚祥爲郡曾如此，却恐當時是偶然。"]'),
('a33bb62b-4f4d-499b-af98-c0747eae5db2','歸東陽臨岐上杜使君七首 六','貫休','唐','唐诗','tang','','[]','枯骨縱橫遍水湄，盡收爲冢碧參差。',32,'全唐诗/poet.tang.46000.json','["枯骨縱橫遍水湄，盡收爲冢碧參差。", "分明爲報精靈輩，好送旌旗到鳳池。"]'),
('c869dcf8-cf16-43a1-9e2d-e0f649463b5e','歸東陽臨岐上杜使君七首 七','貫休','唐','唐诗','tang','','[]','捨魯依劉一片雲，好風吹去遠纖塵。',32,'全唐诗/poet.tang.46000.json','["捨魯依劉一片雲，好風吹去遠纖塵。", "猶期明月清風夜，來作西園第八人。"]'),
('70eb6649-830c-491b-8286-304cf375d1e3','春','貫休','唐','唐诗','tang','','[]','自來自去動洪鑪，無象無私無處無。',64,'全唐诗/poet.tang.46000.json','["自來自去動洪鑪，無象無私無處無。", "迴鴈不多消氣力，染花應最費工夫。", "溟濛便恨豪家惜，濃暖深爲政筆驅。", "莫訝相逢只添睡，伊余心不在榮枯。"]'),
('e110c034-7bad-46d1-b838-25d0a4e57230','聞迎真身','貫休','唐','唐诗','tang','','[]','四海無波八表臣，恭聞今歲禮真身。',64,'全唐诗/poet.tang.46000.json','["四海無波八表臣，恭聞今歲禮真身。", "七重鏁未開今鑰，五色光先入紫宸。", "丹鳳樓臺飄瑞雪，岐陽草木亞香塵。", "可憐優鉢羅花樹，三十年來一度春。"]'),
('2fc31113-d522-415b-aac0-71743f16c0b2','灞陵戰叟','貫休','唐','唐诗','tang','','[]','劍刓秋水鬢梳霜，迴首胡天與恨長。',64,'全唐诗/poet.tang.46000.json','["劍刓秋水鬢梳霜，迴首胡天與恨長。", "官竟不封右校尉，鬬曾生挾左賢王。", "尋班超傳空垂淚，讀李陵書更斷腸。", "今日灞陵陵畔見，春風花霧共茫茫。"]'),
('c6acd38f-908a-455e-94ab-9c7a18999da6','遇道者','貫休','唐','唐诗','tang','','[]','鶴骨松筋風貌殊，不言名姓絕榮枯。',64,'全唐诗/poet.tang.46000.json','["鶴骨松筋風貌殊，不言名姓絕榮枯。", "尋常藜杖九衢裏，莫是商山一皓無。", "身帶煙霞游汗漫，藥兼神鬼在葫蘆。", "只應張果支公輩，時復相逢醉海隅。"]'),
('35753cf7-66ca-4520-98be-235ba949a922','贈鍾陵陳處士','貫休','唐','唐诗','tang','','[]','否極方生社稷才，唯譚帝道鄙梯媒。',64,'全唐诗/poet.tang.46000.json','["否極方生社稷才，唯譚帝道鄙梯媒。", "高吟千首精怪動，長嘯一聲天地開。", "湖上獨居多草木，山前頻醉過風雷。", "吾皇仄席求賢久，莫待徵書兩度來。"]'),
('3dc32f43-980e-48b2-84f5-27d4db2b3fb0','懷鄰叟','貫休','唐','唐诗','tang','','[]','常思東溪[龐]眉翁，是非不解兩頰紅。',66,'全唐诗/poet.tang.46000.json','["常思東溪[龐]眉翁，是非不解兩頰紅。", "桔橰打水聲嘎嘎，紫芋白薤肥濛濛。", "鷗鴨靜遊深竹裏，兒孫多在好花中。", "千門萬戶皆車馬，誰愛如斯太古風。"]'),
('f6363771-d1dc-446c-b97b-5065a5a05433','贈軒轅先生','貫休','唐','唐诗','tang','','[]','曾親文景上金鑾，語共容城語一般。',64,'全唐诗/poet.tang.46000.json','["曾親文景上金鑾，語共容城語一般。", "久向紅霞居不出，若非清世見應難。", "滿鑪藥熟分仙盡，幾局棊終看海乾。", "略問先生真甲子，只言弟子是劉安。"]'),
('43d1a1c6-5d39-4676-954c-afcd0e0f047e','偶作因懷山中道侶','貫休','唐','唐诗','tang','','[]','是是非非竟不真，桃花流水送青春。',64,'全唐诗/poet.tang.46000.json','["是是非非竟不真，桃花流水送青春。", "姓劉姓項今何在，爭利爭名愁殺人。", "必竟輸他常寂默，只應贏得苦沈淪。", "深雲道者相思否，歸去來兮湘水濱。"]'),
('757feaf5-4233-4d55-aa95-744d2a56c94b','送新羅人及第歸','貫休','唐','唐诗','tang','','[]','捧桂香和紫禁煙，遠鄉程徹巨鼇邊。',64,'全唐诗/poet.tang.46000.json','["捧桂香和紫禁煙，遠鄉程徹巨鼇邊。", "莫言挂席飛連夜，見說無風即數年。", "衣上日光真是火，島旁魚骨大於船。", "到鄉必遇來王使，與作唐書寄一篇。"]'),
('3d3f453c-6a9d-4c62-893d-da291b4c1e70','送新羅衲僧','貫休','唐','唐诗','tang','','[]','扶桑枝西真氣奇，古人呼爲師子兒。',64,'全唐诗/poet.tang.46000.json','["扶桑枝西真氣奇，古人呼爲師子兒。", "六環金錫輕擺撼，萬仞雪嶠空參差。", "枕上已無鄉國夢，囊中猶挈石頭碑。", "多慙不便隨高步，正是風清無事時。"]'),
('955e7f76-91e8-414d-9925-4eddaa09e2fb','春晚桐江上閑望作','貫休','唐','唐诗','tang','','[]','江上車聲落日催，紛紛擾擾起紅埃。',64,'全唐诗/poet.tang.46000.json','["江上車聲落日催，紛紛擾擾起紅埃。", "更無人望青山立，空有帆衝夜色來。", "沙鳥似雲鐘外去，汀花如火雨中開。", "可憐瀟灑鴟夷子，散髮扁舟去不迴。"]'),
('88bace35-b989-4721-bf37-255f8a673b40','商山道者','貫休','唐','唐诗','tang','','[]','五千言外得玄音，石屋寒栖隔雪林。',64,'全唐诗/poet.tang.46000.json','["五千言外得玄音，石屋寒栖隔雪林。", "多傍松風梳綠髮，只燒崖藥點黃金。", "澄潭龍氣來縈砌，月冷星精下聽琴。", "曾夢先生非此處，碧桃溪上紫煙深。"]'),
('e2f2ce6c-0e04-4bff-a56d-a32453c6da66','聞許棠及第因寄桂雍','貫休','唐','唐诗','tang','','[]','時清道合出塵埃，清苦爲詩不杖媒。',64,'全唐诗/poet.tang.46000.json','["時清道合出塵埃，清苦爲詩不杖媒。", "今日桂枝平折得，幾年春色併將來。", "勢扶九萬風初極，名到三山花正開。", "更有平人居蟄屋，還應爲作一聲雷。"]'),
('b8de2b80-8047-4533-94de-f08e493d446f','瀔江秋居作','貫休','唐','唐诗','tang','','[]','無事相關性自攄，庭前拾葉等閑書。',64,'全唐诗/poet.tang.46000.json','["無事相關性自攄，庭前拾葉等閑書。", "青山萬里竟不足，好竹數竿涼有餘。", "近看老經加澹泊，欲歸少室復何如。", "面前小沼清如鏡，終養琴高赤鯉魚。"]'),
('841762ef-596e-434e-9c6c-a6761073122a','上縉雲段使君','貫休','唐','唐诗','tang','','[]','清畏人知人盡知，縉雲三載得宣尼。',64,'全唐诗/poet.tang.46000.json','["清畏人知人盡知，縉雲三載得宣尼。", "活民刀尺雖無象，出世文章豈有師。", "朮氣芝香粘甕榼，雲痕翠點滿旌旗。", "今朝暫到金臺上，頗覺心如太古時。"]'),
('744fa8c8-bf75-46c1-9963-63d7e94ba1b8','春末蘭谿道中作','貫休','唐','唐诗','tang','','[]','山花零落紅與緋，汀煙濛茸江水肥。',64,'全唐诗/poet.tang.46000.json','["山花零落紅與緋，汀煙濛茸江水肥。", "人擔犂鋤細雨歇，路入桑柘斜陽微。", "深喜東州云寇去，不知西狩何時歸？", "清平時節何時是，轉覺人心與道違。"]'),
('c185ed02-a354-440e-a938-f3c04c9a5bd0','野居偶作','貫休','唐','唐诗','tang','','[]','高談清虛即是家，何須須占好煙霞。',64,'全唐诗/poet.tang.46000.json','["高談清虛即是家，何須須占好煙霞。", "無心於道道自得，有意向人人轉賒。", "風觸好花文錦落，砌橫流水玉琴斜。", "但令如此還如此，誰羨前程未可涯。"]'),
('0dcf75a4-3924-4eae-8185-dd2d0e7cfe83','再遊東林寺作五首 一','貫休','唐','唐诗','tang','','[]','臺殿參差聳瑞煙，桂花飄雪水潺潺。',32,'全唐诗/poet.tang.46000.json','["臺殿參差聳瑞煙，桂花飄雪水潺潺。", "莫疑遠去無消息，七萬餘年始半年。"]'),
('319369ae-aac6-4019-b076-3984878341e3','再遊東林寺作五首 二','貫休','唐','唐诗','tang','','[]','桓玄舊輦殘雲濕，耶舍孤墳落照遲。',32,'全唐诗/poet.tang.46000.json','["桓玄舊輦殘雲濕，耶舍孤墳落照遲。", "有箇山僧倚松睡，恐人來取白猨兒。"]'),
('98ebed5e-3909-4a64-908b-cea527a6fe27','再遊東林寺作五首 三','貫休','唐','唐诗','tang','','[]','玉像珠龕香陣橫，錦霞多傍石牆生。',32,'全唐诗/poet.tang.46000.json','["玉像珠龕香陣橫，錦霞多傍石牆生。", "辟蛇行者今何在，花裏唯聞鳩鳥聲。"]'),
('22a3843a-37d2-43f1-8555-2714c6b40684','再遊東林寺作五首 四','貫休','唐','唐诗','tang','','[]','愛陶長官醉兀兀，送陸道士行遲遲。',32,'全唐诗/poet.tang.46000.json','["愛陶長官醉兀兀，送陸道士行遲遲。", "買酒過溪皆破戒，斯何人斯師如斯。"]'),
('d43d699b-2166-40fb-8edb-a89ee8a57567','再遊東林寺作五首 五','貫休','唐','唐诗','tang','','[]','白薝蔔花露滴滴，紅苾芻草香濛濛。',32,'全唐诗/poet.tang.46000.json','["白薝蔔花露滴滴，紅苾芻草香濛濛。", "田地更無塵一點，是何人合住其中。"]'),
('83059f64-45b6-4c4d-aa5b-7bef179837d7','題蘭江言上人院二首 一','貫休','唐','唐诗','tang','','[]','一生只著一麻衣，道業還欺習彥威。',32,'全唐诗/poet.tang.46000.json','["一生只著一麻衣，道業還欺習彥威。", "手把新詩說山夢，石橋天柱雪霏霏。"]'),
('185a314c-a93c-4015-bdb4-2ec7df744c16','題蘭江言上人院二首 二','貫休','唐','唐诗','tang','','[]','只是危吟坐翠層，門前岐路自崩騰。',32,'全唐诗/poet.tang.46000.json','["只是危吟坐翠層，門前岐路自崩騰。", "青雲名士時相訪，茶煮西峰瀑布冰。"]'),
('51d18a79-0381-4cf6-9b51-c73b61b2bcc9','中秋十五夜月','貫休','唐','唐诗','tang','','[]','噀雪噴霜滿碧虛，王孫公子翫相呼。',64,'全唐诗/poet.tang.46000.json','["噀雪噴霜滿碧虛，王孫公子翫相呼。", "從來天匠爲輪足，自是人心此夜餘。", "靜入萬家危露滴，清埋衆象呌鴻孤。", "坐來惟覺情無極，何況三湘與五湖。"]'),
('9c0b41c1-26f3-4792-8b61-34b1d6a29f4b','鷺鷥有懷','貫休','唐','唐诗','tang','','[]','粉魄霜華爲爾枯，鴛鴦相伴更堪圖。',64,'全唐诗/poet.tang.46000.json','["粉魄霜華爲爾枯，鴛鴦相伴更堪圖。", "愛來沙島遺銀屋，終作金籠養雪雛。", "栖宿必多清瀨夢，品流還次白猨徒。", "今朝不覺頻回首，曾伴瑤花近玉壺。"]'),
('48cc69b5-d101-4406-85fc-6bc8635d19b1','東陽罹亂後懷王慥使君五首 一','貫休','唐','唐诗','tang','','[]','昨來祗對漢諸侯，勝事消磨不自由。',64,'全唐诗/poet.tang.46000.json','["昨來祗對漢諸侯，勝事消磨不自由。", "裂地鼓鼙軍□急，連天烽火陣雲秋。", "砍毛淬劍雖無數，歃血爲盟不到頭。", "誰爲今朝奉明主，使君司戶在隋州。"]'),
('c510d8ec-3628-4b20-8c48-7c1a81556a88','東陽罹亂後懷王慥使君五首 二','貫休','唐','唐诗','tang','','[]','只報精兵過大河，東西南北殺人多。',64,'全唐诗/poet.tang.46000.json','["只報精兵過大河，東西南北殺人多。", "可憐白日渾如此，來似蝗蟲爭奈何。", "天意豈應容版亂，人心都改太凋訛。", "不勝惆悵還惆悵，一曲東風月胯歌。"]'),
('38145034-fc16-41d1-9911-66ebc4e7e388','東陽罹亂後懷王慥使君五首 三','貫休','唐','唐诗','tang','','[]','爲郡無如王使君，一家清冷似雲根。',64,'全唐诗/poet.tang.46000.json','["爲郡無如王使君，一家清冷似雲根。", "貨財不入崔洪口，俎豆嘗聞夫子言。", "鬚髮坐成三載雪，黎氓空負二天恩。", "不堪西望西風起，縱火崑崙誰爲論。"]'),
('6f54379d-e75a-4c43-b5b9-ebeeff5321a7','東陽罹亂後懷王慥使君五首 四','貫休','唐','唐诗','tang','','[]','魄懾魂飛骨亦銷，此魂此魄亦難招。',64,'全唐诗/poet.tang.46000.json','["魄懾魂飛骨亦銷，此魂此魄亦難招。", "黃今白玉家家盡，繡闥雕甍處處燒。", "驚動乾坤常黯慘，深藏山岳亦傾搖。", "恭聞國有英雄將，擬把何心荅聖朝。"]'),
('ba5f771c-102b-4bb2-9cb5-5f5e69558390','東陽罹亂後懷王慥使君五首 五','貫休','唐','唐诗','tang','','[]','不是龔黃覆育才，即須清苦遠塵埃。',64,'全唐诗/poet.tang.46000.json','["不是龔黃覆育才，即須清苦遠塵埃。", "無人與奏吾皇去，致亂唯因酷吏來。", "刳剝生靈爲事業，巧通毫譖作梯媒。", "令人轉憶王夫子，一片真風去不迴。"]'),
('92382e59-eaa8-4f9c-b5b7-75790a1fe3a0','秋夜懷嵩少因寄洛中舊知','貫休','唐','唐诗','tang','','[]','鑪爇旃檀不稱貧，霏霏玉露濕禪巾。',64,'全唐诗/poet.tang.46000.json','["鑪爇旃檀不稱貧，霏霏玉露濕禪巾。", "紫金地上三更月，紅藕香中一病身。", "少室少年偏入夢，多時多事去無因。", "如今憔悴頭成雪，空想嵯峨羨故人。"]'),
('8ab56be7-54bf-4efe-a025-01a42ab67c64','避地毘陵寒月上孫徽使君兼寄東陽王使君三首 一','貫休','唐','唐诗','tang','','[]','一到毘陵心更勞，冷吟閑步擁雲袍。',64,'全唐诗/poet.tang.46000.json','["一到毘陵心更勞，冷吟閑步擁雲袍。", "豈緣思妙塵埃少，自是風清物態高。", "野色疎黃連楚甸，故山奇碧隔河橋。", "終須愚谷中安致，不是人間好羽毛。"]'),
('daec1866-f2ca-41f1-abf5-d23b024c1eab','避地毘陵寒月上孫徽使君兼寄東陽王使君三首 二','貫休','唐','唐诗','tang','','[]','常憶雙溪八詠前，講詩論道接清賢。',64,'全唐诗/poet.tang.46000.json','["常憶雙溪八詠前，講詩論道接清賢。", "文欺白鳳真難及，藥撚紅蕖豈偶然。", "花濕瑞煙粘玉磬，簾垂幽鳥啄苔錢。", "自憐不是悠悠者，吟嚼真風二十年。"]'),
('af51bc11-f7b7-401b-8136-c936d2180264','避地毘陵寒月上孫徽使君兼寄東陽王使君三首 三','貫休','唐','唐诗','tang','','[]','□雷車雨滴階聲，寂寞焚香獨閉扃。',64,'全唐诗/poet.tang.46000.json','["□雷車雨滴階聲，寂寞焚香獨閉扃。", "錦繡文章無路達，袴襦歌詠隔牆聽。", "松聲冷浸茶軒碧，苔點狂吞納線青。", "唯有孤高江太守，不忘病客在禪靈。"]'),
('ad76517b-cf80-42f1-8ead-bee4e6feda65','秋末寄上桐江馮使君','貫休','唐','唐诗','tang','','[]','山東山色勝諸山，謝守清高不可攀。',64,'全唐诗/poet.tang.46000.json','["山東山色勝諸山，謝守清高不可攀。", "薄俗盡于言下泰，苦心唯到醉中閑。", "香凝錦帳抄書後，月轉棠陰送客還。", "野客霑恩歸未得，蕭蕭霜葉滿柴關。"]'),
('f48698d0-cbf7-40cd-8f1f-7470b9e1e08d','禪師','貫休','唐','唐诗','tang','','[]','擊鼓求亡益是非，木中生火更何爲。',32,'全唐诗/poet.tang.46000.json','["擊鼓求亡益是非，木中生火更何爲。", "吾師別是醍醐昧，不是知心人不知。"]'),
('c203d62d-b1c5-40c1-bc15-c13ab2b9308a','道士','貫休','唐','唐诗','tang','','[]','花島相逢滿袖雲，藉花論道過金巾。',32,'全唐诗/poet.tang.46000.json','["花島相逢滿袖雲，藉花論道過金巾。", "騰騰又入仙山去，只恐是青城丈人。"]'),
('b0714809-e500-4946-821b-eb57b43c3006','風琴','貫休','唐','唐诗','tang','','[]','至境心爲造化功，一枝青竹四弦風。',32,'全唐诗/poet.tang.46000.json','["至境心爲造化功，一枝青竹四弦風。", "寥寥雙耳更深後，如在緱山明月中。"]'),
('651dcc84-03cf-4e51-b2cb-cecc0f3f51cc','庭橘','貫休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蟻踏金苞四五株，洞庭山上味何殊。',32,'全唐诗/poet.tang.46000.json','["蟻踏金苞四五株，洞庭山上味何殊。", "不緣松樹稱君子，肯便甘人喚木奴。"]'),
('9ceb9287-a08a-4b28-9efd-8144f3032cb6','落花','貫休','唐','唐诗','tang','','[]','蝶醉蜂癡一簇香，繡葩紅蔕墮殘芳。',32,'全唐诗/poet.tang.46000.json','["蝶醉蜂癡一簇香，繡葩紅蔕墮殘芳。", "因嗟好德人難得，公子王孫盡斷腸。"]'),
('f3f141a2-c586-44c2-a485-ea0c6f4a330d','孤雲','貫休','唐','唐诗','tang','','[]','將比鷺鷥還恐屈，始思殘雪不如多。',32,'全唐诗/poet.tang.46000.json','["將比鷺鷥還恐屈，始思殘雪不如多。", "清風相引去更遠，皎潔孤高奈爾何。"]'),
('57d7c976-9e10-477d-9e34-9bab3d6532e0','苦吟','貫休','唐','唐诗','tang','','[]','河薄星疎雪月孤，松枝清氣入肌膚。',32,'全唐诗/poet.tang.46000.json','["河薄星疎雪月孤，松枝清氣入肌膚。", "因知好句勝金玉，心極神勞特地無。"]'),
('4faef17f-ed0f-4954-80b7-0c16d7012965','古戰處','貫休','唐','唐诗','tang','','[]','鬼氣蒼黃棘葉紅，昔時人血此時風。',32,'全唐诗/poet.tang.46000.json','["鬼氣蒼黃棘葉紅，昔時人血此時風。", "相憐極目無疆地，曾落將軍一陣中。"]'),
('0593420f-6783-49a0-979f-f6f9fa4210a7','偶然作','貫休','唐','唐诗','tang','','[]','蟬聲引出石中蛩，寂寞門扃葉數重。',32,'全唐诗/poet.tang.46000.json','["蟬聲引出石中蛩，寂寞門扃葉數重。", "誰道思山心不切，等閑盡出兩三峰。"]'),
('abbb5449-dddd-4ec7-890d-d22180728505','招友人宿','貫休','唐','唐诗','tang','','[]','銀地無塵金菊開，紫梨紅棗墮莓苔。',32,'全唐诗/poet.tang.46000.json','["銀地無塵金菊開，紫梨紅棗墮莓苔。", "一泓秋水一輪月，今夜故人來不來。"]'),
('b39981e5-3d2a-4aed-9f01-a4e3dd28fc84','山居詩二十四首 一','貫休','唐','唐诗','tang','','[]','休話諠譁事事難，山翁只合住深山。',64,'全唐诗/poet.tang.46000.json','["休話諠譁事事難，山翁只合住深山。", "數聲清磬是非外，一箇閑人天地間。", "綠圃空階雲冉冉，異禽靈草水潺潺。", "無人與向羣儒說，巖桂枝高亦好扳。"]'),
('d2e57b57-2500-4e95-8375-e6c585c62ba5','山居詩二十四首 二','貫休','唐','唐诗','tang','','[]','難是言休即便休，清吟孤作碧溪頭。',64,'全唐诗/poet.tang.46000.json','["難是言休即便休，清吟孤作碧溪頭。", "三間茆屋無人到，十里松陰獨自遊。", "明月清風宗炳社，夕陽秋色庾公樓。", "修心未到無心地，萬種千般逐水流。"]'),
('a917cddc-8152-4b2c-b30f-e44d1ed449d6','山居詩二十四首 三','貫休','唐','唐诗','tang','','[]','好鳥聲長睡眼開，好茶擎乳坐莓苔。',64,'全唐诗/poet.tang.46000.json','["好鳥聲長睡眼開，好茶擎乳坐莓苔。", "不聞榮辱成番盡，只見熊羆作隊來。", "詩裏從前欺白雪，道情終遣似嬰孩。", "由來此事知音少，不是真風去不迴。"]'),
('5bb2b579-c51c-411f-be6a-199f45909911','山居詩二十四首 四','貫休','唐','唐诗','tang','','[]','萬境忘機是道華，碧芙蓉裏日空斜。',64,'全唐诗/poet.tang.46000.json','["萬境忘機是道華，碧芙蓉裏日空斜。", "幽深有徑通仙窟，寂寞無人落異花。", "掣電浮雲真好喻，如龍似鳳不須誇。", "君看江上英雄冢，只有松根與柏槎。"]'),
('e2764600-4f3e-492b-9625-8103910621e2','山居詩二十四首 五','貫休','唐','唐诗','tang','','[]','鞭後從他素髮兼，湧清奔碧冷侵簾。',64,'全唐诗/poet.tang.46000.json','["鞭後從他素髮兼，湧清奔碧冷侵簾。", "高奇章句無人愛，澹泊身心舉世嫌。", "白石橋高吟不足，紅霞影暖臥無厭。", "居山別有非山意，莫錯將予比宋纖。"]'),
('522f216f-0be5-40b7-b1d8-7030d5ced7d1','山居詩二十四首 六','貫休','唐','唐诗','tang','','[]','鳥外塵中四十秋，亦曾高挹漢諸侯。',64,'全唐诗/poet.tang.46000.json','["鳥外塵中四十秋，亦曾高挹漢諸侯。", "如斯標致雖清拙，大丈夫兒合自由。", "紫朮黃菁苗蕺蕺，錦囊香麝語啾啾。", "終須心到曹溪叟，千歲櫧根雪滿頭。"]'),
('ea7cee7e-95fa-43cd-81ff-72e3fac82df4','山居詩二十四首 七','貫休','唐','唐诗','tang','','[]','慵甚嵇康竟不迴，何妨方寸似寒灰。',64,'全唐诗/poet.tang.46000.json','["慵甚嵇康竟不迴，何妨方寸似寒灰。", "山精日作兒童出，仙者時將玉器來。", "筠帚埽花驚睡鹿，地壚燒樹帶枯苔。", "不行朝市多時也，許史金張安在哉。"]'),
('524102ae-bf44-4be2-ac4b-e9d877fe91a3','山居詩二十四首 八','貫休','唐','唐诗','tang','','[]','心心心不住希夷，石屋巉巖鬢髮垂。',64,'全唐诗/poet.tang.46000.json','["心心心不住希夷，石屋巉巖鬢髮垂。", "養竹不除當路筍，愛松留得礙人枝。", "焚香開卷霞生砌，捲箔冥心月在池。", "多少故人頭盡白，不知今日又何之。"]'),
('324eeb50-2980-430b-9e43-79cc55568963','山居詩二十四首 九','貫休','唐','唐诗','tang','','[]','龍藏琅函遍九垓，霜鍾金鼓振瓊臺。',64,'全唐诗/poet.tang.46000.json','["龍藏琅函遍九垓，霜鍾金鼓振瓊臺。", "堪嗟一句無人得，遂使吾師特地來。", "無角鐵牛眠少室，生兒石女老黃梅。", "令人轉憶龐居士，天上人間不可陪。"]'),
('89221d02-759e-4155-b38f-bc5c12483aaa','山居詩二十四首 十','貫休','唐','唐诗','tang','','[]','五嶽煙霞連不斷，三山洞穴去應通。',64,'全唐诗/poet.tang.46000.json','["五嶽煙霞連不斷，三山洞穴去應通。", "石窗欹枕疎疎雨，水碓無人浩浩風。", "童子念經深竹裏，獼猴拾蝨夕陽中。", "因思往事拋心力，六七年來楚水東。"]'),
('4e9cb47d-1e85-481c-9d2a-81b36eb2fd7b','山居詩二十四首 十一','貫休','唐','唐诗','tang','','[]','塵埃中更有埃塵，時復雙眉十爲顰。',64,'全唐诗/poet.tang.46000.json','["塵埃中更有埃塵，時復雙眉十爲顰。", "賴有年光飛似箭，是何心地亦稱人。", "回賢參孝時時說，蜂蠆狼貪日日新。", "天意剛容此徒在，不堪惆悵不堪陳。"]'),
('687ea415-b382-4fef-a2c4-e9eddf033aa4','山居詩二十四首 十二','貫休','唐','唐诗','tang','','[]','翠竇煙巖畫不成，桂華瀑沫雜芳馨。',64,'全唐诗/poet.tang.46000.json','["翠竇煙巖畫不成，桂華瀑沫雜芳馨。", "撥霞掃雪和雲母，掘石移松得茯苓。", "好鳥傍花窺玉磬，嫩苔和水沒金缾。", "從他人說從他笑，地覆天翻也只寧。"]'),
('6cc5f04b-8d45-4041-8336-68ef9105b6e5','山居詩二十四首 十三','貫休','唐','唐诗','tang','','[]','騰騰兀兀步遲遲，兆朕消磨只自知。',64,'全唐诗/poet.tang.46000.json','["騰騰兀兀步遲遲，兆朕消磨只自知。", "龍猛金膏雖未作，孫登土窟且相宜。", "薜蘿山帔偏能𫃷，橡栗年糧亦且支。", "已得真人好消息，人間天上更無疑。"]'),
('c05f6f71-75a8-4205-9696-638f053e1183','山居詩二十四首 十四','貫休','唐','唐诗','tang','','[]','嵐嫩風輕似碧紗，雪樓金像隔煙霞。',64,'全唐诗/poet.tang.46000.json','["嵐嫩風輕似碧紗，雪樓金像隔煙霞。", "葛苞玉粉生香壠，菌簇銀釘滿淨楂。", "舉世只知嗟逝水，無人微解悟空花。", "可憐擾擾塵埃裏，雙鬢如銀事似麻。"]'),
('d623364d-e154-411f-8f17-5588cfb18bab','山居詩二十四首 十五','貫休','唐','唐诗','tang','','[]','千巖萬壑路傾欹，杉檜濛濛獨掩扉。',64,'全唐诗/poet.tang.46000.json','["千巖萬壑路傾欹，杉檜濛濛獨掩扉。", "斸藥童穿溪𥕕去，採花蜂冒曉煙歸。", "閑行放意尋流水，靜坐支頤到落暉。", "長憶南泉好言語，如斯癡鈍者還稀。"]'),
('c7cd52e2-8188-4b4a-a1f4-10a431f24238','山居詩二十四首 十六','貫休','唐','唐诗','tang','','[]','一菴冥目在穹冥，菌枕松牀蘚陣青。',64,'全唐诗/poet.tang.46000.json','["一菴冥目在穹冥，菌枕松牀蘚陣青。", "乳鹿暗行檉徑雪，瀑泉微濺石樓經。", "閑行不覺過天井，長嘯深能動岳靈。", "應恐無人知此意，非凡非聖獨醒醒。"]'),
('649346a9-a04a-439c-bd99-3e77fa032007','山居詩二十四首 十七','貫休','唐','唐诗','tang','','[]','慵刻芙蓉傳永漏，休誇麗藻鄙湯休。',64,'全唐诗/poet.tang.46000.json','["慵刻芙蓉傳永漏，休誇麗藻鄙湯休。", "且爲小囤盛紅粟，別有珍禽勝白鷗。", "拾栗遠尋深澗底，弄猨多在小峯頭。", "不能更出塵中也，百煉剛爲繞指柔。"]'),
('0032e555-ef03-45c5-94c8-dcb4a81bfe09','山居詩二十四首 十八','貫休','唐','唐诗','tang','','[]','業薪心火日燒煎，浪死虛生自古然。',64,'全唐诗/poet.tang.46000.json','["業薪心火日燒煎，浪死虛生自古然。", "陸氏稱龍終妄矣，漢家得鹿更空焉。", "白衣居士深深說，青眼胡僧遠遠傳。", "剛地無人知此意，不堪惆悵落花前。"]'),
('56e8845b-da91-4de1-b849-633d568f10e7','山居詩二十四首 十九','貫休','唐','唐诗','tang','','[]','露滴紅蘭玉滿畦，閑拖象屣到峯西。',64,'全唐诗/poet.tang.46000.json','["露滴紅蘭玉滿畦，閑拖象屣到峯西。", "但令心似蓮花潔，何必身將槁木齊。", "古壍細煙紅樹老，半岩殘雪白猨啼。", "雖然不是桃源洞，春至桃花亦滿蹊。"]'),
('9542ad78-4178-4d89-beed-e844338927a0','山居詩二十四首 二十','貫休','唐','唐诗','tang','','[]','自休自已自安排，常願居山事偶諧。',64,'全唐诗/poet.tang.46000.json','["自休自已自安排，常願居山事偶諧。", "僧採樹衣臨絕壑，狖爭山果落空階。", "閑擔茶器緣青障，靜衲禪袍坐綠崖。", "虛作新詩反招隱，出來多與此心乖。"]'),
('2832230e-2df2-4911-aa1c-b938e552a97e','山居詩二十四首 二十一','貫休','唐','唐诗','tang','','[]','石罏金鼎紅蕖嫩，香閣茶棚綠巘齊。',64,'全唐诗/poet.tang.46000.json','["石罏金鼎紅蕖嫩，香閣茶棚綠巘齊。", "塢燒崩騰奔澗鼠，岩花狼籍鬬山雞。", "蒙莊環外知音少，阮籍途窮旨趣低。", "應有世人來覓我，水重山疊幾層迷。"]'),
('940bd761-57ad-458e-a1c3-efd9a61dd32b','山居詩二十四首 二十二','貫休','唐','唐诗','tang','','[]','自古浮華能幾幾，逝波終日去滔滔。',64,'全唐诗/poet.tang.46000.json','["自古浮華能幾幾，逝波終日去滔滔。", "漢王廢苑生秋草，吳主荒宮入夜濤。", "滿屋黃金機不息，一頭白髮氣猶高。", "豈知知足金仙子，霞外天香滿毳袍。"]'),
('d1139583-ba1f-4800-bb7b-8ce53c077dee','山居詩二十四首 二十三','貫休','唐','唐诗','tang','','[]','如愚何止直如弦，只合深藏碧嶂前。',64,'全唐诗/poet.tang.46000.json','["如愚何止直如弦，只合深藏碧嶂前。", "但見山中常有雪，不知世上是何年。", "野人愛向菴前笑，赤玃頻來袖畔眠。", "只有逍遙好知己，何須更問洞中天。"]'),
('07aa0959-baeb-4482-a39d-1673882accea','山居詩二十四首 二十四','貫休','唐','唐诗','tang','','[]','支公放鶴情相似，范泰論交趣不同。',64,'全唐诗/poet.tang.46000.json','["支公放鶴情相似，范泰論交趣不同。", "有念盡爲煩惱相，無私方稱水晶宮。", "香焚薝蔔諸峯曉，珠掐金剛萬境空。", "若買山資言不及，恆河沙劫用無窮。"]'),
('d0bdb9ce-ff21-40e6-beb9-8d91dd99b65c','再逢虛中道士三首 一','貫休','唐','唐诗','tang','','[]','天目西峯古壞壇，壇邊相別雪漫漫。',32,'全唐诗/poet.tang.46000.json','["天目西峯古壞壇，壇邊相別雪漫漫。", "如今四十餘年也，還共當時恰一般。"]'),
('9d21f30c-04c2-466e-acc1-128ee5af716c','再逢虛中道士三首 二','貫休','唐','唐诗','tang','','[]','囊裏靈龜小似錢，道伊年與我同年。',32,'全唐诗/poet.tang.46000.json','["囊裏靈龜小似錢，道伊年與我同年。", "壺中長挈天相逐，何處昇天更有天。"]'),
('e3789544-e970-496b-b085-a1f979da7f80','再逢虛中道士三首 三','貫休','唐','唐诗','tang','','[]','吾道將君道且殊，君鬚全似老君鬚。',32,'全唐诗/poet.tang.46000.json','["吾道將君道且殊，君鬚全似老君鬚。", "尋常有語爭堪信，愛說蟠桃似甕麤。"]'),
('315e3e1e-5cff-4764-b34e-88b989b60706','上盧使君二首 一','貫休','唐','唐诗','tang','','[]','一領彤弓下赤墀，惟將清淨作藩籬。',64,'全唐诗/poet.tang.46000.json','["一領彤弓下赤墀，惟將清淨作藩籬。", "馬卿山岳金相似，張緒風情柳不如。", "心染煙霞新句出，筆驅奸蠹宿根隳。", "鄱陽黎庶還堪羨，頭有重天足有氂。"]'),
('cbd411ee-7154-4fb9-b6bf-4a4cb03b00db','上盧使君二首 二','貫休','唐','唐诗','tang','','[]','司馬遷文亞聖人，三頭九陌碾香塵。',64,'全唐诗/poet.tang.46000.json','["司馬遷文亞聖人，三頭九陌碾香塵。", "盡傳棣萼麟兼鳳，終作昌朝甫與申。", "樓聳嬌歌疎雨過，風含和氣滿城春。", "因知寰海昇平去，又見高宗夢裏人。"]'),
('8fec40be-623a-4f2c-960f-7ca2976265e8','陪馮使君遊六首 登干霄亭','貫休','唐','唐诗','tang','','[]','擁翠捫蘿山屐輕，飄颻紅斾在青冥。',64,'全唐诗/poet.tang.46000.json','["擁翠捫蘿山屐輕，飄颻紅斾在青冥。", "仙科朱紱言非貴，溪鳥林泉癖愛聽。", "古桂林邊棊局濕，白雲堆裏茗煙青。", "因思廬岳彌天客，手把金書倚石屏。"]'),
('364e597c-adf1-41f5-aa10-f3a8249b1c82','陪馮使君遊六首 遊靈泉院','貫休','唐','唐诗','tang','','[]','珂珮喧喧滿路岐，亂泉聲裏扣禪扉。',64,'全唐诗/poet.tang.46000.json','["珂珮喧喧滿路岐，亂泉聲裏扣禪扉。", "對花語合希夷境，坐石苔黏黻黼衣。", "鳥啄古杉雲冉冉，風吹清磬露霏霏。", "惠巖亦有孤峯在，只戀繙經未得歸。"]'),
('3e19ff8f-b0c8-4b67-8cf7-adcfea1770ed','陪馮使君遊六首 過相思嶺','貫休','唐','唐诗','tang','','[]','譽自馨香道自怡，相思嶺上却無機。',64,'全唐诗/poet.tang.46000.json','["譽自馨香道自怡，相思嶺上却無機。", "荒蕖葉覆深霞在，片石人吟一鳥飛。", "何處風砧傳古曲，誰家冢樹挂斜暉。", "因思往事真堪笑，鶴背漁竿未是歸。"]'),
('e0807c5b-ae76-4dba-9b13-a10bf22234ff','陪馮使君遊六首 錦沙墩','貫休','唐','唐诗','tang','','[]','臨水登山興自奇，錦沙墩上最多時。',64,'全唐诗/poet.tang.46000.json','["臨水登山興自奇，錦沙墩上最多時。", "雖云髮白孤峯好，其奈名清聖主知。", "草媚蓮塘資逸步，雲生松壑有新詩。", "翛然別是神仙趣，豈羨東山妓樂隨。"]'),
('fc173248-bc42-4c25-9a2b-ccf0fc0e24f9','陪馮使君遊六首 釣罾潭','貫休','唐','唐诗','tang','','[]','境靜江清無事時，紅旌畫鷁動漁磯。',64,'全唐诗/poet.tang.46000.json','["境靜江清無事時，紅旌畫鷁動漁磯。", "心期只是行春去，日暮還應待鶴歸。", "風破綺霞山寺出，人歌白雪島花飛。", "自憐亦在仙舟上，玉浪翻翻濺草衣。"]'),
('4bbe4e98-ee3e-4e1f-a428-a4e2ccbddf78','陪馮使君遊六首 迎仙閣','貫休','唐','唐诗','tang','','[]','澗香霞影遶樓臺，捲箔凭闌耳目開。',64,'全唐诗/poet.tang.46000.json','["澗香霞影遶樓臺，捲箔凭闌耳目開。", "況從旌旗近鸞鳳，可憐談笑出塵埃。", "火雲不入長松徑，露茗何須白玉杯。", "誰道迎仙仙不至，今朝還有謝公來。"]'),
('2409a641-89b0-4bc7-b055-f44ec862d0b7','賀雨上王使君二首 一','貫休','唐','唐诗','tang','','[]','一片丹心合萬靈，應時甘雨帶龍腥。',64,'全唐诗/poet.tang.46000.json','["一片丹心合萬靈，應時甘雨帶龍腥。", "驅塵煞燒連窮□，□電衝霓滿窅冥。", "處處已知倉廩溢，家家皆歇管弦聽。", "應須蚤勒南山石，黃霸清風滿內庭。"]'),
('91ca652b-c1af-4896-9f42-6715bb6ad7d0','賀雨上王使君二首 二','貫休','唐','唐诗','tang','','[]','由來天贊德唯馨，朋禱心期事盡行。',64,'全唐诗/poet.tang.46000.json','["由來天贊德唯馨，朋禱心期事盡行。", "玄妙久聞談佛母，感通今日見神明。", "破除秋熱飄蕭盡，還似春時散漫傾。", "他日爲霖亦如此，諸生無不沐經營。"]'),
('abd241df-4d58-4f19-ac44-67a32fb03e5a','感懷寄盧給事二首 一','貫休','唐','唐诗','tang','','[]','緜緜遠念近來多，喜鵲隨函到綠蘿。',64,'全唐诗/poet.tang.46000.json','["緜緜遠念近來多，喜鵲隨函到綠蘿。", "雖匪二賢曾入洛，忽驚六義減沈疴。", "童扳鄰杏隳牆瓦，燕啄花泥落砌莎。", "好更因人寄消息，沃州歸去已蹉跎。"]'),
('3053742a-97b1-4121-950b-5e65420c0091','感懷寄盧給事二首 二','貫休','唐','唐诗','tang','','[]','常憶團圓繡像前，東歸經亂獨生全。',64,'全唐诗/poet.tang.46000.json','["常憶團圓繡像前，東歸經亂獨生全。", "孤峯已住六七處，萬事無成三十年。", "每想苑牆危逼路，更思鉢塔曉凌煙。", "如今憔悴荆枝盡，一諷來書一愴然。"]'),
('e282b6db-9dff-4f40-bd98-0b97d81fdfad','賀鄭使君','貫休','唐','唐诗','tang','','[]','三衢蜂蠆陷城池，八詠龍韜整武貔。',320,'全唐诗/poet.tang.46000.json','["三衢蜂蠆陷城池，八詠龍韜整武貔。", "纔諭危亡書半幅，便思父母淚雙垂。", "戈收甲束投仁境，汗浹魂飄拜虎旗。", "死地再生知德重，精兵連譀覺山移。", "人和美叶禎祥出，陣善深爲典教推。", "仗信輸誠方始是，執俘折馘欲何爲。", "清威嚴令無纖𡏖，長路深山不拾遺。", "七邑恩波歌浩渺，一方雲物自鮮奇。", "天文仰視同諸掌，劒術無前更數誰。", "戰馬閑眠汀草遠，秋鼙乾揭岳霞隳。", "義爲土地精靈伏，仁作金湯鐵石卑。", "龔遂劉寬同煦嫗，張飛關羽太驅馳。", "笙歌席上偏憐客，刀劒林中亦念詩。", "縠渚美爲長飲水，金山高作受降碑。", "時猶草草秋方盡，陳是堂堂孰敢窺。", "寵渥豈唯分節鉞，勳庸須勒上鍾彝。", "神資天贊誰堪比，名遂功成自不知。", "捲箔倚闌雲欲雪，擁罏傾榼酒如飴。", "扶堯社稷常憂老，到郭汾陽亦未遲。", "釋子沾恩無以報，只將葑菲賀階墀。"]'),
('2823dfe3-4a12-47f1-bcc4-d295a66e0c4b','送鄭使君','貫休','唐','唐诗','tang','','[]','刺婺廉閩動帝臺，唯將清淨作梯媒。',192,'全唐诗/poet.tang.46000.json','["刺婺廉閩動帝臺，唯將清淨作梯媒。", "綠沈槍卓妖星落，白玉壺澄苦霧開。", "仁愛久懸溪上月，恩光又發領頭梅。", "天資劉邵龔黃筆，神助韓彭衛霍才。", "古驛劒江分掩映，畫旗花舫下喧豗。", "鳳麟帟幕芙蓉坼，洞壑清威霹靂來。", "禮樂封疆添禮樂，塵埃時節勿塵埃。", "荔支花下驅千騎，薝葡林中禮萬迴。", "視事蠻奴磨玉硯，邀賓海月射金杯。", "謳歌合合千門樂，鼙角雄雄一閣雷。", "君父恩深頭早白，子孫榮襲日難陪。", "東陽緇素如何好，空向生祠祝上台。"]'),
('96876542-ffa7-4bfa-8eab-aaa2f6aa4ca1','贈楊公杜之舅','貫休','唐','唐诗','tang','','[]','分盡君憂一不遺，鳳書徵入萬民悲。',208,'全唐诗/poet.tang.46000.json','["分盡君憂一不遺，鳳書徵入萬民悲。", "風雲終日如相逐，雨露前程即可知。", "畫舸還盛江革石，秋山又看謝安棊。", "談諧盡是經邦術，頭角由來出世姿。", "天地事須歸橐籥，文章誰得到罘罳。", "扣舷傍島清吟健，問俗看漁晚泊遲。", "霞影滿江搖枕簟，鳥行和月下漣漪。", "周秦漢魏書書在，麟鳳龜龍步步隨。", "金殿恩波將浩浩，圭峯意緒謾孜孜。", "郡中條令春常在，境外謌謠美更奇。", "道者藥罏留要妙，林僧禪偈寄相思。", "王楊盧駱真何者，房杜蕭張更是誰。", "應念衢民千萬戶，家家皆置一生祠。"]'),
('36ccc72c-ccaa-4cea-9113-6766fabc8094','遊金華山禪院','貫休','唐','唐诗','tang','','[]','茲地曾棲菩薩僧，旃檀樓殿瀑崩騰。',64,'全唐诗/poet.tang.46000.json','["茲地曾棲菩薩僧，旃檀樓殿瀑崩騰。", "因知境勝終難到，問著人來悉不曾。", "斜谷暗藏千載雪，薄嵐常翳一龕燈。", "多慙不及當時海，又下嵯峨一萬層。"]'),
('e7831490-30bc-4ca7-a01a-18c32f92c280','寄鄭道士二首 一','貫休','唐','唐诗','tang','','[]','常憶蘇耽好羽儀，信安山觀住多時。',32,'全唐诗/poet.tang.46000.json','["常憶蘇耽好羽儀，信安山觀住多時。", "不知玉質雙棲處，兩箇仙人是阿誰。"]'),
('daaf0474-5d00-4df4-afac-9620183b3215','寄鄭道士二首 二','貫休','唐','唐诗','tang','','[]','誰帶金輪髻裏珠，何妨相逐去清都。',32,'全唐诗/poet.tang.46000.json','["誰帶金輪髻裏珠，何妨相逐去清都。", "舊山大有閑田地，五色香茆有子無。"]'),
('13b1b26e-21d7-47a4-a90a-1c050ce5f705','送少年禪師二首 一','貫休','唐','唐诗','tang','','[]','秀眉青目樹花衣，一鉢隨緣智不知。',32,'全唐诗/poet.tang.46000.json','["秀眉青目樹花衣，一鉢隨緣智不知。", "佛與輪王嫌不作，世間剛有箇癡兒。"]'),
('4568800d-6951-4c00-a1fc-98a9c28f4c5d','送少年禪師二首 二','貫休','唐','唐诗','tang','','[]','萬水千山一鶴飛，豈愁遊子暮何之。',32,'全唐诗/poet.tang.46000.json','["萬水千山一鶴飛，豈愁遊子暮何之。", "古今此著無人會，王積新輸更不疑。"]'),
('4b249508-0611-4674-86bb-7ea073dabd98','古劒池','貫休','唐','唐诗','tang','','[]','秋水蓮花三四枝，我來慷慨步遲遲。',32,'全唐诗/poet.tang.46000.json','["秋水蓮花三四枝，我來慷慨步遲遲。", "不決浮雲斬邪佞，真成龍去擬何爲。"]'),
('bead3a53-0606-4b5e-827a-35daa5f40fa8','曹娥碑','貫休','唐','唐诗','tang','','[]','高碑說爾孝應難，彈指端思白浪間。',32,'全唐诗/poet.tang.46000.json','["高碑說爾孝應難，彈指端思白浪間。", "堪歎行人不迴首，前山應是苧蘿山。"]'),
('a1fcc4c3-a0c9-41f5-bb28-889e9ab1aa29','比干傳','貫休','唐','唐诗','tang','','[]','昏王亡國豈堪陳，只見明誠不見身。',32,'全唐诗/poet.tang.46000.json','["昏王亡國豈堪陳，只見明誠不見身。", "想得先生也知自，欲將留與後來人。"]'),
('c9474027-c994-4c16-a569-e1ecbcea2769','送人遊茆山','貫休','唐','唐诗','tang','','[]','鳥啼花笑煖紛紛，路入青雲白石門。',32,'全唐诗/poet.tang.46000.json','["鳥啼花笑煖紛紛，路入青雲白石門。", "君到前頭好看好，老僧或恐是茆君。"]'),
('b67d1517-f383-45b5-bfe4-3867ef9d26b4','聞杜宇','貫休','唐','唐诗','tang','','[]','咽雨哀風更不停，春光於爾豈無情。',32,'全唐诗/poet.tang.46000.json','["咽雨哀風更不停，春光於爾豈無情。", "宜須喚得謝豹出，方始年年無此聲。"]'),
('2eefe0f8-ef53-45d1-9bf4-43935fd784f9','聽曉角','貫休','唐','唐诗','tang','','[]','三會單于滿閣風，五行無忒月朦朧。',32,'全唐诗/poet.tang.46000.json','["三會單于滿閣風，五行無忒月朦朧。", "如何十萬家休戚，只在嗚嗚咽咽中。"]'),
('d9aa6ac4-66cc-4d19-9a12-061b8580c342','宿赤松山觀題道人水閣兼寄郡守','貫休','唐','唐诗','tang','','[]','珠殿香軿倚翠稜，寒棲吾道寄孫登。',64,'全唐诗/poet.tang.46000.json','["珠殿香軿倚翠稜，寒棲吾道寄孫登。", "豈應肘後終無分，見說仙中亦有僧。", "雲斂石泉飛險竇，月明山鼠下枯藤。", "還如華頂清談夜，因有新詩寄鄭弘。"]'),
('bef28a93-ce6b-4710-859f-b00747c763a2','春遊涼泉寺','貫休','唐','唐诗','tang','','[]','一到涼泉未擬歸，迸珠噴玉落階[墀]。',66,'全唐诗/poet.tang.46000.json','["一到涼泉未擬歸，迸珠噴玉落階[墀]。", "幾多僧祗因泉在，無限松如潑墨爲。", "雲塹含香啼鳥細，茗甌擎乳落花遲。", "青山看著不可上，多病多慵爭奈伊。"]'),
('ff0a8bd0-7d58-4239-b835-867b5c0f235c','經吳宮','貫休','唐','唐诗','tang','','[]','夫差昏暗霸圖傾，千古淒涼地不靈。',64,'全唐诗/poet.tang.46000.json','["夫差昏暗霸圖傾，千古淒涼地不靈。", "妖豔恩餘宮露濁，忠臣心苦海山青。", "蕭條陵隴侵寒水，彷彿樓臺出杳冥。", "此是前車況非遠，六朝何更不惺惺。"]'),
('7c9ec1bf-b9a9-4f1b-a95e-e6990821b1d6','送薛侍郎貶峽州司馬','貫休','唐','唐诗','tang','','[]','得罪唯驚恩未酬，夷陵山誰稱閑遊。',64,'全唐诗/poet.tang.46000.json','["得罪唯驚恩未酬，夷陵山誰稱閑遊。", "人知八凱須當國，猨到三聲不用愁。", "花落扁舟香冉冉，草侵公署雨脩脩。", "因人好寄新詩好，不獨江東有沃州。"]'),
('d54aba44-4de7-4479-9938-44fe131616c1','將入匡山宿韓判官宅','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','一宿蘭堂接上才，白雲歸去幾裴回。',64,'全唐诗/poet.tang.46000.json','["一宿蘭堂接上才，白雲歸去幾裴回。", "黛青峯朵孤吟後，雪白猨兒必寄來。", "簾卷茶煙縈墮葉，月明棊子落深苔。", "明朝江上空迴首，始覺清風不可陪。"]'),
('d01b6b15-b0bd-437f-b3c5-90b87ff65d79','送鄭侍郎騫赴闕','貫休','唐','唐诗','tang','','[]','文章國器盡琅玕，朝騎駸駸歲欲殘。',64,'全唐诗/poet.tang.46000.json','["文章國器盡琅玕，朝騎駸駸歲欲殘。", "彩筆祗宜天上用，繡衣偏稱雪中看。", "休驚斷鴈離三楚，漸入祥煙下七槃。", "翰苑舊知憑與說，紫金輪畔寄書難。"]'),
('a350cc5e-3f0d-4a6a-b55e-113886e8fe32','上盧使君','貫休','唐','唐诗','tang','','[]','一別旌旗已一年，二林真子勸安禪。',64,'全唐诗/poet.tang.46000.json','["一別旌旗已一年，二林真子勸安禪。", "常思雙戟華堂裏，還似孤峯峭壁前。", "步出林泉多吉夢，帆侵分野入祥煙。", "自憐酷似隨陽鴈，霜打風飄到日邊。"]'),
('3c5033b1-2b3b-499e-8fcd-a0a86220d2e7','寄匡山大願和尚','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','一聽玄音下竹亭，却思窗雪與囊螢。',64,'全唐诗/poet.tang.46000.json','["一聽玄音下竹亭，却思窗雪與囊螢。", "祗將清淨酬恩德，敢信文章有性靈。", "夢歷山牀聞鶴語，吟思海月上沙汀。", "不堪迴首滄江上，萬仞廬峯在杳冥。"]'),
('cbff8bb7-1890-4df0-9e9c-ef9169544c04','別盧使君歸東陽二首 一','貫休','唐','唐诗','tang','','[]','雨氣濛濛草滿庭，式微吟劇更誰聽。',64,'全唐诗/poet.tang.46000.json','["雨氣濛濛草滿庭，式微吟劇更誰聽。", "詩逢匠化唯貪住，日覺恩深不易銘。", "心苦祗應消鬢黑，夢遊頻入倚天青。", "從茲還似歸回首，唯祝台星與福星。"]'),
('1ea3444e-8165-4907-9795-02e0f601fb28','別盧使君歸東陽二首 二','貫休','唐','唐诗','tang','','[]','家在嚴陵釣渚旁，細漣嘉樹拂窗涼。',64,'全唐诗/poet.tang.46000.json','["家在嚴陵釣渚旁，細漣嘉樹拂窗涼。", "難醫林藪煙霞癖，又出芝蘭父母鄉。", "孤帆好風千里煖，深花黃鳥一聲長。", "終期金鼎調羹日，再近尼丘日月光。"]'),
('4f58e728-9449-48f3-b276-a2b123235bf6','溪寺水閣閑眺因寄宋使君','貫休','唐','唐诗','tang','','[]','溪木蕭條一凭闌，玉霜飛後浪花寒。',64,'全唐诗/poet.tang.46000.json','["溪木蕭條一凭闌，玉霜飛後浪花寒。", "釣魚船上風煙暝，古木林中砧杵乾。", "至竟道心方始是，空耽山色亦無端。", "誰如太守分憂外，時把西經盡日看。"]'),
('1f7ba2c9-3692-4cb7-9814-804ba910666d','春送趙文觀送故合州座主神櫬歸洛','貫休','唐','唐诗','tang','','[]','喜繼于悲錦水東，還鄉仙騎却尋嵩。',66,'全唐诗/poet.tang.46000.json','["喜繼于悲錦水東，還鄉仙騎却尋嵩。", "再燒良玉堯雲動，方報深恩絳帳空。", "遠道靈[輀]春欲盡，亂山羸馬恨無窮。", "他年必立吾君側，好把書紳荅至公。"]'),
('ca1d5eb2-46e6-48a4-90b3-58e5e064e98d','{巩/言}光大師草書歌','貫休','唐','唐诗','tang','','[]','雪壓千峯橫枕上，窮困雖多還激壯。',160,'全唐诗/poet.tang.46000.json','["雪壓千峯橫枕上，窮困雖多還激壯。", "看師逸蹟兩相宜，高適歌行李白詩。", "海上驚驅山猛燒，吹斷狂煙著沙草。", "江樓曾見落星石，幾回試發將軍砲。", "別有寒雕掠絕壁，提上玄猨更生力。", "又見吳中磨角來，舞槊盤刀初觸擊。", "好文天子揮宸翰，御製本多推玉案。", "晨開水殿教題壁，題罷紫衣親寵錫。", "僧家愛詩自拘束，僧家愛畫亦局促。", "唯師草聖藝偏高，一掬山泉心便足。"]'),
('41002bdd-8178-4a0c-855a-04893a35a6ae','題成都玉局觀孫位畫龍','貫休','唐','唐诗','tang','','[]','我見蘇州崑山佛殿中，金城柱上有二龍。',72,'全唐诗/poet.tang.46000.json','["我見蘇州崑山佛殿中，金城柱上有二龍。", "老僧相傳道是僧繇手，尋常入海共龍鬬。", "又聞蜀國玉局觀有孫遇蹟，蟠屈身長八十尺。", "遊人爭看不敢近，頭覻寒泉萬丈碧。"]'),
('b0e33ac1-1d66-4f21-965d-6fd48693fee2','觀地獄圖','貫休','唐','唐诗','tang','','[]','峨峨非劒閣，有樹不堪攀。',48,'全唐诗/poet.tang.46000.json','["峨峨非劒閣，有樹不堪攀。", "佛手遮不得，人心似等閑。", "周王應未雪，白起作何顏。", "盡日空彈指，茫茫塵世間。"]'),
('d604def2-02ce-45b6-99c2-9f8f0e1a7651','贈雷卿張明府','貫休','唐','唐诗','tang','','[]','任官征戰後，度日寄閑身。',48,'全唐诗/poet.tang.46000.json','["任官征戰後，度日寄閑身。", "封卷還高客，飛書問野人。", "廢田教種穀，生路遣尋薪。", "若起柴桑興，無先漉酒巾。"]'),
('c39edcf7-7ab6-46a8-9bb0-ef3b5a628753','獻錢尚父','貫休','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','貴逼人來不自由，龍驤鳳翥勢難收。',64,'全唐诗/poet.tang.46000.json','["貴逼人來不自由，龍驤鳳翥勢難收。", "滿堂花醉三千客，一劒霜寒十四州。", "鼓角揭天嘉氣冷，風濤動地海山秋。", "東南永作金天柱，誰羨當時萬戶侯。"]'),
('c76f37f1-efad-4125-aa0a-a0da55b293ec','繡州張相公見訪','貫休','唐','唐诗','tang','','[]','德符唐德瑞通天，曾叱讒諛玉座前。',64,'全唐诗/poet.tang.46000.json','["德符唐德瑞通天，曾叱讒諛玉座前。", "千襲彩衣宮錦薄，數牀御札主恩偏。", "出師暫放張良箸，得罪惟撐范蠡船。", "未報君恩終必報，不妨金地禮青蓮。"]'),
('1206a6b8-5634-4094-81a7-32a0caf50a83','題某公宅','貫休','唐','唐诗','tang','','[]','宅成天下借圖看，始笑平生眼力慳。',64,'全唐诗/poet.tang.46000.json','["宅成天下借圖看，始笑平生眼力慳。", "地占百灣多是水，樓無一面不當山。", "荷深似入苕溪路，石怪疑行鴈蕩間。", "只恐中原方鼎沸，天心未遣主人閑。"]'),
('ca22768e-68f7-49f6-9d79-8510fbde9b7f','海覺禪師山院','貫休','唐','唐诗','tang','','[]','人言海覺老宗師，隱絕層巔世莫知。',64,'全唐诗/poet.tang.46000.json','["人言海覺老宗師，隱絕層巔世莫知。", "青草不生行道跡，白雲常護坐禪扉。", "六環金錫飛來後，一派銀河瀉落時。", "借問大心能濟物，龍門風雹捲天池。"]'),
('86db44bb-e795-46ea-93c8-1639f9d38bcb','悼張道古','貫休','唐','唐诗','tang','','[]','清河逝水大悤悤，東觀無人失至公。',64,'全唐诗/poet.tang.46000.json','["清河逝水大悤悤，東觀無人失至公。", "天上君恩三載隔，鑑中鸞影一時空。", "墳生苦霧蒼茫外，門掩寒雲寂寞中。", "惆悵斯人又如此，一聲蠻笛滿江風。"]'),
('b14b868b-a12f-40f7-a9f9-40d3b976e7e6','月夕','貫休','唐','唐诗','tang','','[]','霜月夜裴回，樓中羌笛催。',24,'全唐诗/poet.tang.46000.json','["霜月夜裴回，樓中羌笛催。", "曉風吹不盡，江上落殘梅。"]'),
('250caca0-1923-45da-af7c-b6e30bafe065','夜雨','貫休','唐','唐诗','tang','','[]','夜雨山草濕，爽籟雜枯木。',24,'全唐诗/poet.tang.46000.json','["夜雨山草濕，爽籟雜枯木。", "閑吟笁仙偈，清絕過于玉。"]'),
('84290a47-4e78-4463-a1a5-59124b398cd7','晚望','貫休','唐','唐诗','tang','','[]','落日碧江靜，蓮唱清且閑。',24,'全唐诗/poet.tang.46000.json','["落日碧江靜，蓮唱清且閑。", "更尋花發處，借月過前灣。"]'),
('841abb9e-9d47-4d1b-ab12-e12faaaedb60','早霜寄蔡大','貫休','唐','唐诗','tang','','[]','昨夜楚鐘鳴，飛霜下楚城。',24,'全唐诗/poet.tang.46000.json','["昨夜楚鐘鳴，飛霜下楚城。", "定知遷客鬢，先向鑑中生。"]'),
('34bd8a4d-e3b7-4da1-abbb-8fefa4256a05','贈寫經僧楚雲','貫休','唐','唐诗','tang','','[]','剔皮刺血誠何苦，爲寫靈山九會文。',32,'全唐诗/poet.tang.46000.json','["剔皮刺血誠何苦，爲寫靈山九會文。", "十指瀝乾終七軸，後來求法更無君。"]'),
('577c4ebf-a237-43c8-ace3-0f32a8418607','寄題詮律師院','貫休','唐','唐诗','tang','','[]','錦溪光裏聳樓臺，師院高凌積翠開。',64,'全唐诗/poet.tang.46000.json','["錦溪光裏聳樓臺，師院高凌積翠開。", "深竹杪聞殘磐盡，一茶中見數帆來。", "焚香只是看新律，幽步猶疑損綠苔。", "莫訝題詩又東去，石房清冷在天台。"]'),
('1ff4ac11-4a8f-4ad9-977e-d7deb6127bd1','寄天台葉道士','貫休','唐','唐诗','tang','','[]','負局高風不可陪，玉霄峯北置樓臺。',64,'全唐诗/poet.tang.46000.json','["負局高風不可陪，玉霄峯北置樓臺。", "注參同契未將出，尋楖栗僧多宿來。", "颼槭松風山棗落，閒關溪鳥朮花開。", "終須肘後相傳好，莫便乘鸞去不迴。"]'),
('4a502043-8347-4426-9f2f-d9ecce39a62e','送道友歸天台','貫休','唐','唐诗','tang','','[]','蘚濃苔濕冷層層，珍重先生獨去登。',64,'全唐诗/poet.tang.46000.json','["蘚濃苔濕冷層層，珍重先生獨去登。", "氣養三田傳未得，藥非八石許還曾。", "雲根應狎玉斧子，月逕多尋銀地僧。", "太守苦留終不住，可憐江上去騰騰。"]'),
('3b99d516-4282-45fd-9abd-5ebbdbe1e8df','陶種柑橙令山童買之','貫休','唐','唐诗','tang','','[]','高步南山南，高歌北山北。',24,'全唐诗/poet.tang.46000.json','["高步南山南，高歌北山北。", "數載買柑橙，山資近又足。"]'),
('0ae9b7d7-62ef-460a-a241-bdc13382c555','春送僧','貫休','唐','唐诗','tang','','["\u9001\u522b", "\u6625\u5929", "\u5199\u666f"]','蜀魄關關花雨深，送師衝雨到江潯。',32,'全唐诗/poet.tang.46000.json','["蜀魄關關花雨深，送師衝雨到江潯。", "不能更折江頭柳，自有青青松柏心。"]'),
('b9880c4d-e0a5-485c-8b1f-3c3553d38006','律師','貫休','唐','唐诗','tang','','[]','薝蔔花紅徑草青，雪膚冰骨步輕輕。',32,'全唐诗/poet.tang.46000.json','["薝蔔花紅徑草青，雪膚冰骨步輕輕。", "今朝暫到焚香處，只恐牀前有蝨聲。"]'),
('9e5d341d-73a5-4352-81b9-49dc9673e9b3','書石壁禪居屋壁','貫休','唐','唐诗','tang','','[]','赤旃檀塔六七級，白菡萏花三四枝。',32,'全唐诗/poet.tang.46000.json','["赤旃檀塔六七級，白菡萏花三四枝。", "禪客相逢只彈指，此心能有幾人知。"]'),
('82945f4b-9b24-4610-a96a-b61fb9bf0c4a','句','貫休','唐','唐诗','tang','','[]','今日再三難更識，讖辭唯道待錢來。',172,'全唐诗/poet.tang.46000.json','["今日再三難更識，讖辭唯道待錢來。", "鴈蕩經行雲漠漠，龍湫宴坐雨濛濛。", "刻成箏柱鴈相挨。", "黃昏風雨黑如磐，別我不知何處去。", "郭尚父休誇塞北，裴中令莫說淮西。", "萬計交人買，華軒保惜深。", "如何忠爲主，至竟不封侯。", "但看千騎去，知有幾人歸。", "一生不蓄買田錢，華屋何心亦偶然。", "客至多逢僧在坐，釣歸惟許鶴隨船。", "家爲買琴添舊價，廚因養鶴減晨炊。", "黏粉爲題棲鳳竹，帶香因洗落花泉。"]'),
('d56305d8-52ec-43b1-bb8f-d31eabfd0185','夏日草堂作','齊己','唐','唐诗','tang','','[]','沙泉帶草堂，紙帳卷空牀。',48,'全唐诗/poet.tang.46000.json','["沙泉帶草堂，紙帳卷空牀。", "靜是真消息，吟非俗肺腸。", "園林坐清影，梅杏嚼紅香。", "誰住原西寺，鐘聲送夕陽。"]'),
('bbc775ba-d10c-4bc5-80bd-44e37559a24d','寄鏡湖方干處士','齊己','唐','唐诗','tang','','[]','賀監舊山川，空來近百年。',48,'全唐诗/poet.tang.46000.json','["賀監舊山川，空來近百年。", "聞君與琴鶴，終日在漁船。", "島露深秋石，湖澄半夜天。", "雲門幾迴去，題徧好林泉。"]'),
('07ad9594-0b2f-4dbf-9e0a-15b78b3175c8','送人歸吳','齊己','唐','唐诗','tang','','[]','比說歸耕釣，迢迢向海涯。',48,'全唐诗/poet.tang.46000.json','["比說歸耕釣，迢迢向海涯。", "春寒游子路，村晚主人家。", "□□□□□，□山綠過茶。", "重尋舊鄰里，菱藕正開花。"]'),
('44dcf956-3bba-47c6-82e2-bbd2aa3dee77','贈仰上人','齊己','唐','唐诗','tang','','[]','避地依真境，安閒似舊溪。',48,'全唐诗/poet.tang.46000.json','["避地依真境，安閒似舊溪。", "干戈百里外，泉石亂峰西。", "草瑞香難歇，松靈蓋盡低。", "尋應報休馬，瓶錫向南攜。"]'),
('b56350fa-e151-41c0-95e0-255f150fce02','夜坐','齊己','唐','唐诗','tang','','[]','百蟲聲裏坐，夜色共冥冥。',48,'全唐诗/poet.tang.46000.json','["百蟲聲裏坐，夜色共冥冥。", "遠憶諸峰頂，曾栖此性靈。", "月華澄有象，詩思在無形。", "徹曙都忘寢，虛牕日照經。"]'),
('089af8ba-1989-4556-8c4a-bfad31509fee','新栽松','齊己','唐','唐诗','tang','','[]','野僧教種法，苒苒出蓬蒿。',48,'全唐诗/poet.tang.46000.json','["野僧教種法，苒苒出蓬蒿。", "百歲催人老，千年待爾高。", "靜宜兼竹石，幽合近猨猱。", "他日成陰後，秋風吹海濤。"]'),
('3437e6d0-4bc3-436e-a3bd-01819bd789dd','期友人','齊己','唐','唐诗','tang','','[]','早晚逐茲來，閑門日爲開。',48,'全唐诗/poet.tang.46000.json','["早晚逐茲來，閑門日爲開。", "亂蛩鳴白草，殘菊藉蒼苔。", "困臥誰驚起，閑行自欲迴。", "何時此攜手，吾子本多才。"]'),
('63a24942-856d-4cb0-8cff-9cf8ffd413be','和鄭谷郎中看棊','齊己','唐','唐诗','tang','','[]','箇是仙家事，何人合用心。',48,'全唐诗/poet.tang.46000.json','["箇是仙家事，何人合用心。", "幾時終一局，萬木老千岑。", "有路如飛出，無機似陸沈。", "樵夫可能解，也此廢光陰。"]'),
('fdc10952-f0bf-4d70-959a-34ae4379c98d','寄錢塘羅給事','齊己','唐','唐诗','tang','','[]','憤憤嘔讒書，無人誦子虛。',48,'全唐诗/poet.tang.46000.json','["憤憤嘔讒書，無人誦子虛。", "傷心天祐末，搔首懿宗初。", "海樹青叢短，湖山翠點疎。", "秋濤看足否，羅剎石邊居。"]'),
('93a1791f-1127-44f0-bad8-4f18ea9f999f','戊辰歲湘中寄鄭谷郎中','齊己','唐','唐诗','tang','','[]','白髮久慵簪，常聞病亦吟。',48,'全唐诗/poet.tang.46000.json','["白髮久慵簪，常聞病亦吟。", "瘦應成鶴骨，閑想似禪心。", "上國楊花亂，滄洲荻笋深。", "不堪思翠巘，西望獨沾襟。"]'),
('e619aaab-2603-43fc-a3a5-2e222a37abe0','寓言','齊己','唐','唐诗','tang','','[]','造化安能保，山川鑿欲翻。',48,'全唐诗/poet.tang.46000.json','["造化安能保，山川鑿欲翻。", "精華銷地底，珠玉聚侯門。", "始作驕奢本，終爲禍亂根。", "亡家與亡國，云此更何言。"]'),
('e187a5bb-1427-43ed-8813-02fe5f7528db','寄王振拾遺','齊己','唐','唐诗','tang','','[]','折檻意何如，平安信不虛。',48,'全唐诗/poet.tang.46000.json','["折檻意何如，平安信不虛。", "近來焚諫草，深去覓山居。", "□□□□□，□□□□餘。", "分明知在處，難寄亂離書。"]'),
('71f16b34-f83a-4089-8b40-68a5da849811','經賈島舊居','齊己','唐','唐诗','tang','','[]','先生居處所，野燒幾爲灰。',48,'全唐诗/poet.tang.46000.json','["先生居處所，野燒幾爲灰。", "若有吟魂在，應隨夜魄迴。", "地寧銷志氣，天忍罪清才。", "古木霜風晚，江禽共宿來。"]'),
('b6b781b8-b71c-466e-8110-000e9973f48e','送人游塞','齊己','唐','唐诗','tang','','["\u9001\u522b", "\u8fb9\u585e"]','槐柳野橋邊，行塵暗馬前。',48,'全唐诗/poet.tang.46000.json','["槐柳野橋邊，行塵暗馬前。", "秋風來漢地，客路入胡天。", "鴈聚河流濁，羊羣磧草膻。", "那堪隴頭宿，鄉夢逐潺湲。"]'),
('22293a4c-c4c3-4010-9948-a5c1ea760360','桃花','齊己','唐','唐诗','tang','','[]','千株含露態，何處照人紅？',48,'全唐诗/poet.tang.46000.json','["千株含露態，何處照人紅？", "風暖仙源裏，春和水國中。", "流鶯應見落，舞蜨未知空。", "擬欲求圖畫，枝枝帶竹叢。"]'),
('62a5d50e-5aa3-43b9-a7cb-4572d868c088','聞鴈','齊己','唐','唐诗','tang','','[]','何處人驚起，飛來過草堂。',48,'全唐诗/poet.tang.46000.json','["何處人驚起，飛來過草堂。", "丹心勞避弋，萬里念隨陽。", "影斷風天月，聲孤荻岸霜。", "明年趁春去，江上別鴛鴦。"]'),
('98e44f41-26bd-49f9-9e41-49910bf7953e','送人遊南','齊己','唐','唐诗','tang','','[]','南國多山水，君遊興可知。',48,'全唐诗/poet.tang.46000.json','["南國多山水，君遊興可知。", "船中江上景，晚泊早行時。", "子美遺魂地，藏真舊墨池。", "經過幾銷日，荒草裏尋碑。"]'),
('69f3b4c5-9dd4-4e45-aaab-98566f58d8f0','送益公歸舊居','齊己','唐','唐诗','tang','','[]','舊隱終牽夢，春殘結束歸。',48,'全唐诗/poet.tang.46000.json','["舊隱終牽夢，春殘結束歸。", "溪山無伴過，風雨有花飛。", "片石留題字，孤潭照浣衣。", "鄰僧喜相接，埽逕與開扉。"]'),
('2ec65acb-a2e6-4881-a6a3-41e47d8e4d95','不睡','齊己','唐','唐诗','tang','','[]','永夜不欲睡，虛堂閉復開。',48,'全唐诗/poet.tang.46000.json','["永夜不欲睡，虛堂閉復開。", "却離燈影去，待得月光來。", "落葉逢巢住，飛螢值我迴。", "天明拂經案，一炷白檀灰。"]'),
('0c5ac245-b8c6-4795-884b-5202a69f4395','新秋雨後','齊己','唐','唐诗','tang','','[]','夜雨洗河漢，詩懷覺有靈。',48,'全唐诗/poet.tang.46000.json','["夜雨洗河漢，詩懷覺有靈。", "籬聲新蟋蟀，草影老蜻蜓。", "靜引閑機發，涼吹遠思醒。", "逍遙向誰說，時注漆園經。"]'),
('387efba8-9b97-4768-95cb-f07d8280a5da','送劉蛻秀才赴舉','齊己','唐','唐诗','tang','','[]','百發百中□，□□□□年。',48,'全唐诗/poet.tang.46000.json','["百發百中□，□□□□年。", "丹枝如計分，一箭的無偏。", "文物兵銷國，關河雪霽天。", "都人看春牓，韓字在誰前。"]'),
('b8c4f85d-2248-4731-84ed-00a5a5cf804b','留題仰山大師塔院','齊己','唐','唐诗','tang','','[]','嵐光疊杳冥，曉翠濕窗明。',48,'全唐诗/poet.tang.46000.json','["嵐光疊杳冥，曉翠濕窗明。", "欲起遊方去，重來繞塔行。", "亂雲開鳥道，羣木發秋聲。", "曾約諸徒弟，香燈盡此生。"]'),
('652c3575-2ca8-4931-b0db-c4057eff07c8','亂中聞鄭谷吳延保下世','齊己','唐','唐诗','tang','','[]','小諫纔埋玉，星郎亦逝川。',48,'全唐诗/poet.tang.46000.json','["小諫纔埋玉，星郎亦逝川。", "國由多聚盜，天似不容賢。", "兵火焚詩草，江流漲墓田。", "長安已塗炭，追想更淒然。"]'),
('2011e0a5-5b95-4c21-9a43-97c243e169d2','送東林寺睦公往吳國','齊己','唐','唐诗','tang','','[]','八月江行好，風帆日夜飄。',48,'全唐诗/poet.tang.46000.json','["八月江行好，風帆日夜飄。", "煙霞經北固，禾黍過南朝。", "社客無宗炳，詩家有鮑昭。", "莫因賢相請，不返舊山椒。"]'),
('08296017-2fa9-4227-9fa5-850ad4db1833','除夜','齊己','唐','唐诗','tang','','[]','夜久誰同坐，爐寒鼎亦澄。',48,'全唐诗/poet.tang.46000.json','["夜久誰同坐，爐寒鼎亦澄。", "亂松飄雨雪，一室掩香燈。", "白髮添新歲，清吟減舊朋。", "明朝待晴旭，池上看春冰。"]'),
('121489aa-4a00-4dea-89eb-5516530db8dd','送祕上人','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','誰喜老閑身，春山起送君。',48,'全唐诗/poet.tang.46000.json','["誰喜老閑身，春山起送君。", "欲憑蓮社信，轉入洞庭雲。", "道路長無阻，干戈漸不聞。", "秋來向何處，相憶鴈成羣。"]'),
('0f2f7eda-d888-4c0d-9494-967e08ed3ea3','寓居嶽麓謝進士沈彬再訪','齊己','唐','唐诗','tang','','[]','去歲來尋我，留題在蘚痕。',48,'全唐诗/poet.tang.46000.json','["去歲來尋我，留題在蘚痕。", "又因風雪夜，重宿古松門。", "玉有疑休泣，詩無主且言。", "明朝此相送，披褐入桃源。"]'),
('c75267e1-beaa-44fb-81e8-98da18107f3a','對雪','齊己','唐','唐诗','tang','','[]','松門堆復積，埋石亦埋莎。',48,'全唐诗/poet.tang.46000.json','["松門堆復積，埋石亦埋莎。", "爲瑞還難得，居貧莫厭多。", "聽憐終夜落，吟惜一年過。", "誰在江樓望，漫漫墮綠波。"]'),
('eb0a53de-28f1-4e0e-8d99-ac257ff10ff2','和岷公送李評事往宜春','齊己','唐','唐诗','tang','','[]','兵火銷鄰境，龍沙有去人。',48,'全唐诗/poet.tang.46000.json','["兵火銷鄰境，龍沙有去人。", "江潭牽興遠，風物入題新。", "雪湛將殘臘，霞明向早春。", "郡侯開宴處，桃李照歌塵。"]'),
('cab60911-500a-49ec-9f37-1889b03ebdec','送僧','齊己','唐','唐诗','tang','','[]','老憶遊方日，天涯錫獨搖。',48,'全唐诗/poet.tang.46000.json','["老憶遊方日，天涯錫獨搖。", "凌晨從北固，衝雪向南朝。", "鬢髮泉邊剃，香燈樹下燒。", "雙峰諸道友，夏滿有書招。"]'),
('419b83aa-b19f-4f6e-bad8-e4a345b4c748','過荆門','齊己','唐','唐诗','tang','','[]','路出荆門遠，行行日欲西。',48,'全唐诗/poet.tang.46000.json','["路出荆門遠，行行日欲西。", "草枯蠻塚亂，山斷漢江低。", "野店叢蒿短，煙村簇樹齊。", "翻思故林去，在處有猨啼。"]'),
('4d8b285b-6ca2-4e35-ac95-5fbd66b6238c','山中荅人','齊己','唐','唐诗','tang','','[]','謾道詩名出，何曾著苦吟。',48,'全唐诗/poet.tang.46000.json','["謾道詩名出，何曾著苦吟。", "忽來還有意，已過即無心。", "夏月山長往，霜天寺獨尋。", "故人憐拙朴，時復寄空林。"]'),
('88c8ec99-8d0c-4c2e-8735-5f7651ab7072','贈盧明府閑居','齊己','唐','唐诗','tang','','[]','鬢霜垂七十，江國久辭官。',48,'全唐诗/poet.tang.46000.json','["鬢霜垂七十，江國久辭官。", "滿篋新風雅，何人舊歲寒。", "閑居當野水，幽鳥宿漁竿。", "終欲相尋去，兵戈時轉難。"]'),
('61447f61-c0d4-47c4-ac26-1644ba239fd5','幽庭','齊己','唐','唐诗','tang','','[]','不放生纖草，從教徧綠苔。',48,'全唐诗/poet.tang.46000.json','["不放生纖草，從教徧綠苔。", "還防長者至，未著牡丹栽。", "蛺蝶空飛過，鶺鴒時下來。", "南鄰折芳子，到此寂寥迴。"]'),
('a3262a25-fa6e-480c-b9e3-09e21358c1ba','送休師歸長沙寧覲','齊己','唐','唐诗','tang','','[]','吾子此歸寧，風煙是舊經。',48,'全唐诗/poet.tang.46000.json','["吾子此歸寧，風煙是舊經。", "無窮芳草色，何處故山青？", "偶泊鳴蟬島，難眠好月汀。", "殷勤問安外，湘岸採詩靈。"]'),
('07fd4fb1-ae0a-42e6-8d74-23a07217c46e','將遊嵩華行次荆渚','齊己','唐','唐诗','tang','','[]','蓮峰映敷水，嵩嶽壓伊河。',48,'全唐诗/poet.tang.46000.json','["蓮峰映敷水，嵩嶽壓伊河。", "兩處思歸久，前賢隱去多。", "閑身應絕跡，在世幸無他。", "會向紅霞嶠，僧龕對薜蘿。"]'),
('a21b4ce5-902b-4668-aa27-d28892a8aaa2','遠思','齊己','唐','唐诗','tang','','[]','遠思極何處，南樓煙水長。',48,'全唐诗/poet.tang.46000.json','["遠思極何處，南樓煙水長。", "秋風過鴻鴈，遊子在瀟湘。", "海面雲生白，天涯墮晚光。", "徘徊古堤上，曾此贈垂楊。"]'),
('2e270394-f4da-4491-b01a-213d4f2b57a1','寄勉二三子','齊己','唐','唐诗','tang','','[]','不見二三子，悠然吳楚間。',48,'全唐诗/poet.tang.46000.json','["不見二三子，悠然吳楚間。", "盡應生白髮，幾箇在青山。", "□□□□□，□□莫放閑。", "君聞國風否，千秋詠關關。"]'),
('3d52dbae-43b9-45c3-adf6-0254bdbc7f4d','渚宮江亭寓目','齊己','唐','唐诗','tang','','[]','津亭雖極望，未稱本心閑。',48,'全唐诗/poet.tang.46000.json','["津亭雖極望，未稱本心閑。", "白有三江水，青無一點山。", "新鴻喧夕浦，遠櫂聚空灣。", "終遂歸匡社，孤帆即此還。"]'),
('8b3b2817-a0d7-4afc-aa67-c88a6e8ead55','蝴蝶','齊己','唐','唐诗','tang','','[]','何處背繁紅，迷芳到檻重。',96,'全唐诗/poet.tang.46000.json','["何處背繁紅，迷芳到檻重。", "分飛還獨出，成隊偶相逢。", "遠害終防雀，爭先不避蜂。", "桃蹊牽往復，蘭徑引相從。", "翠裛丹心冷，香凝粉翅濃。", "可尋穿樹影，難覓宿花蹤。", "日晚來仍急，春殘舞未慵。", "西風舊池館，猶得採芙蓉。"]'),
('ba3d0f58-a3e6-4985-8f8c-415e07bc59c0','送劉秀才往東洛','齊己','唐','唐诗','tang','','[]','羨子去東周，行行非旅遊。',48,'全唐诗/poet.tang.46000.json','["羨子去東周，行行非旅遊。", "煙霄有兄弟，事業盡曹劉。", "洛水清奔夏，嵩雲白入秋。", "來年遂鵬化，一舉上瀛洲。"]'),
('8c141ef3-f5b2-4382-b66a-d2724528f618','移竹','齊己','唐','唐诗','tang','','[]','舊溪千萬竿，風雨夜珊珊。',48,'全唐诗/poet.tang.46000.json','["舊溪千萬竿，風雨夜珊珊。", "白首來江國，黃金買歲寒。", "乍移傷粉節，終遶著朱欄。", "會得承春力，新抽錦籜看。"]'),
('7891348a-8f0d-4d17-968c-78fa45a724ab','雉','齊己','唐','唐诗','tang','','[]','角角類關關，春晴錦羽乾。',48,'全唐诗/poet.tang.46000.json','["角角類關關，春晴錦羽乾。", "文呈五色異，瑞入九苞難。", "暮宿紅蘭暖，朝飛綠野寒。", "山梁從行者，錯解仲尼歎。"]'),
('f263415a-363d-4b13-8abb-72952bbbfb52','懷軒轅先生','齊己','唐','唐诗','tang','','[]','不得先生信，空懷汗漫秋。',48,'全唐诗/poet.tang.46000.json','["不得先生信，空懷汗漫秋。", "月華離鶴背，日影上鼇頭。", "欲學孤雲去，其如重骨留。", "槎程在何處，人世屢荒丘。"]'),
('50c91c7f-2ccd-44fa-939c-cb466c201378','永夜感懷寄鄭谷郎中','齊己','唐','唐诗','tang','','[]','展轉復展轉，所思安可論。',48,'全唐诗/poet.tang.46000.json','["展轉復展轉，所思安可論。", "夜涼難就枕，月好重開門。", "霜殺百草盡，蛩歸四壁根。", "生來苦章句，早遇至公言。"]'),
('07f88174-575a-4b67-b695-47ab2052791e','賣松者','齊己','唐','唐诗','tang','','[]','未得凌雲價，何慙所買真。',48,'全唐诗/poet.tang.46000.json','["未得凌雲價，何慙所買真。", "自知桃李世，有愛歲寒人。", "瑟瑟初離澗，青青未識塵。", "寧同買花者，貴逐片時春。"]'),
('e3fb6171-5605-4094-90d1-9be740851bf4','丙寅歲寄潘歸仁','齊己','唐','唐诗','tang','','[]','九土盡荒墟，干戈殺害餘。',48,'全唐诗/poet.tang.46000.json','["九土盡荒墟，干戈殺害餘。", "更須憂去國，未可守貧居。", "康泰終來在，編聯莫破除。", "他年遇知己，無恥報襜褕。"]'),
('eced4d25-e7f5-4fcc-b147-f015978e7844','嘗茶','齊己','唐','唐诗','tang','','[]','石屋晚煙生，松窗鐵碾聲。',48,'全唐诗/poet.tang.46000.json','["石屋晚煙生，松窗鐵碾聲。", "因留來客試，共說寄僧名。", "味擊詩魔亂，香搜睡思輕。", "春風霅川上，憶傍綠叢行。"]'),
('d662dbbb-8328-4253-83b9-fd5a5112e556','楊花','齊己','唐','唐诗','tang','','[]','暖景照悠悠，遮空勢漸稠。',144,'全唐诗/poet.tang.46000.json','["暖景照悠悠，遮空勢漸稠。", "乍如飛雪遠，未似落花休。", "萬帶都門外，千株渭水頭。", "紛紜知近夏，銷歇恐成秋。", "軟著朝簪去，狂隨別騎遊。", "斾衝離館驛，鶯撲繞宮樓。", "江國晴愁對，池塘晚見浮。", "虛窗縈筆雅，深院藉苔幽。", "靜墮王孫酒，繁黏客子裘。", "詠吟何潔白，根本屬風流。", "向日還輕舉，因風更自由。", "不堪思汴岸，千里到揚州。"]'),
('737cbc0b-05ce-43c2-bd8b-81672ec782f8','詠影','齊己','唐','唐诗','tang','','[]','萬物患有象，不能逃大明。',48,'全唐诗/poet.tang.46000.json','["萬物患有象，不能逃大明。", "始隨殘魄滅，又逐曉光生。", "曲直寧相隱，洪纖必自呈。", "還如至公世，洞鑒是非情。"]'),
('631c2be7-61c4-4114-9ea8-d9aaf7debc88','南歸舟中二首 一','齊己','唐','唐诗','tang','','[]','南歸乘客櫂，道路免崎嶇。',48,'全唐诗/poet.tang.46000.json','["南歸乘客櫂，道路免崎嶇。", "江上經時節，船中聽鷓鴣。", "春容含衆岫，雨氣泛平蕪。", "落日停舟望，王維未有圖。"]'),
('daaf6ed2-12c0-4fd7-ac88-9d33271666fb','南歸舟中二首 二','齊己','唐','唐诗','tang','','["\u957f\u6c5f"]','長江春氣寒，客況櫂聲閑。',48,'全唐诗/poet.tang.46000.json','["長江春氣寒，客況櫂聲閑。", "夜泊諸村雨，程迴數郡山。", "桑根垂斷岸，浪沫聚空灣。", "已去鄰園近，隨緣是暫還。"]'),
('7dbbe7b3-77bc-400c-b6aa-3b60281b1da9','送遷客','齊己','唐','唐诗','tang','','[]','天涯即愛州，謫去莫多愁。',48,'全唐诗/poet.tang.46000.json','["天涯即愛州，謫去莫多愁。", "若似承恩好，何如傍主休。", "瘴昏銅柱黑，草赤火山秋。", "應想堯陰下，當時獬豸頭。"]'),
('acfebc9f-3e72-4ff2-8ecb-f7945e84df2e','題中上人院','齊己','唐','唐诗','tang','','[]','高房占境幽，講退即冥搜。',48,'全唐诗/poet.tang.46000.json','["高房占境幽，講退即冥搜。", "欠鶴同支遁，多詩似惠休。", "缾澄孤井浪，案白小窗秋。", "莫道歸山字，朝賢日獻酬。"]'),
('5c6e3ced-47a1-49cb-aadd-39f08ad60e4a','逢鄉友','齊己','唐','唐诗','tang','','[]','無況來江島，逢君話滯留。',48,'全唐诗/poet.tang.46000.json','["無況來江島，逢君話滯留。", "生緣同一國，相識共他州。", "竹影斜青蘚，茶香在白甌。", "猶憐心道合，多事亦冥搜。"]'),
('500b7d8b-97ce-407e-a53f-4dde875fd4fb','自勉','齊己','唐','唐诗','tang','','[]','試筭平生事，中年欠五年。',48,'全唐诗/poet.tang.46000.json','["試筭平生事，中年欠五年。", "知非未落後，讀易尚加前。", "分受詩魔役，寧容俗態牽。", "閑吟見秋水，數隻釣魚船。"]'),
('41138879-7e8f-4d84-b81c-58dac438a9f5','寄詩友','齊己','唐','唐诗','tang','','[]','天地有萬物，盡應輸苦心。',48,'全唐诗/poet.tang.46000.json','["天地有萬物，盡應輸苦心。", "他人雖欲解，此道奈何深。", "返朴遺時態，關門度歲陰。", "相思去秋夕，共對冷燈吟。"]'),
('5a01f571-9285-4d69-b9c0-4079095aab72','居道林寺書懷','齊己','唐','唐诗','tang','','[]','花落水喧喧，端居信晝昏。',48,'全唐诗/poet.tang.46000.json','["花落水喧喧，端居信晝昏。", "誰來看山寺，自要埽松門。", "是事皆能諱，唯詩未嬾言。", "傳聞好時世，亦欲背啼猨。"]'),
('095bbae9-6326-4c3f-ad15-7e8a8b77177a','經吳平觀','齊己','唐','唐诗','tang','','[]','中元齋醮後，殘燼滿空壇。',48,'全唐诗/poet.tang.46000.json','["中元齋醮後，殘燼滿空壇。", "老鶴心何待，尊師鬢已乾。", "幡燈古殿夜，霜霰大椿寒。", "誰見長生路，人間事萬端。"]'),
('8ac8299d-72ec-4370-baf0-2626058066f5','劒客','齊己','唐','唐诗','tang','','["\u5bb4\u996e", "\u9001\u522b", "\u5199\u4eba"]','拔劒遶殘樽，歌終便出門。',48,'全唐诗/poet.tang.46000.json','["拔劒遶殘樽，歌終便出門。", "西風滿天雪，何處報人恩。", "勇死尋常事，輕讐不足論。", "翻嫌易水上，細碎動離魂。"]'),
('840831a9-a13c-4449-85c2-7fb9b1a7ec31','白髮','齊己','唐','唐诗','tang','','[]','莫染亦莫鑷，任從伊滿頭。',48,'全唐诗/poet.tang.46000.json','["莫染亦莫鑷，任從伊滿頭。", "白雖無耐藥，黑也不禁秋。", "靜枕聽蟬臥，閑垂看水流。", "浮生未達此，多爲爾爲愁。"]'),
('c61b4087-6df3-4f7b-9acf-9c908ef38b83','秋興寄胤公','齊己','唐','唐诗','tang','','[]','風聲吹竹健，涼氣著身輕。',48,'全唐诗/poet.tang.46000.json','["風聲吹竹健，涼氣著身輕。", "誰有閑心去，江邊看水行。", "村遙紅樹遠，野闊白煙平。", "試裂芭蕉片，題詩問竺卿。"]'),
('264a1f1d-f76b-4d14-a28d-a5d9b59e5cd7','野步','齊己','唐','唐诗','tang','','[]','城裏無閑處，却尋城外行。',48,'全唐诗/poet.tang.46000.json','["城裏無閑處，却尋城外行。", "田園經雨水，鄉國憶桑耕。", "傍澗蕨薇老，隔村岡隴橫。", "何窮此心興，時復鷓鴣聲。"]'),
('391d1b26-301e-481a-b98d-644efc8f499f','殘春','齊己','唐','唐诗','tang','','[]','三月看無也，芳時此可嗟。',48,'全唐诗/poet.tang.46000.json','["三月看無也，芳時此可嗟。", "園林欲向夕，風雨更吹花。", "影亂衝人蝶，聲繁遶塹蛙。", "那堪傍楊柳，飛絮滿鄰家。"]'),
('c23e4b45-c7f6-4d15-a223-d2f49605dfe1','酬尚顏','齊己','唐','唐诗','tang','','[]','取盡風騷妙，名高身倍閑。',48,'全唐诗/poet.tang.46000.json','["取盡風騷妙，名高身倍閑。", "久離王者闕，欲向祖師山。", "幕府秋招去，溪鄰日望還。", "伊余豈酬敵，來往踏苔斑。"]'),
('21000c47-63d8-4d83-b09a-86954a265e4c','苦熱','齊己','唐','唐诗','tang','','[]','雲勢嶮於峰，金流斷竹風。',48,'全唐诗/poet.tang.46000.json','["雲勢嶮於峰，金流斷竹風。", "萬方應望雨，片景欲焚空。", "毒害芙蓉死，煩蒸瀑布紅。", "恩多是團扇，出入畫屏中。"]'),
('3e4b0eca-5e02-46dd-a635-5b2376e98f61','送歐陽秀才赴舉','齊己','唐','唐诗','tang','','[]','莫疑空手去，無援取高科。',48,'全唐诗/poet.tang.46000.json','["莫疑空手去，無援取高科。", "直是文章好，爭如德行多。", "煙霄心一寸，霜雪路千坡。", "稱意東歸後，交親那喜何。"]'),
('ba5ff7e1-d6b9-4987-b75a-81a556dcb65c','放鷺鷥','齊己','唐','唐诗','tang','','[]','潔白雖堪愛，腥膻不那何。',24,'全唐诗/poet.tang.46000.json','["潔白雖堪愛，腥膻不那何。", "到頭從所欲，還汝舊滄波。"]'),
('afb290e4-6e86-4d10-9ff2-a4661c387d99','謝王秀才見示詩卷','齊己','唐','唐诗','tang','','[]','誰見少年心，低摧向苦吟。',48,'全唐诗/poet.tang.46000.json','["誰見少年心，低摧向苦吟。", "後須離影響，得必洞精深。", "道院春苔徑，僧樓夏竹林。", "天如愛才子，何慮未知音。"]'),
('f4d1bbf4-5ac5-4acf-8cc1-d4e9e4d07b1c','送徐秀才之吳','齊己','唐','唐诗','tang','','[]','吳都霸道昌，才子去觀光。',48,'全唐诗/poet.tang.46000.json','["吳都霸道昌，才子去觀光。", "望闕雲天近，朝宗水路長。", "海門收片雨，建業泊殘陽。", "欲問淮王信，仙都即帝鄉。"]'),
('d5ab1300-c686-4d94-8eac-beb9c6279856','獨院偶作','齊己','唐','唐诗','tang','','[]','風篁清一院，坐臥潤肌膚。',48,'全唐诗/poet.tang.46000.json','["風篁清一院，坐臥潤肌膚。", "此境終拋去，鄰房肯信無。", "身非王者役，門是祖師徒。", "畢竟伊雲鳥，從來我友于。"]'),
('f0062af4-dce3-4e01-b5c4-885f9b605ca7','酬元員外見寄','齊己','唐','唐诗','tang','','[]','僻巷誰相訪，風籬翠蔓牽。',48,'全唐诗/poet.tang.46000.json','["僻巷誰相訪，風籬翠蔓牽。", "易中通性命，貧裏過流年。", "且有吟情撓，都無俗事煎。", "時聞得新意，多是此忘緣。"]'),
('2e92fabf-a06d-4881-a2e3-4836d3ca5c5e','寄文秀大師','齊己','唐','唐诗','tang','','[]','皎然靈一時，還有屈於詩。',48,'全唐诗/poet.tang.46000.json','["皎然靈一時，還有屈於詩。", "世豈無英主，天何惜大師。", "道終歸正始，心莫問多岐。", "覽卷堪驚立，貞風喜未衰。"]'),
('d83bbd59-59ca-4db7-8d71-77335922d563','夏雨','齊己','唐','唐诗','tang','','[]','霮䨴蔽穹蒼，冥濛自一方。',144,'全唐诗/poet.tang.46000.json','["霮䨴蔽穹蒼，冥濛自一方。", "當時消酷毒，隨處有清涼。", "著物聲雖暴，滋農潤即長。", "乍紅縈急電，微白露殘陽。", "應禱尤難得，經旬甚不妨。", "吟聽喧竹樹，立見漲池塘。", "衆類聲休出，羣峰色盡藏。", "頹沱來洞壑，汗漫入瀟湘。", "下叶黎甿望，高祛旱暵光。", "幽齋飄臥簟，極浦灑歸檣。", "蘚在堦從濕，花衰苑任傷。", "閑思濟時力，謌詠發哀腸。"]'),
('f51e1a65-b210-48bc-a6d7-28dec1a0e01b','謝興公上人寄山水簇子','齊己','唐','唐诗','tang','','[]','半幅古潺顏，看來心意閑。',48,'全唐诗/poet.tang.46000.json','["半幅古潺顏，看來心意閑。", "何須尋鳥道，即此出人間。", "巘暮疑啼狖，松深認掩關。", "知君遠相惠，免我憶歸山。"]'),
('d3b0d997-32c9-4f59-aa2b-6ecbe66b8142','酬微上人','齊己','唐','唐诗','tang','','[]','古律皆深妙，新吟復造微。',48,'全唐诗/poet.tang.46000.json','["古律皆深妙，新吟復造微。", "搜難窮月窟，琢苦盡天機。", "晚檜清蟬咽，寒江白鳥飛。", "他年舊山去，爲子遠攜歸。"]'),
('f01b1f52-8147-464f-b6e5-855da05e3251','同光歲送人及第東歸','齊己','唐','唐诗','tang','','[]','西笑道何光，新朝舊桂堂。',48,'全唐诗/poet.tang.46000.json','["西笑道何光，新朝舊桂堂。", "春官如白傅，內試似文皇。", "變化龍三十，升騰鳳一行。", "還家幾多興，滿袖月中香。"]'),
('7a56c542-7938-4a57-8852-891af32e3b9f','寄江居耿處士','齊己','唐','唐诗','tang','','[]','野癖雖相似，生涯即不同。',48,'全唐诗/poet.tang.46000.json','["野癖雖相似，生涯即不同。", "紅霞禪石上，明月釣船中。", "醉倒蘆花白，吟緣蓼岸紅。", "相思何以寄，吾道本空空。"]'),
('930240ab-8807-4b0b-a308-2ecc3115eab0','病起二首 一','齊己','唐','唐诗','tang','','[]','一臥四十日，起來秋氣深。',48,'全唐诗/poet.tang.46000.json','["一臥四十日，起來秋氣深。", "已甘長逝魄，還見舊交心。", "撐拄筇猶重，枝梧力未任。", "終將此形陋，歸死故丘林。"]'),
('a53fc624-ef50-44ce-9793-50e6356a04f2','病起二首 二','齊己','唐','唐诗','tang','','[]','秋風已傷骨，更帶竹聲吹。',48,'全唐诗/poet.tang.46000.json','["秋風已傷骨，更帶竹聲吹。", "抱疾關門久，扶羸傍砌時。", "無生即不可，有死必相隨。", "除却歸真覺，何由擬免之。"]'),
('5e7b35d7-de37-4191-bef9-8abf211f564d','送中觀進公歸巴陵','齊己','唐','唐诗','tang','','[]','一論破雙空，持行大國中。',48,'全唐诗/poet.tang.46000.json','["一論破雙空，持行大國中。", "不知從此去，何處挫邪宗。", "晝雨懸帆黑，殘陽泊島紅。", "應游到㴩岸，相憶遶茶叢。"]'),
('41412043-048c-4772-bf29-a537e0950c2a','寄鄭谷郎中','齊己','唐','唐诗','tang','','[]','高名喧省闥，雅頌出吾唐。',48,'全唐诗/poet.tang.46000.json','["高名喧省闥，雅頌出吾唐。", "疊巘供秋望，無雲到夕陽。", "自封修藥院，別埽著僧牀。", "幾夢中朝事，依依鵷鷺行。"]'),
('97aad611-14bf-4160-a186-25f4075cf155','歸鴈','齊己','唐','唐诗','tang','','[]','塞門春已暖，連影起蘋風。',48,'全唐诗/poet.tang.46000.json','["塞門春已暖，連影起蘋風。", "雲夢千行去，瀟湘一夜空。", "江人休舉網，虜將又虛弓。", "莫失南來伴，衡陽樹即紅。"]'),
('14287725-784a-42bd-bdf9-e6b3f93e4724','登大林寺觀白太傅題版','齊己','唐','唐诗','tang','','[]','九疊蒼崖裏，禪家鑿翠開。',48,'全唐诗/poet.tang.46000.json','["九疊蒼崖裏，禪家鑿翠開。", "清時誰夢到，白傅獨尋來。", "怪石和僧定，閑雲共鶴迴。", "任茲休去者，心是不然灰。"]'),
('38cb69f5-11dc-413a-9fb7-acc8020739b0','贈曹松先輩','齊己','唐','唐诗','tang','','[]','今歲赴春闈，達如夫子稀。',48,'全唐诗/poet.tang.46000.json','["今歲赴春闈，達如夫子稀。", "山中把卷去，榜下注官歸。", "楚月吟前落，江禽酒外飛。", "閑遊向諸寺，却看白麻衣。"]'),
('820e3835-770a-4b29-a3dd-da246e6831e5','夏日江寺寄無上人','齊己','唐','唐诗','tang','','[]','講終齋磬罷，何處稱真心。',48,'全唐诗/poet.tang.46000.json','["講終齋磬罷，何處稱真心。", "古寺高杉下，炎天獨院深。", "燕和江鳥語，牆奪暮花陰。", "大府多才子，閑過在竹林。"]'),
('618fe135-f216-4ccd-a809-869ba1b5bc4c','夏日梅雨中寄睦公','齊己','唐','唐诗','tang','','[]','梅月來林寺，冥冥各閉門。',48,'全唐诗/poet.tang.46000.json','["梅月來林寺，冥冥各閉門。", "已應雙履跡，全沒亂雲根。", "琢句心無味，看經眼亦昏。", "何時見清霽，招我憑巖軒。"]'),
('78ce4ca7-6aba-4866-b990-87f0a21867c0','傷鄭谷郎中','齊己','唐','唐诗','tang','','[]','鍾陵千首作，筆絕亦身終。',48,'全唐诗/poet.tang.46000.json','["鍾陵千首作，筆絕亦身終。", "知落干戈裏，誰家煨燼中。", "吟齋春長蕨，釣渚夜鳴鴻。", "惆悵秋江月，曾招我看同。"]'),
('0c39b309-75de-424f-a99c-590abb846075','臨行題友生壁','齊己','唐','唐诗','tang','','[]','山衲宜何處，經行避暑深。',48,'全唐诗/poet.tang.46000.json','["山衲宜何處，經行避暑深。", "峰西多古寺，日午亂松陰。", "鶴默堪分靜，蟬涼解助吟。", "慇懃題壁去，秋早此相尋。"]'),
('b734d4d1-1989-4634-b163-f9b0e7ee6fbe','別東林後迴寄修睦','齊己','唐','唐诗','tang','','[]','昨夜從香社，辭君出薜蘿。',48,'全唐诗/poet.tang.46000.json','["昨夜從香社，辭君出薜蘿。", "晚來巾舃上，已覺俗塵多。", "遠路縈芳草，遙空共白波。", "南朝在天末，此去重經過。"]'),
('b63b43cb-5c7a-4985-8a3d-c9cafb3fc2f0','古松','齊己','唐','唐诗','tang','','[]','雷電不敢伐，鱗皴勢萬端。',48,'全唐诗/poet.tang.46000.json','["雷電不敢伐，鱗皴勢萬端。", "蠹依枯節死，蛇入朽根盤。", "影浸僧禪濕，聲吹鶴夢寒。", "尋常風雨夜，應有鬼神看。"]'),
('f49e0176-dd11-48a8-8006-04eba01eaa8b','夏日西霞寺書懷寄張逸人','齊己','唐','唐诗','tang','','[]','人中林下現，名自有閑忙。',48,'全唐诗/poet.tang.46000.json','["人中林下現，名自有閑忙。", "建業紅塵熱，栖霞白石涼。", "倚身檉几穩，灑面瀑流香。", "不似高齋裏，花連竹影長。"]'),
('b9733437-6629-4215-8344-4fa9afba429c','訪自牧上人不遇','齊己','唐','唐诗','tang','','[]','然諾竟如何，諸侯見重多。',48,'全唐诗/poet.tang.46000.json','["然諾竟如何，諸侯見重多。", "高房度江雨，經月長寒莎。", "道本同騷雅，書曾到薜蘿。", "相尋未相見，危閣望滄波。"]'),
('9152e5d5-6c15-4533-a0aa-f53031270229','題東林白蓮','齊己','唐','唐诗','tang','','[]','大士生兜率，空池滿白蓮。',48,'全唐诗/poet.tang.46000.json','["大士生兜率，空池滿白蓮。", "秋風明月下，齋日影堂前。", "色後羣芳拆，香殊百和燃。", "誰知不染性，一片好心田。"]'),
('3aaeae4d-d712-45fe-8611-f677db61a8b5','寄懷江西徵岷二律師','齊己','唐','唐诗','tang','','[]','亂後江邊寺，堪懷二律師。',48,'全唐诗/poet.tang.46000.json','["亂後江邊寺，堪懷二律師。", "幾番新弟子，一樣舊威儀。", "院影連春竹，窗聲接雨池。", "共緣山水癖，久別共題詩。"]'),
('c650154c-a623-48dd-aaf5-724ee45f924e','東林作寄金陵知己','齊己','唐','唐诗','tang','','[]','十八賢真在，時來拂榻看。',48,'全唐诗/poet.tang.46000.json','["十八賢真在，時來拂榻看。", "已知前事遠，更結後人難。", "泉滴勝清磬，松香掩白檀。", "憑君聽朝貴，誰欲厭簪冠。"]'),
('8e97e4d1-f28c-4d67-8251-ace8c1094b30','山寺喜道者至','齊己','唐','唐诗','tang','','[]','閏年春過後，山寺始花開。',48,'全唐诗/poet.tang.46000.json','["閏年春過後，山寺始花開。", "還有無心者，閑尋此境來。", "鳥幽聲忽斷，茶好味重迴。", "知住南巖久，冥心坐綠苔。"]'),
('8a593bcb-b63f-4247-b759-983809edb915','再遊匡山','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','紫霄兼二老，相對倚空寒。',48,'全唐诗/poet.tang.46000.json','["紫霄兼二老，相對倚空寒。", "久別成衰病，重來更上難。", "徑危雲母滑，崖旱瀑流乾。", "目斷嵐煙際，神仙有石壇。"]'),
('262cc8a0-eba5-4075-afde-44bdbb5d983a','贈浙西李推官','齊己','唐','唐诗','tang','','[]','他皆恃勳貴，君獨愛詩玄。',48,'全唐诗/poet.tang.46000.json','["他皆恃勳貴，君獨愛詩玄。", "終日秋光裏，無人竹影邊。", "東樓生倚月，北固積吟煙。", "聞說鴛行裏，多才復少年。"]'),
('3f1479ec-7014-41b0-a192-6431d84ecdb4','題終南山隱者室','齊己','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','終南山北面，直下是長安。',48,'全唐诗/poet.tang.46000.json','["終南山北面，直下是長安。", "自埽青苔室，閑攲白石看。", "風吹窗樹老，日曬竇雲乾。", "時向圭峰宿，僧房瀑布寒。"]'),
('26e38b06-5654-486d-b664-12fa01489504','禪庭蘆竹十二韻呈鄭谷郎中','齊己','唐','唐诗','tang','','[]','錯錯在禪庭，高宜與竹名。',144,'全唐诗/poet.tang.46000.json','["錯錯在禪庭，高宜與竹名。", "健添秋雨響，乾助夜風清。", "雀靜如枯折，僧閑見笋生。", "對吟殊灑落，負氣甚孤貞。", "密謝編欄固，齊由灌溉平。", "松姿真可敵，柳態薄難幷。", "映帶兼苔石，參差近畫楹。", "雪霜消後色，蟲鳥默時聲。", "遠憶滄洲岸，寒連暮角城。", "幽根狂亂迸，勁葉動相撐。", "避暑須臨坐，逃眠必遶行。", "未逢仙手詠，俗眼見猶輕。"]'),
('84f109dd-2b1c-46fb-8a9f-0f1ae5f8c2d3','送孫鳳秀才赴舉','齊己','唐','唐诗','tang','','[]','九重方側席，四海仰文明。',48,'全唐诗/poet.tang.46000.json','["九重方側席，四海仰文明。", "好把孤吟去，便隨公道行。", "梁園浮雪氣，汴水漲春聲。", "此日登仙衆，君應最後生。"]'),
('73aca2c7-9fe1-4545-b8d6-c2cdfc25df49','落花','齊己','唐','唐诗','tang','','[]','朝開暮亦衰，雨打復風吹。',48,'全唐诗/poet.tang.46000.json','["朝開暮亦衰，雨打復風吹。", "古屋無人處，殘陽滿地時。", "靜依青蘚片，閑綴綠莎枝。", "繁豔根枝在，明年向此期。"]'),
('5d6fa5c9-4dc0-47ee-86a7-c443a5d14ed3','秋苔','齊己','唐','唐诗','tang','','[]','獨憐蒼翠文，長與寂寥存。',48,'全唐诗/poet.tang.46000.json','["獨憐蒼翠文，長與寂寥存。", "鶴靜窺秋片，僧閑踏冷痕。", "月明疎竹徑，雨歇敗莎根。", "別有深宮裏，兼花鎖斷魂。"]'),
('250bdae6-d4d8-409f-87fd-30a0764af24a','老將','齊己','唐','唐诗','tang','','[]','破虜與平戎，曾居第一功。',48,'全唐诗/poet.tang.46000.json','["破虜與平戎，曾居第一功。", "明時不用武，白首向秋風。", "馬病霜飛草，弓閑鴈過空。", "兒孫已成立，膽氣亦英雄。"]'),
('7a646a58-94de-4878-9c27-6de558b5d4cf','城中示友人','齊己','唐','唐诗','tang','','[]','久與寒灰合，人中亦覺閑。',48,'全唐诗/poet.tang.46000.json','["久與寒灰合，人中亦覺閑。", "重城不鎖夢，每夜自歸山。", "雨破冥鴻出，桐枯井月還。", "唯君道心在，來往寂寥間。"]'),
('8ae1b9fa-fadc-477d-bc72-4e4176da1e41','送友人遊湘中','齊己','唐','唐诗','tang','','[]','懷才難自住，此去亦如僧。',48,'全唐诗/poet.tang.46000.json','["懷才難自住，此去亦如僧。", "何處西風夜，孤吟旅舍燈。", "路沿湘樹疊，山入楚雲層。", "若有東來札，歸鴻亦可憑。"]'),
('78ffe2f1-93c1-4917-b1ef-88240977548f','經費徵君舊居','齊己','唐','唐诗','tang','','[]','高眠當聖代，雲鳥未爲孤。',48,'全唐诗/poet.tang.46000.json','["高眠當聖代，雲鳥未爲孤。", "天子徵不起，閑人親得無。", "猿猱狂欲墜，水石怪難圖。", "寂寞荒齋外，松杉相倚枯。"]'),
('b7ac169d-b7d9-43a6-bfb7-3c58d0f0802c','嚴陵釣臺','齊己','唐','唐诗','tang','','[]','夫子垂竿處，空江照古臺。',48,'全唐诗/poet.tang.46000.json','["夫子垂竿處，空江照古臺。", "無人更如此，白浪自成堆。", "鶴靜尋僧去，魚狂入海迴。", "登臨秋值晚，樹石盡多苔。"]'),
('c11bbe3c-f0e1-4dab-9d9c-3e8dbe1753b0','原上晚望','齊己','唐','唐诗','tang','','[]','倚杖聊攄望，寒原遠近分。',48,'全唐诗/poet.tang.46000.json','["倚杖聊攄望，寒原遠近分。", "夜來何處火，燒出古人墳。", "野勢盤空澤，江流合暮雲。", "殘陽催百鳥，各自著栖羣。"]'),
('86913720-5fcf-40e3-ae04-2e96ba4b2df2','送惠空上人歸','齊己','唐','唐诗','tang','','[]','塵中名利熱，鳥外水雲閑。',48,'全唐诗/poet.tang.46000.json','["塵中名利熱，鳥外水雲閑。", "吾子多高趣，秋風獨自還。", "空囊隨客櫂，幾宿泊湖山。", "應有吟僧在，鄰居樹影間。"]'),
('ec69b0e2-6bac-4fe2-9e72-3f58c1a2ed55','酬章水知己','齊己','唐','唐诗','tang','','[]','新吟忽有寄，千里到荆門。',48,'全唐诗/poet.tang.46000.json','["新吟忽有寄，千里到荆門。", "落日雲初碧，殘年眼正昏。", "已爲難敵手，誰更入深論。", "後信多相寄，吾生重此言。"]'),
('9a8a2e84-cea6-4b79-b32a-da7885fb3252','閑居','齊己','唐','唐诗','tang','','[]','漸覺春光媚，塵銷作土膏。',36,'全唐诗/poet.tang.46000.json','["漸覺春光媚，塵銷作土膏。", "微寒放楊柳，纖草入風騷。", "睡少全無病，身輕乍去袍。"]'),
('8014ab61-8204-4083-81bd-768ba3e8b865','次韻酬鄭谷郎中','齊己','唐','唐诗','tang','','[]','林下高眠起，相招得句時。',48,'全唐诗/poet.tang.46000.json','["林下高眠起，相招得句時。", "開門流水入，靜話鷺鷥知。", "每許題成晚，多嫌雪阻期。", "西齋坐來久，風竹撼疎籬。"]'),
('d7d7d478-a9c7-4297-baa7-4e16a5d28822','思遊峨嵋寄林下諸友','齊己','唐','唐诗','tang','','[]','剛有峨嵋念，秋來錫欲飛。',48,'全唐诗/poet.tang.46000.json','["剛有峨嵋念，秋來錫欲飛。", "會拋湘寺去，便逐蜀帆歸。", "難世堪言善，閑人合見機。", "殷勤別諸友，莫厭楚江薇。"]'),
('6fad6db7-6fab-426a-b96a-ba9cc0b86de1','送劉秀才南遊','齊己','唐','唐诗','tang','','[]','南去謁諸侯，名山亦得遊。',48,'全唐诗/poet.tang.46000.json','["南去謁諸侯，名山亦得遊。", "便應尋瀑布，乘興上岣嶁。", "高鳥隨雲起，寒星向地流。", "相思應北望，天晚石橋頭。"]'),
('7a78a910-aa30-487f-8bcf-61f667b8aee3','示諸姪','齊己','唐','唐诗','tang','','[]','莫問年將朽，加餐已不多。',48,'全唐诗/poet.tang.46000.json','["莫問年將朽，加餐已不多。", "形容渾瘦削，行止強牽拖。", "死也何憂惱，生而有詠歌。", "侯門終謝去，却埽舊松蘿。"]'),
('2a7f9958-dbb5-4147-b420-7031562c25ed','荆渚病中因思匡廬遂成三百字寄梁先輩','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','生老病死者，早聞天竺書。',290,'全唐诗/poet.tang.46000.json','["生老病死者，早聞天竺書。", "相隨幾汩沒，不了堪欷歔。", "自理自可適，他人誰與袪。", "應當入寂滅，乃得長銷除。", "前月已骨立，今朝還貌舒。", "披衣試步履，倚策聊躊躇。", "江月青眸冷，秋風白髮疎。", "新題憶剡硾，舊約懷匡廬。", "張野久絕跡，樂[天]曾卜居。", "空龕掩薜荔，瀑布歕蟾蜍。", "古檜鳴玄鶴，涼泉躍錦魚。", "狂吟樹蔭映，縱踏花蔫菸。", "脣舌既已閑，心脾亦散攄。", "松窗有偃息，石徑無趦趄。", "夢冷通仙闕，神融合太虛。", "千峰杳靄際，萬壑明清初。", "長往期非晚，半生閑有餘。", "依劉未是詠，訪戴寧忘諸。", "稽古堪求己，觀時好笑渠。", "埋頭逐小利，沒脚拖長裾。", "道種將閑養，情田把藥鉏。", "幽香發蘭蕙，穢莽摧丘墟。", "敢謂囊盈物，那言庾滿儲。", "微煙動晨爨，細雨滋園蔬。"]'),
('a864a0a5-f045-4bf5-abe2-ca6f6272338d','竟陵遇晝公','齊己','唐','唐诗','tang','','[]','高跡何來此，遊方漸老身。',48,'全唐诗/poet.tang.46000.json','["高跡何來此，遊方漸老身。", "欲投蓮岳夏，初過竟陵春。", "錫影離雲遠，衣痕拂蘚新。", "無言即相別，此處不迷津。"]'),
('70b7197d-3d90-4302-965c-34442ce5f857','聞貫休下世','齊己','唐','唐诗','tang','','[]','吾師詩匠者，真箇碧雲流。',48,'全唐诗/poet.tang.46000.json','["吾師詩匠者，真箇碧雲流。", "爭得梁太子，重爲文選樓。", "錦江新塚樹，婺女舊山秋。", "欲去焚香禮，啼猨峽阻修。"]'),
('62492b1a-dfba-4cf0-a21a-80bec4558b82','金山寺','齊己','唐','唐诗','tang','','[]','山帶金名遠，樓臺壓翠層。',48,'全唐诗/poet.tang.46000.json','["山帶金名遠，樓臺壓翠層。", "魚龍光照像，風浪影搖燈。", "檻外揚州樹，船通建業僧。", "塵埃何所到，青石坐如冰。"]'),
('7cc0a488-6891-4e6a-a5b2-561b4e0a6b1d','早秋雨後晚望','齊己','唐','唐诗','tang','','[]','暑氣時將薄，蟲聲夜轉稠。',48,'全唐诗/poet.tang.46000.json','["暑氣時將薄，蟲聲夜轉稠。", "江湖經一雨，日月換新秋。", "有景堪援筆，何人未上樓。", "欲承涼冷興，西向碧嵩遊。"]'),
('9129bbf3-e9a8-44d5-a65d-5a9413e314b7','過西塞山','齊己','唐','唐诗','tang','','[]','空江平野流，風島葦颼颼。',48,'全唐诗/poet.tang.46000.json','["空江平野流，風島葦颼颼。", "殘日銜西塞，孤帆向北洲。", "邊鴻渡漢口，楚樹出吳頭。", "終入高雲裏，身依片石休。"]'),
('703f5f44-4147-45e8-880a-6adadcaee339','溪齋二首 一','齊己','唐','唐诗','tang','','[]','豈敢言招隱，歸休喜自安。',48,'全唐诗/poet.tang.46000.json','["豈敢言招隱，歸休喜自安。", "一溪雲臥穩，四海路行難。", "瑞獸藏頭角，幽禽惜羽翰。", "子猷何處在，老盡碧琅玕。"]'),
('fccc8dc4-a7a9-4fc6-8766-19575d39b2df','溪齋二首 二','齊己','唐','唐诗','tang','','[]','杉竹映溪關，修修共歲寒。',48,'全唐诗/poet.tang.46000.json','["杉竹映溪關，修修共歲寒。", "幽人眠日晏，花雨落春殘。", "道妙言何強，詩玄論甚難。", "閑居有親賦，搔首憶潘安。"]'),
('f5d0f225-4bcd-4dec-87d7-06126a3edaf6','新秋','齊己','唐','唐诗','tang','','[]','始驚三伏盡，又遇立秋時。',48,'全唐诗/poet.tang.46000.json','["始驚三伏盡，又遇立秋時。", "露彩朝還冷，雲峰晚更奇。", "壠香禾半熟，原迥草微衰。", "幸好清光裏，安仁謾起悲。"]'),
('607e7fb0-5f9a-41db-b60c-57c3e87dbfda','寄上荆渚因夢廬岳乃圖壁賦詩','齊己','唐','唐诗','tang','','[]','夢繞嵯峨裏，神疎骨亦寒。',48,'全唐诗/poet.tang.46000.json','["夢繞嵯峨裏，神疎骨亦寒。", "覺來誰共說，壁上自圖看。", "古翠松藏寺，春紅杏濕壇。", "歸心幾時遂，日向漸衰殘。"]'),
('70a402db-0387-4111-b58f-e8a10436a2ef','己卯歲值凍阻歸有作','齊己','唐','唐诗','tang','','[]','河冰連地凍，朔氣壓春寒。',48,'全唐诗/poet.tang.46000.json','["河冰連地凍，朔氣壓春寒。", "開戶思歸遠，出門移步難。", "湖雲黏鴈重，廟樹刮風乾。", "坐看孤燈焰，微微向曉殘。"]'),
('ee09a2ce-0bf7-49a5-80ad-ecbd8dd79279','送盧說亂後投知己','齊己','唐','唐诗','tang','','[]','兵寇殘江墅，生涯盡蕩除。',48,'全唐诗/poet.tang.46000.json','["兵寇殘江墅，生涯盡蕩除。", "事堪煎桂玉，時莫倚詩書。", "暮狖啼空半，春山列雨餘。", "舟中有新作，迴寄示慵疎。"]'),
('5d7b2a22-ef4d-4435-b366-b39b71777d35','讀峴山碑','齊己','唐','唐诗','tang','','[]','三載羊公政，千年峴首碑。',48,'全唐诗/poet.tang.46000.json','["三載羊公政，千年峴首碑。", "何人更墮淚，此道亦殊時。", "兵火燒文缺，江雲觸蘚滋。", "那堪望黎庶，匝地是瘡痍。"]'),
('da77c41f-d9b3-4eb9-b3b9-94374d78d223','過鹿門作','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','鹿門埋孟子，峴首載羊公。',48,'全唐诗/poet.tang.46000.json','["鹿門埋孟子，峴首載羊公。", "萬古千秋裏，青山明月中。", "政從襄沔絕，詩過洞庭空。", "塵路誰迴眼，松聲兩處風。"]'),
('b2f2f43c-8878-4a91-84a6-7ba018f0ca42','題玉泉寺大師影堂','齊己','唐','唐诗','tang','','[]','大化終華頂，靈蹤示玉泉。',48,'全唐诗/poet.tang.46000.json','["大化終華頂，靈蹤示玉泉。", "由來負高尚，合向好山川。", "洞壑藏諸怪，杉松列瘦煙。", "千秋空樹影，猶似覆長禪。"]'),
('b26f64c5-8dd3-422f-bdd2-70c90ca09de2','秋日錢塘作','齊己','唐','唐诗','tang','','[]','秋光明水國，遊子倚長亭。',48,'全唐诗/poet.tang.46000.json','["秋光明水國，遊子倚長亭。", "海浸全吳白，山澄百越青。", "英雄貴黎庶，封土絕精靈。", "句踐魂如在，應懸戰血腥。"]'),
('cb5da6b0-aa8b-40e5-9b60-0ffec5d1f4d9','送人赴舉','齊己','唐','唐诗','tang','','[]','分有爭忘得，時來須出山。',48,'全唐诗/poet.tang.46000.json','["分有爭忘得，時來須出山。", "白雲終許在，清世莫空還。", "驛樹秋聲健，行衣雨點斑。", "明年從月裏，滿握度春關。"]'),
('4c895152-ae26-46ae-b986-3c4eaaa046b6','友人寒夜所寄','齊己','唐','唐诗','tang','','[]','通宵亦孤坐，但念舊峰雲。',48,'全唐诗/poet.tang.46000.json','["通宵亦孤坐，但念舊峰雲。", "白日還如此，清閑本共君。", "二毛凋一半，百歲去三分。", "早晚尋流水，同歸麋鹿羣。"]'),
('5166c6dc-aaf9-4853-bb3a-8ecf0206ba71','酬洞庭陳秀才','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','何必要識面，見詩驚苦心。',48,'全唐诗/poet.tang.46000.json','["何必要識面，見詩驚苦心。", "此門從自古，難學至如今。", "青草湖雲闊，黃陵廟木深。", "精搜當好景，得即動知音。"]'),
('2114783f-a3be-4a5e-a083-ed83565b40bf','題鶴鳴泉八韻','齊己','唐','唐诗','tang','','[]','嘹淚遺蹤去，澄明物掩難。',96,'全唐诗/poet.tang.46000.json','["嘹淚遺蹤去，澄明物掩難。", "噴開山面碧，飛落寺門寒。", "汲引隨缾滿，分流逐處安。", "幽蟲乘葉過，渴狖擁條看。", "上有危峰疊，旁宜怪石盤。", "冷吞雙樹影，甘潤百毛端。", "異早聞鐫玉，靈終別建壇。", "瀟湘在何處，終日自波瀾。"]'),
('47a6342f-35f9-4d5a-864e-23b53f858cef','登金山寺','齊己','唐','唐诗','tang','','[]','四面白波聲，中流翠嶠橫。',48,'全唐诗/poet.tang.46000.json','["四面白波聲，中流翠嶠橫。", "望來堪目斷，上徹始心平。", "鳥向天涯去，雲連水國生。", "重來與誰約，題罷自吟行。"]'),
('7ee5fa87-75d1-4cbb-8298-fc27a4e9403e','寄吳都沈員外彬','齊己','唐','唐诗','tang','','[]','歸休興若何，朱紱盡還他。',48,'全唐诗/poet.tang.46000.json','["歸休興若何，朱紱盡還他。", "自有園林闊，誰爭山水多。", "村煙晴莽蒼，僧磬晚嵯峨。", "野醉題招隱，相思可寄麽。"]'),
('f073b5a0-ea41-40d3-a224-ac0f3f6a71a5','寄明月山僧','齊己','唐','唐诗','tang','','[]','山稱明月好，月出徧山明。',48,'全唐诗/poet.tang.46000.json','["山稱明月好，月出徧山明。", "要上諸峰去，無妨半夜行。", "白猨真雪色，幽鳥古琴聲。", "吾子居來久，應忘我在城。"]'),
('69688924-edb0-4941-9f20-53a7ae6ee1f8','寄哭西川壇長廣濟大師','齊己','唐','唐诗','tang','','[]','千萬僧中寶，三朝帝寵身。',48,'全唐诗/poet.tang.46000.json','["千萬僧中寶，三朝帝寵身。", "還源未化火，舉國葬全真。", "文集編金在，碑銘刻玉新。", "有誰於異代，彈指禮遺塵。"]'),
('535133d5-b507-4169-8e91-d827439a68bd','酬西川楚巒上人卷','齊己','唐','唐诗','tang','','[]','玉壘峨嵋秀，岷江錦水清。',48,'全唐诗/poet.tang.46000.json','["玉壘峨嵋秀，岷江錦水清。", "古人搜不盡，吾子得何精。", "可信由前習，堪聞正後生。", "東西五千里，多謝寄無成。"]'),
('418b5309-1378-4234-a1cf-fc8b182ee11a','覽延栖上人卷','齊己','唐','唐诗','tang','','[]','今體雕鏤妙，古風研考精。',48,'全唐诗/poet.tang.46000.json','["今體雕鏤妙，古風研考精。", "何人忘律韻，爲子辨詩聲。", "賈島苦兼此，孟郊清獨行。", "荆門見編集，媿我老無成。"]'),
('c6735a02-79de-412e-81c4-464a4f5c099f','寄洛下王彝訓先輩二首 一','齊己','唐','唐诗','tang','','[]','賈島存正始，王維留格言。',48,'全唐诗/poet.tang.46000.json','["賈島存正始，王維留格言。", "千篇千古在，一詠一驚魂。", "離別無他寄，相思共此門。", "陽春堪永恨，郢路轉塵昏。"]'),
('ea764679-765d-4a26-9198-05f970928ee2','寄洛下王彝訓先輩二首 二','齊己','唐','唐诗','tang','','[]','北極新英主，高科舊少年。',48,'全唐诗/poet.tang.46000.json','["北極新英主，高科舊少年。", "風流傳貴達，談笑取榮遷。", "洛水秋空底，嵩峰曉翠巔。", "尋常誰竝馬，橋上戲成篇。"]'),
('b831a058-979b-4187-bfba-080262df35c7','酬岳陽李主簿卷','齊己','唐','唐诗','tang','','[]','把卷思高興，瀟湘闊浸門。',48,'全唐诗/poet.tang.46000.json','["把卷思高興，瀟湘闊浸門。", "無雲生翠浪，有月動清魂。", "倚檻應窮底，凝情合到源。", "爲君吟所寄，難甚至忘筌。"]'),
('239cb3cb-7ca2-4264-b21c-b8177b957751','寄懷江西僧達禪翁','齊己','唐','唐诗','tang','','[]','長憶舊山日，與君同聚沙。',48,'全唐诗/poet.tang.46000.json','["長憶舊山日，與君同聚沙。", "未能精貝葉，便學詠楊花。", "苦甚傷心骨，清還切齒牙。", "何妨繼餘習，前世是詩家。"]'),
('20cab7f6-b799-4144-a75b-71fd5cc55f80','送吳守明先輩遊蜀','齊己','唐','唐诗','tang','','[]','憑君遊蜀去，細爲話幽奇。',48,'全唐诗/poet.tang.46000.json','["憑君遊蜀去，細爲話幽奇。", "喪亂嘉陵驛，塵埃賈島詩。", "未應過錦府，且合上峨嵋。", "既逐高科後，東西任所之。"]'),
('75708e2b-13dd-4377-bc8d-95b3b86ea1d8','寄普明大師可準','齊己','唐','唐诗','tang','','[]','蓮嶽三徵者，論詩舊與君。',48,'全唐诗/poet.tang.46000.json','["蓮嶽三徵者，論詩舊與君。", "相留曾幾歲，酬唱有新文。", "翠竇容閑憇，嵐峰許共分。", "當年若同訪，合得伴吟雲。"]'),
('99d4d0ce-823d-4c94-8d4d-bfb6b1200752','還黃平素秀才卷','齊己','唐','唐诗','tang','','[]','求己甚忘筌，得之經渾然。',48,'全唐诗/poet.tang.46000.json','["求己甚忘筌，得之經渾然。", "僻能離詭差，清不尚妖妍。", "冷澹聞姚監，精奇見浪仙。", "如君好風格，自可繼前賢。"]'),
('a3c65f71-2984-4336-bd52-a97b4f120a69','與張先輩話別','齊己','唐','唐诗','tang','','[]','爲□□□者，各自話離心。',48,'全唐诗/poet.tang.46000.json','["爲□□□者，各自話離心。", "及第還全蜀，遊方歸二林。", "巴江□□漲，楚野入吳深。", "他日傳消息，東西不易尋。"]'),
('59418ffd-76a9-4e5f-afda-16c75b6e98ae','寄朱拾遺','齊己','唐','唐诗','tang','','[]','一聞歸闕下，幾番熟金桃。',48,'全唐诗/poet.tang.46000.json','["一聞歸闕下，幾番熟金桃。", "滄海期仍晚，清資路漸高。", "研冰濡諫筆，賦雪擁朝袍。", "豈念空林下，冥心坐石勞。"]'),
('4c19824c-d4dd-4ab7-b431-29743afdf86d','荆門送興禪師','齊己','唐','唐诗','tang','','[]','灑落南宗子，遊方跡似雲。',48,'全唐诗/poet.tang.46000.json','["灑落南宗子，遊方跡似雲。", "青山尋處處，赤葉路紛紛。", "虎共松巖宿，猨和石溜聞。", "何峰一迴首，憶我在人羣。"]'),
('7bc27d6e-1ed4-4180-9c7e-be7b03ea9627','過西山施肩吾舊居','齊己','唐','唐诗','tang','','[]','大志終難起，西峰臥翠堆。',48,'全唐诗/poet.tang.46000.json','["大志終難起，西峰臥翠堆。", "牀前倒秋壑，枕上過春雷。", "鶴見丹成去，僧聞栗熟來。", "荒齋松竹老，鸞鶴自裴回。"]'),
('c5b01055-2065-45e1-81db-a01df4856499','喜夏雨','齊己','唐','唐诗','tang','','[]','四郊雲影合，千里雨聲來。',48,'全唐诗/poet.tang.46000.json','["四郊雲影合，千里雨聲來。", "盡洗紅埃去，併將清氣迴。", "潺湲浮楚甸，蕭散露荆臺。", "欲賦隨車瑞，濡毫渴謏才。"]'),
('73c9f292-3c6b-4957-83d2-ee44996d494b','酬元員外見寄八韻','齊己','唐','唐诗','tang','','[]','舊隱夢牽仍，歸心只似蒸。',96,'全唐诗/poet.tang.46000.json','["舊隱夢牽仍，歸心只似蒸。", "遠青憐島峭，輕白愛雲騰。", "豔冶叢翻蝶，腥膻地聚蠅。", "雨聲連灑竹，詩興繼填膺。", "訪戴情彌切，依劉力不勝。", "衆人忘苦苦，獨自媿兢兢。", "處世無他望，流年有病僧。", "時慙大雅客，遺韻許相承。"]'),
('092e8280-28f0-4491-b5de-94b3aded6d07','浣口泊舟曉望天柱峰','齊己','唐','唐诗','tang','','[]','根盤潛岳半，頂逼日輪邊。',48,'全唐诗/poet.tang.46000.json','["根盤潛岳半，頂逼日輪邊。", "冷碧無雲點，危稜有瀑懸。", "秀輕毛女下，名與鼎湖偏。", "誰見扶持力，峨峨出後天。"]'),
('9aa8b28e-83ef-42cd-94ef-24466d056a07','寄楚萍上人','齊己','唐','唐诗','tang','','[]','北面香爐秀，南邊瀑布寒。',48,'全唐诗/poet.tang.46000.json','["北面香爐秀，南邊瀑布寒。", "自來還獨去，夏滿又秋殘。", "日影松杉亂，雲容洞壑寬。", "何峰是鄰側，片石許相安。"]'),
('1832cc7e-500e-436f-acd4-2a2e2c8a6a1e','竹裏作六韻','齊己','唐','唐诗','tang','','[]','我來深處坐，剩覺有吟思。',72,'全唐诗/poet.tang.46000.json','["我來深處坐，剩覺有吟思。", "忽似瀟湘岸，欲生風雨時。", "冷煙濛古屋，乾籜墮秋墀。", "徑熟因頻入，身閑得徧欹。", "踏多鞭節損，題亂粉痕隳。", "猶見前山疊，微茫隔短籬。"]'),
('0fb192db-b56d-4098-ab81-601aae5b9c0a','寄江西幕中孫魴員外','齊己','唐','唐诗','tang','','[]','簪履爲官興，芙蓉結社緣。',48,'全唐诗/poet.tang.46000.json','["簪履爲官興，芙蓉結社緣。", "應思陶令醉，時訪遠公禪。", "茶影中殘月，松聲裏落泉。", "此門曾共說，知未遂終焉。"]'),
('08836432-4823-47b9-805a-ac82d7d511ae','盆池','齊己','唐','唐诗','tang','','[]','盆沼陷花邊，孤明似玉泉。',48,'全唐诗/poet.tang.46000.json','["盆沼陷花邊，孤明似玉泉。", "涵虛心不淺，待月底長圓。", "平穩承天澤，依微泛曙煙。", "何須照菱鏡，即此鑒媸妍。"]'),
('a3bc2075-7661-4f31-babb-957eb3c0e6f7','喜乾晝上人遠相訪','齊己','唐','唐诗','tang','','[]','彼此垂七十，相逢意若何。',48,'全唐诗/poet.tang.46000.json','["彼此垂七十，相逢意若何。", "聖明殊未至，離亂更應多。", "澹泊門難到，從容日易過。", "餘生消息外，只合聽詩魔。"]'),
('d4c04d80-df58-43aa-971d-4afcab2e8008','過陳陶處士舊居','齊己','唐','唐诗','tang','','[]','一室貯琴尊，詩皆大雅言。',48,'全唐诗/poet.tang.46000.json','["一室貯琴尊，詩皆大雅言。", "夜過秋竹寺，醉打老僧門。", "遠燒來籬下，寒蔬簇石根。", "閑庭除鶴跡，半是杖頭痕。"]'),
('d7af4fe5-c45b-4b09-a5bb-474baaa93502','寄敬亭清越','齊己','唐','唐诗','tang','','[]','敬亭山色古，廟與寺松連。',48,'全唐诗/poet.tang.46000.json','["敬亭山色古，廟與寺松連。", "住此修行過，春風四十年。", "鼎嘗天柱茗，詩硾剡溪牋。", "冥目應思著，終南北闕前。"]'),
('8c661efb-f02f-4f2b-ab86-f31ee3a7fbab','湘江漁父','齊己','唐','唐诗','tang','','[]','湘潭春水滿，岸遠草青青。',48,'全唐诗/poet.tang.46000.json','["湘潭春水滿，岸遠草青青。", "有客釣煙月，無人論醉醒。", "門前蛟蜃氣，蓑上蕙蘭馨。", "曾受蒙莊子，逍遙一卷經。"]'),
('42962339-76b9-4a3f-9fde-8d77c90881d9','書古寺僧房','齊己','唐','唐诗','tang','','[]','綠樹深深處，長明焰焰燈。',48,'全唐诗/poet.tang.46000.json','["綠樹深深處，長明焰焰燈。", "春時遊寺客，花落閉門僧。", "萬法心中寂，孤泉石上澄。", "勞生莫相問，喧默不相應。"]'),
('dca3f054-1b49-4fa8-90e3-9d6ed2c079cf','湖西逸人','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','老隱洞庭西，漁樵共一溪。',48,'全唐诗/poet.tang.46000.json','["老隱洞庭西，漁樵共一溪。", "琴前孤鶴影，石上遠僧題。", "橘柚園林熟，蒹葭徑路迷。", "君能許鄰並，分藥斸春畦。"]'),
('e9c5b1d0-e828-4ef4-9bd5-bb23c18e6d39','瀟湘二十韻','齊己','唐','唐诗','tang','','[]','二水遠難論，從離向坎奔。',240,'全唐诗/poet.tang.46000.json','["二水遠難論，從離向坎奔。", "冷穿千嶂脈，清過幾州門。", "闊去都凝白，傍來盡帶渾。", "經游聞舜禹，表裏見乾坤。", "浦靜魚閑釣，灣涼鴈自屯。", "月來分夜底，雲度見秋痕。", "暮氣藏鄰寺，寒濤聒近村。", "離騷傳永恨，鼓瑟奏遺魂。", "霧擁魚龍窟，槎欹島嶼根。", "秋風帆上下，落日樹沈昏。", "柳少沙洲缺，苔多古岸存。", "禽巢依橘柚，獺逕入蘭蓀。", "色自江南絕，名聞海內尊。", "吳頭雄莫遏，漢口壯堪吞。", "寥泬晴方映，馮夷信忽翻。", "渡遙峰翠疊，汀小荻花繁。", "勢接湖煙漲，聲和瘴雨歕。", "急搖吟客舫，狂濺野人樽。", "疎鑿誰窮本，澄鮮自有源。", "對茲傷九曲，含濁出崑崙。"]'),
('00c6fdc4-baa7-4a49-8922-f1c1974b3265','江行早發','齊己','唐','唐诗','tang','','["\u957f\u6c5f"]','舟子相呼起，長江未五更。',48,'全唐诗/poet.tang.46000.json','["舟子相呼起，長江未五更。", "幾看星月在，猶帶夢魂行。", "鳥亂村林迥，人喧水柵橫。", "蒼茫平野外，漸認遠峰名。"]'),
('e978d0f5-2e55-47f1-9478-e895a40aca75','宜陽道中作','齊己','唐','唐诗','tang','','[]','宜陽南面路，下嶽又經過。',48,'全唐诗/poet.tang.46000.json','["宜陽南面路，下嶽又經過。", "楓葉紅遮店，芒花白滿坡。", "猨無山漸薄，鴈衆水還多。", "日落猶前去，諸村牧豎歌。"]'),
('6da6efcd-4019-4f21-b820-d90cbf86ce31','落日','齊己','唐','唐诗','tang','','[]','晚照背高臺，殘鐘殘角催。',48,'全唐诗/poet.tang.46000.json','["晚照背高臺，殘鐘殘角催。", "能銷幾度落，已是半生來。", "吹葉陰風發，漫空暝色迴。", "因思古人事，更變盡塵埃。"]'),
('93e329a4-bbb9-4f72-acfb-5ea783db7db0','春興','齊己','唐','唐诗','tang','','[]','柳暖鶯多語，花明草盡長。',48,'全唐诗/poet.tang.46000.json','["柳暖鶯多語，花明草盡長。", "風流在詩句，牽率遶池塘。", "叫切禽名宇，飛忙蝶姓莊。", "時來真可惜，自勉掇蘭芳。"]'),
('eb938ee6-61a4-4fab-831e-5b6a1d11f326','遠山','齊己','唐','唐诗','tang','','[]','天際雲根破，寒山列翠迴。',48,'全唐诗/poet.tang.46000.json','["天際雲根破，寒山列翠迴。", "幽人當立久，白鳥背飛來。", "瀑濺何州地，僧尋幾嶠苔。", "終須拂巾履，獨去謝塵埃。"]'),
('83d6e735-fde0-4a30-98d6-04ede7f05c2c','和鄭谷郎中幽棲之什','齊己','唐','唐诗','tang','','[]','誰知閑退跡，門逕入寒汀。',48,'全唐诗/poet.tang.46000.json','["誰知閑退跡，門逕入寒汀。", "靜倚雲僧杖，孤看野燒星。", "墨霑吟石黑，苔染釣船青。", "相對唯溪寺，初宵聞念經。"]'),
('41795542-a684-461f-8b8a-b88b74899034','勉道林謙光鴻蘊二姪','齊己','唐','唐诗','tang','','[]','舊林諸姪在，還住本師房。',48,'全唐诗/poet.tang.46000.json','["舊林諸姪在，還住本師房。", "共埽焚修地，同聞水石香。", "莫將閑世界，擬敵好時光。", "須看南山下，無名塚滿岡。"]'),
('b7850763-3f51-410b-b499-97a70cb74184','渚宮自勉二首 一','齊己','唐','唐诗','tang','','[]','晨午殊豐足，伊何撓肺腸。',48,'全唐诗/poet.tang.46000.json','["晨午殊豐足，伊何撓肺腸。", "形容侵老病，山水憶韜藏。", "必謝金臺去，還攜鐵錫將。", "東林露壇畔，舊對白蓮房。"]'),
('a7865e6e-0d8b-46a3-8f1a-1a063ed9044f','渚宮自勉二首 二','齊己','唐','唐诗','tang','','[]','畢竟擬何求，隨緣去住休。',48,'全唐诗/poet.tang.46000.json','["畢竟擬何求，隨緣去住休。", "天涯遊勝境，海上宿仙洲。", "夢好尋無跡，詩成旋不留。", "從他笑輕事，獨自憶莊周。"]'),
('650ad76c-dc6b-48bb-91a5-37a4d90aea1c','謝㴩湖茶','齊己','唐','唐诗','tang','','[]','㴩湖唯上貢，何以惠尋常。',48,'全唐诗/poet.tang.46000.json','["㴩湖唯上貢，何以惠尋常。", "還是詩心苦，堪消蠟面香。", "碾聲通一室，烹色帶殘陽。", "若有新春者，西來信勿忘。"]'),
('d67b7439-eef5-436d-80e9-c7c6a19e15ff','寄歸州馬判官','齊己','唐','唐诗','tang','','[]','郡帶女𡡓名，民康境亦寧。',48,'全唐诗/poet.tang.46000.json','["郡帶女𡡓名，民康境亦寧。", "晏梳秋鬢白，閑坐暮山青。", "贈客椒初熟，尋僧酒半醒。", "應懷舊居處，歌管隔牆聽。"]'),
('20b83822-4c15-4540-a81b-5e4d4fa283ff','倦客','齊己','唐','唐诗','tang','','[]','閉眼即開門，人間事倦聞。',48,'全唐诗/poet.tang.46000.json','["閉眼即開門，人間事倦聞。", "如何迎好客，不似看閑雲。", "少欲資三要，多言讓十分。", "疎慵本吾性，任笑早離羣。"]'),
('8d114de5-b582-4563-b2c3-5763ed9b8fa0','送靈{巩/言}上人遊五臺','齊己','唐','唐诗','tang','','[]','此去清涼頂，期瞻大聖容。',48,'全唐诗/poet.tang.46000.json','["此去清涼頂，期瞻大聖容。", "便應過洛水，即未上嵩峰。", "殘照催行影，幽林惜駐蹤。", "想登金閣望，東北極兵鋒。"]'),
('e59b0761-8246-4b26-8826-766359671ea0','靜坐','齊己','唐','唐诗','tang','','[]','坐臥與行住，入禪還出吟。',48,'全唐诗/poet.tang.46000.json','["坐臥與行住，入禪還出吟。", "也應長日月，消得箇身心。", "默論相如少，黃梅付囑深。", "門前古松徑，時起步清陰。"]'),
('1391f0de-1bcc-499f-b434-6ff4063d84ca','謝虛中上人寄示題天策閣詩','齊己','唐','唐诗','tang','','[]','天策二首作，境幽搜亦玄。',48,'全唐诗/poet.tang.46000.json','["天策二首作，境幽搜亦玄。", "閣橫三楚上，題挂九霄邊。", "寺額因標勝，詩人合遇賢。", "他時誰倚檻，吟此豈忘筌。"]'),
('9f28d134-8d67-484b-a588-45740f08b0bb','荆門寄懷章供奉兼呈幕中知己','齊己','唐','唐诗','tang','','[]','紫衣居貴上，青衲老關中。',48,'全唐诗/poet.tang.46000.json','["紫衣居貴上，青衲老關中。", "事佛門相似，朝天路不同。", "神凝無惡夢，詩澹老真風。", "聞道知音在，官高信莫通。"]'),
('a1cc2535-5f6e-4faa-904b-dce571a5c9fd','江令石','齊己','唐','唐诗','tang','','[]','思量江令意，愛石甚悠悠。',48,'全唐诗/poet.tang.46000.json','["思量江令意，愛石甚悠悠。", "貪向深宮去，死同亡國休。", "兩株荒草裏，千古暮江頭。", "若似黃金貴，隋軍也不留。"]'),
('83bccb39-1507-41b6-ba47-d7168124db92','月下作','齊己','唐','唐诗','tang','','[]','良夜如清晝，幽人在小庭。',48,'全唐诗/poet.tang.46000.json','["良夜如清晝，幽人在小庭。", "滿空垂列宿，那箇是文星。", "世界歸誰是，心魂向自寧。", "何當見堯舜，重爲造生靈。"]'),
('c9ca9e66-99e0-4919-a270-ab66a60d1354','遊道林寺四絕亭觀宋杜詩版','齊己','唐','唐诗','tang','','[]','宋杜詩題在，風騷到此真。',48,'全唐诗/poet.tang.46000.json','["宋杜詩題在，風騷到此真。", "獨來終日看，一爲拂秋塵。", "古石生寒仞，春松脫老鱗。", "高僧眼根靜，應見客吟神。"]'),
('fbf07096-03b8-4c17-b214-14daf96efc3b','勉詩僧','齊己','唐','唐诗','tang','','[]','莫把毛生刺，低佪謁李膺。',48,'全唐诗/poet.tang.46000.json','["莫把毛生刺，低佪謁李膺。", "須防知佛者，解笑愛名僧。", "道性宜如水，詩情合似冰。", "還同蓮社客，聯唱遶香燈。"]'),
('0d890812-78b8-4fb7-926a-13a28f78cc4a','謝人墨','齊己','唐','唐诗','tang','','[]','珍重歲寒煙，攜來路幾千。',48,'全唐诗/poet.tang.46000.json','["珍重歲寒煙，攜來路幾千。", "只應真典誥，消得苦磨研。", "正色浮端硯，精光動蜀牋。", "因君強濡染，捨此即忘筌。"]'),
('892cf82d-9cd9-48b3-a671-ae332cea8afe','送人遊玉泉寺','齊己','唐','唐诗','tang','','[]','西峰大雪開，萬疊向空堆。',48,'全唐诗/poet.tang.46000.json','["西峰大雪開，萬疊向空堆。", "客貴猶尋去，僧高肯不來。", "潭澄猨覰月，竇冷鹿眠苔。", "公子將才子，聯題興未迴。"]'),
('dd28c4a2-034a-4f2e-801b-0ba34830854e','寄鄭谷郎中','齊己','唐','唐诗','tang','','[]','詩心何以傳，所證自同禪。',48,'全唐诗/poet.tang.46000.json','["詩心何以傳，所證自同禪。", "覓句如探虎，逢知似得仙。", "神清太古在，字好雅風全。", "曾沐星郎許，終慙是斐然。"]'),
('408b97c2-539c-45dd-90e1-e03935b04202','春雨','齊己','唐','唐诗','tang','','[]','欲布如膏勢，先聞動地雷。',48,'全唐诗/poet.tang.46000.json','["欲布如膏勢，先聞動地雷。", "雲龍相得起，風電一時來。", "霢霂農桑野，冥濛楊柳臺。", "何人待晴暖，庭有牡丹開。"]'),
('629c6e7b-3662-444b-a22b-8df30f90b1a7','明月峰','齊己','唐','唐诗','tang','','[]','明月峰頭石，曾聞學月明。',48,'全唐诗/poet.tang.46000.json','["明月峰頭石，曾聞學月明。", "別舒長夜彩，高照一村耕。", "頗亂無私理，徒驚鄙俗情。", "傳云遭鑿後，頑白在崢嶸。"]'),
('347ff74b-3ac5-4a01-b2c4-a15222b967c7','謝人惠紫栗拄杖','齊己','唐','唐诗','tang','','[]','仙掌峰前得，何當此見遺。',48,'全唐诗/poet.tang.46000.json','["仙掌峰前得，何當此見遺。", "百年衰朽骨，六尺歲寒姿。", "雪外兼松凭，泉邊待月欹。", "他時出山去，猶謝見相隨。"]'),
('3f9132ae-c791-4d4c-9ffd-034199d38222','送人遊湘湖','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','君遊南國去，旅夢若爲寧。',48,'全唐诗/poet.tang.46000.json','["君遊南國去，旅夢若爲寧。", "一路隨鴻鴈，千峰遶洞庭。", "林明楓盡落，野黑燒初經。", "有興尋僧否，湘西寺最靈。"]'),
('f969d44e-8927-4fb8-869b-be86c2234ebb','小松','齊己','唐','唐诗','tang','','[]','發地纔過膝，蟠根已有靈。',48,'全唐诗/poet.tang.46000.json','["發地纔過膝，蟠根已有靈。", "嚴霜百草白，深院一林青。", "後夜蕭騷動，空階蟋蟀聽。", "誰於千歲外，吟遶老龍形。"]'),
('3dc51ba0-80f6-44d9-8a2b-57ecbc59e8a4','金江寓居','齊己','唐','唐诗','tang','','[]','考槃應未永，聊此養閑疎。',48,'全唐诗/poet.tang.46000.json','["考槃應未永，聊此養閑疎。", "野趣今何似，詩題舊不如。", "春篁離籜盡，陂藕折花初。", "終要秋雲是，從風恣卷舒。"]'),
('abbbd055-7935-417b-9ea6-db52300d5806','晚夏金江寓居答友生','齊己','唐','唐诗','tang','','[]','日日衝殘熱，相尋入亂蒿。',48,'全唐诗/poet.tang.46000.json','["日日衝殘熱，相尋入亂蒿。", "閑中滋味遠，詩裏是非高。", "碧聳新生竹，紅垂半熟桃。", "時難未可出，且欲淬豪曹。"]'),
('a5a855ad-92d2-495f-afc6-8a692eeed140','寄李洞秀才','齊己','唐','唐诗','tang','','[]','到處聽時論，知君屈最深。',48,'全唐诗/poet.tang.46000.json','["到處聽時論，知君屈最深。", "秋風幾西笑，抱玉但傷心。", "野水翻紅藕，滄江老白禽。", "相思未相識，聞在蜀中吟。"]'),
('0068feff-a674-4cda-b330-8ea23ab56a1c','過商山','齊己','唐','唐诗','tang','','[]','疊疊疊嵐寒，紅塵翠裏盤。',48,'全唐诗/poet.tang.46000.json','["疊疊疊嵐寒，紅塵翠裏盤。", "前程有名利，此路莫艱難。", "雲水侵天老，輪蹄到月殘。", "何能尋四皓，過盡見長安。"]'),
('fd5c1942-a090-468c-a456-6c4c5a2f49d2','蟬八韻','齊己','唐','唐诗','tang','','[]','咽咽復啾啾，多來自早秋。',96,'全唐诗/poet.tang.46000.json','["咽咽復啾啾，多來自早秋。", "園林涼正好，風雨思相收。", "在處聲無別，何人淚欲流。", "冷憐天露滴，傷共野禽遊。", "靜息深依竹，驚移瞥過樓。", "分明晴渡口，淒切暮關頭。", "時節推應定，飛鳴即未休。", "年年聞爾苦，遠憶所居幽。"]'),
('af9018bc-b647-4429-9b00-413fa12bfc69','鷺鷥二首 一','齊己','唐','唐诗','tang','','[]','日日滄江去，時時得意歸。',48,'全唐诗/poet.tang.46000.json','["日日滄江去，時時得意歸。", "自能終潔白，何處悞翻飛。", "晚立銀塘闊，秋栖玉露微。", "殘陽葦花畔，雙下釣魚磯。"]'),
('b09d4d44-088a-4694-9263-549fc3af24f9','鷺鷥二首 二','齊己','唐','唐诗','tang','','[]','雪裏曾迷我，籠中舊養君。',48,'全唐诗/poet.tang.46000.json','["雪裏曾迷我，籠中舊養君。", "忽從紅蓼岸，飛出白鷗羣。", "影照翹灘浪，翎濡宿島雲。", "鴛鴻解相憶，天上列紛紛。"]'),
('8ff20737-ba4e-482e-b1d6-b053ecd0c713','送僧歸南岳','齊己','唐','唐诗','tang','','[]','濁世住終難，孤峰念永安。',48,'全唐诗/poet.tang.46000.json','["濁世住終難，孤峰念永安。", "逆風眉磔磔，衝雪錫珊珊。", "石室關霞嫩，松枝拂蘚乾。", "巖猨應認得，連臂下句欄。"]'),
('8f086365-2930-4dde-9ac3-a922af30550c','夏日林下作','齊己','唐','唐诗','tang','','[]','煩暑莫相煎，森森在眼前。',48,'全唐诗/poet.tang.46000.json','["煩暑莫相煎，森森在眼前。", "暫來還盡日，獨坐只聞蟬。", "草媚終難死，花飛卒未蔫。", "秋風捨此去，滿篋貯新篇。"]'),
('e1b41c40-52db-462b-a6e0-543cdc5ffe5a','村居寄懷','齊己','唐','唐诗','tang','','[]','風雨如堯代，何心欲退藏。',48,'全唐诗/poet.tang.46000.json','["風雨如堯代，何心欲退藏。", "諸侯行教化，下國自耕桑。", "道挫時機盡，禪留話路長。", "前溪久不過，忽覺早禾香。"]'),
('7386ed93-4b1f-4618-a5bd-93f18f55b0f0','酬王秀才','齊己','唐','唐诗','tang','','[]','相於分倍親，靜論到吟真。',48,'全唐诗/poet.tang.46000.json','["相於分倍親，靜論到吟真。", "王澤曾無外，風騷甚少人。", "鴻隨秋過盡，雪向臘飛頻。", "何處多幽勝，期君作近鄰。"]'),
('32c9245c-8730-4b81-b133-5427f14946ce','贈無本上人','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','往年吟月社，因亂散揚州。',48,'全唐诗/poet.tang.46000.json','["往年吟月社，因亂散揚州。", "未免無端事，何妨出世流。", "洞庭禪過臘，衡岳坐經秋。", "終說將衣鉢，天台老去休。"]'),
('2b9e51e7-dd6e-4fdb-a12c-dd083ebea766','寄華山司空圖','齊己','唐','唐诗','tang','','[]','天下艱難際，全家入華山。',48,'全唐诗/poet.tang.46000.json','["天下艱難際，全家入華山。", "幾勞丹詔問，空見使臣還。", "瀑布寒吹夢，蓮峰翠濕關。", "兵戈阻相訪，身老瘴雲間。"]'),
('e0147be6-bd00-47a4-b53d-841accddaa08','題真州精舍','齊己','唐','唐诗','tang','','[]','波心精舍好，那岸是繁華。',48,'全唐诗/poet.tang.46000.json','["波心精舍好，那岸是繁華。", "礙目無高樹，當門即遠沙。", "晨齋來海客，夜磬到漁家。", "石鼎秋濤靜，禪回有岳茶。"]'),
('ff75ba70-8fcb-434d-ba52-cecff1bfd2f7','懷道林寺因寄仁用二上人','齊己','唐','唐诗','tang','','[]','名山知不遠，長憶寺門松。',48,'全唐诗/poet.tang.46000.json','["名山知不遠，長憶寺門松。", "昨晚登樓見，前年過夏峰。", "雨餘雲脚樹，風外日西鐘。", "莫更來東岸，紅塵沒馬蹤。"]'),
('cb216bc4-0d81-479f-a3ef-2ee9faa1ed11','尋陽道中作','齊己','唐','唐诗','tang','','[]','秋聲連岳樹，草色徧汀洲。',48,'全唐诗/poet.tang.46000.json','["秋聲連岳樹，草色徧汀洲。", "多事時爲客，無人處上樓。", "雲疎片雨歇，野闊九江流。", "欲向南朝去，詩僧有惠休。"]'),
('74054d40-b588-4403-a595-55698869fc34','東林雨後望香爐峰','齊己','唐','唐诗','tang','','[]','翠濕僧窗裏，寒堆鳥道邊。',48,'全唐诗/poet.tang.46000.json','["翠濕僧窗裏，寒堆鳥道邊。", "靜思尋去路，急遶落來泉。", "暮雨開青壁，朝陽照紫煙。", "二林多長老，誰憶上頭禪。"]'),
('576da9e4-fb3f-47ca-8b1b-ee3171a66d33','寄雙泉大師師兄','齊己','唐','唐诗','tang','','[]','清泉流眼底，白道倚巖稜。',48,'全唐诗/poet.tang.46000.json','["清泉流眼底，白道倚巖稜。", "後夜禪初入，前溪樹折冰。", "南涼來的的，北魏去騰騰。", "敢把吾師意，密傳門外僧。"]'),
('24875964-dec1-410b-8bb8-f10fb93eb57d','送人潤州尋兄弟','齊己','唐','唐诗','tang','','[]','君話南徐去，迢迢過建康。',48,'全唐诗/poet.tang.46000.json','["君話南徐去，迢迢過建康。", "弟兄新得信，鴻鴈久離行。", "木落空林浪，秋殘漸雪霜。", "閑遊登北固，東望海蒼蒼。"]'),
('d79dd82d-2f37-4304-b510-62b446485d1d','貽張生','齊己','唐','唐诗','tang','','[]','日日見入寺，未曾含酒容。',48,'全唐诗/poet.tang.46000.json','["日日見入寺，未曾含酒容。", "閑聽老僧語，坐到夕陽鐘。", "竹裏行多影，花邊偶過蹤。", "猶言謝生計，隨我去孤峰。"]'),
('acc06edc-6b58-4a25-a462-d4541e9a2fb2','送人遊雍京','齊己','唐','唐诗','tang','','[]','君來乞詩別，聊與愴前程。',48,'全唐诗/poet.tang.46000.json','["君來乞詩別，聊與愴前程。", "九野未無事，少年何遠行。", "商雲盤翠險，秦甸下煙平。", "應見周南化，如今在雍京。"]'),
('700b5dfc-8c45-40b4-a559-20494d5ff44f','春草','齊己','唐','唐诗','tang','','[]','處處碧萋萋，平原帶日西。',48,'全唐诗/poet.tang.46000.json','["處處碧萋萋，平原帶日西。", "堪隨遊子路，遠入鷓鴣啼。", "金谷園應沒，夫差國已迷。", "欲尋蘭蕙徑，荒穢滿汀畦。"]'),
('d6db9572-1035-4fdf-9e29-efca749f51e5','懷華頂道人','齊己','唐','唐诗','tang','','[]','華頂星邊出，真宜上士家。',48,'全唐诗/poet.tang.46000.json','["華頂星邊出，真宜上士家。", "無人觸牀榻，滿屋貯煙霞。", "坐臥臨天井，晴明見海涯。", "禪餘石橋去，屐齒印松花。"]'),
('32216375-4854-487a-b2be-b89a6d9f8148','寄自牧上人','齊己','唐','唐诗','tang','','[]','五老迴無計，三峰去不成。',48,'全唐诗/poet.tang.46000.json','["五老迴無計，三峰去不成。", "何言謝雲鳥，此地識公卿。", "夢媿將僧說，心嫌觸類生。", "南朝古山寺，曾憶共尋行。"]'),
('26ef4d65-5bc5-4d4f-b157-4f41b66b81e5','靜坐','齊己','唐','唐诗','tang','','[]','日日只騰騰，心機何以興。',48,'全唐诗/poet.tang.46000.json','["日日只騰騰，心機何以興。", "詩魔苦不利，禪寂頗相應。", "硯滿塵埃點，衣多作臥稜。", "如斯自消息，合是箇閑僧。"]'),
('532305fe-18ed-4cf1-b2b3-6a8efee3512d','送人遊衡岳','齊己','唐','唐诗','tang','','[]','荆楚臘將殘，江湖蒼莽間。',48,'全唐诗/poet.tang.46000.json','["荆楚臘將殘，江湖蒼莽間。", "孤舟載高興，千里向名山。", "雪浪來無定，風帆去是閑。", "石橋僧問我，應寄岳茶還。"]'),
('ef031c67-5e6e-441e-a405-b9c8dbef1c45','荅知己自闕下寄書','齊己','唐','唐诗','tang','','[]','故人勞札翰，千里寄荆臺。',48,'全唐诗/poet.tang.46000.json','["故人勞札翰，千里寄荆臺。", "知戀文明在，來尋江漢來。", "羣機喧白晝，陸海漲黃埃。", "得路應相笑，無成守死灰。"]'),
('b7ade9e4-a623-4b61-978d-6aff8147a113','新笋','齊己','唐','唐诗','tang','','[]','亂迸苔錢破，參差出小欄。',48,'全唐诗/poet.tang.46000.json','["亂迸苔錢破，參差出小欄。", "層層離錦籜，節節露琅玕。", "直上心終勁，四垂煙漸寬。", "欲知含古律，試剪鳳簫看。"]'),
('24ffa383-10c1-4ef6-8ea8-e9848276aed2','寄唐洙處士','齊己','唐','唐诗','tang','','[]','行僧去湘水，歸鴈度荆門。',48,'全唐诗/poet.tang.46000.json','["行僧去湘水，歸鴈度荆門。", "彼此亡家國，東西役夢魂。", "多慵如長傲，久住不生根。", "曾問興亡事，丁寧寄勿言。"]'),
('faaae310-4449-42da-ae3c-d5b44769c6ec','謝人惠竹蠅拂','齊己','唐','唐诗','tang','','[]','妙刮筠篁製，纖柔玉柄同。',48,'全唐诗/poet.tang.46000.json','["妙刮筠篁製，纖柔玉柄同。", "拂蠅聲滿室，指月影搖空。", "敢捨經行外，常將宴坐中。", "揮談一無取，千萬媿生公。"]'),
('eaa53729-5851-4d2a-8b41-990b07014c9b','新燕','齊己','唐','唐诗','tang','','[]','燕燕知何事，年年應候來。',48,'全唐诗/poet.tang.46000.json','["燕燕知何事，年年應候來。", "却緣華屋在，長得好時催。", "花外銜泥去，空中接食迴。", "不同黃雀意，迷逐網羅媒。"]'),
('ecd1e51d-7705-4ddb-98a2-ecb9b56bee62','謝王先輩寄氈','齊己','唐','唐诗','tang','','[]','深謝高科客，名氈寄惠重。',48,'全唐诗/poet.tang.46000.json','["深謝高科客，名氈寄惠重。", "靜思生朔漠，和雪長蒙茸。", "摺坐資禪悅，鋪眠減病容。", "他年從破碎，擔去臥孤峰。"]'),
('8b9c7c5b-3e12-427a-b6fc-564760456159','寄還闕下高輦先輩卷','齊己','唐','唐诗','tang','','[]','去歲逢京使，因還所寄詩。',48,'全唐诗/poet.tang.46000.json','["去歲逢京使，因還所寄詩。", "難留天上作，曾換月中枝。", "趣極僧迷旨，功深鬼不知。", "仍聞得名後，特地更忘疲。"]'),
('3b7b986e-cd7d-4350-82ef-1a7d0d662a4b','和孫支使惠示院中庭竹之什','齊己','唐','唐诗','tang','','[]','憶就江僧乞，和煙得一莖。',48,'全唐诗/poet.tang.46000.json','["憶就江僧乞，和煙得一莖。", "剪黃憎舊本，科綠惜新生。", "護噪蟬身穩，資吟客眼明。", "星郎有佳詠，雅合此君聲。"]'),
('ab29e751-dee0-4fa2-ab51-9fc2b6a76058','苦熱中江上懷爐峰舊居','齊己','唐','唐诗','tang','','[]','舊寄爐峰下，杉松遶石房。',48,'全唐诗/poet.tang.46000.json','["舊寄爐峰下，杉松遶石房。", "年年五六月，江上憶清涼。", "久別應荒廢，終歸隔渺茫。", "何當便搖落，披衲玩秋光。"]'),
('101ceb21-6e66-457b-91b4-7d5ce891c4a0','送僧遊龍門香山寺','齊己','唐','唐诗','tang','','[]','君到香山寺，探幽莫損神。',24,'全唐诗/poet.tang.46000.json','["君到香山寺，探幽莫損神。", "且尋風雅主，細看樂天真。"]'),
('be0d5be9-5b04-4d28-8556-1f039ca31a99','江上值春雨','齊己','唐','唐诗','tang','','[]','江臯正月雨，平陸亦波瀾。',48,'全唐诗/poet.tang.46000.json','["江臯正月雨，平陸亦波瀾。", "半是峨嵋雪，重爲澤國寒。", "農田淹寖盡，客櫂往來難。", "愁殺騷人路，滄浪正渺漫。"]'),
('2f300006-2568-4c7e-a6d8-45d674dc30ab','七十作','齊己','唐','唐诗','tang','','[]','七十去百歲，都來三十春。',48,'全唐诗/poet.tang.46000.json','["七十去百歲，都來三十春。", "縱饒生得到，終免死無因。", "密理方通理，栖真始見真。", "沃洲匡阜客，幾劫不迷人。"]'),
('aac88dd4-40e4-48e0-b613-e22b305ef1e6','謝虛中寄新詩','齊己','唐','唐诗','tang','','[]','舊友一千里，新詩五十篇。',48,'全唐诗/poet.tang.46000.json','["舊友一千里，新詩五十篇。", "此文經大匠，不見已多年。", "趣極同無迹，精深合自然。", "相思把行坐，南望隔塵煙。"]'),
('f2f9f1d7-4122-41b2-ac92-357d0fe05e00','送彬座主赴龍安請講','齊己','唐','唐诗','tang','','[]','兩論久研精，龍安受請行。',48,'全唐诗/poet.tang.46000.json','["兩論久研精，龍安受請行。", "春城雨雪霽，古寺殿堂明。", "白髮老僧聽，金毛師子聲。", "同流有誰共，別著國風清。"]'),
('a4c5f940-e701-45ec-ae27-7b63cae6ae7d','夏日荆渚書懷','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','嵩岳去值亂，匡廬迴阻兵。',48,'全唐诗/poet.tang.46000.json','["嵩岳去值亂，匡廬迴阻兵。", "中途息瓶錫，十載依公卿。", "不那猨鳥性，但懷林泉聲。", "何時遂情興，吟遶杉松行。"]'),
('25eab67e-065e-4ca3-9464-9b55a950813c','春日西湖作','齊己','唐','唐诗','tang','','["\u897f\u6e56"]','一水遶孤島，閑門掩春草。',24,'全唐诗/poet.tang.46000.json','["一水遶孤島，閑門掩春草。", "曾無長者轍，枉此問衰老。"]'),
('32796434-5818-4ebb-ab20-16e6d6951086','謝中上人寄茶','齊己','唐','唐诗','tang','','[]','春山穀雨前，併手摘芳煙。',48,'全唐诗/poet.tang.46000.json','["春山穀雨前，併手摘芳煙。", "綠嫩難盈籠，清和易晚天。", "且招鄰院客，試煮落花泉。", "地遠勞相寄，無來又隔年。"]'),
('dd83d4bd-984a-4b86-9b25-abea03996ac4','送節大德歸闕','齊己','唐','唐诗','tang','','[]','西京曾入內，東洛又朝天。',48,'全唐诗/poet.tang.46000.json','["西京曾入內，東洛又朝天。", "聖上方虛席，僧中正乏賢。", "晨光金殿裏，紫氣玉簾前。", "知祝唐堯化，新恩異往年。"]'),
('dab0b054-181b-4058-aca9-7fdd9f1fe00d','覽清尚卷','齊己','唐','唐诗','tang','','[]','李洞僻相似，得詩先示師。',48,'全唐诗/poet.tang.46000.json','["李洞僻相似，得詩先示師。", "鬼神迷去處，風日背吟時。", "格已搜清竭，名還着紫卑。", "從容味高作，翻爲古人疑。"]'),
('adee4133-be4b-4325-8c55-752c589be191','荆門送晝公歸彭澤舊居','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','彭澤舊居在，匡廬翠疊前。',48,'全唐诗/poet.tang.46000.json','["彭澤舊居在，匡廬翠疊前。", "因思從楚寺，便附入吳船。", "岸遶春殘樹，江浮曉霽天。", "應過虎溪社，佇立想諸賢。"]'),
('8a0ef495-fc54-48d2-ae3e-e9bd88ab8523','登祝融峯','齊己','唐','唐诗','tang','','[]','猨鳥共不到，我來身欲浮。',48,'全唐诗/poet.tang.46000.json','["猨鳥共不到，我來身欲浮。", "四邊空碧落，絕頂正清秋。", "宇宙知何極，華夷見細流。", "壇西獨立久，白日轉神州。"]'),
('65e9f151-6e57-4d6e-bb55-fa20321f0992','寄貫休','齊己','唐','唐诗','tang','','[]','子美曾吟處，吾師復去吟。',48,'全唐诗/poet.tang.46000.json','["子美曾吟處，吾師復去吟。", "是何多勝地，銷得二公心。", "錦水流春闊，峨嵋疊雪深。", "時逢蜀僧說，或道近遊黔。"]'),
('012628f0-7000-4266-9d08-9f17234f9c35','送唐稟正字歸萍川','齊己','唐','唐诗','tang','','[]','霜鬚芸閣吏，久掩白雲扉。',48,'全唐诗/poet.tang.46000.json','["霜鬚芸閣吏，久掩白雲扉。", "來謁元戎後，還騎病馬歸。", "煙村蔬飲淡，江驛雪泥肥。", "知到中林日，春風長澗薇。"]'),
('2bc4e451-749c-4b0e-a0e1-91eaf750b679','寄懷江西栖公','齊己','唐','唐诗','tang','','[]','龍沙爲別日，廬阜得書年。',48,'全唐诗/poet.tang.46000.json','["龍沙爲別日，廬阜得書年。", "不見來香社，相思遶白蓮。", "江僧歸海寺，楚路接吳煙。", "老病何堪說，扶羸寄此篇。"]'),
('0d9f31c2-c991-4291-9e0e-a77b877719a2','山中喜得友生書','齊己','唐','唐诗','tang','','[]','柴門關樹石，未省夢塵埃。',48,'全唐诗/poet.tang.46000.json','["柴門關樹石，未省夢塵埃。", "落日啼猨裏，同人有信來。", "自成爲拙隱，難以謝多才。", "見說相思處，前峯對古臺。"]'),
('36f396a8-4e27-466a-89ea-77a57dc8a632','謝人惠扇子及茶','齊己','唐','唐诗','tang','','[]','鎗旗封蜀茗，圓潔製鮫綃。',48,'全唐诗/poet.tang.46000.json','["鎗旗封蜀茗，圓潔製鮫綃。", "好客分烹煮，青蠅避動搖。", "陸生誇妙法，班女恨涼飆。", "多謝崔居士，相思寄寂寥。"]'),
('9cc69a02-6180-4801-8378-d9f7f2e4b6d9','寄監利司空學士','齊己','唐','唐诗','tang','','[]','詩家爲政別，清苦日聞新。',48,'全唐诗/poet.tang.46000.json','["詩家爲政別，清苦日聞新。", "亂後無荒地，歸來盡遠人。", "寬容民賦稅，憔悴吏精神。", "何必河陽縣，空傳桃李春。"]'),
('ba9d2070-76f4-4239-984d-a8999ed41639','荅陳秀才','齊己','唐','唐诗','tang','','[]','萬事皆可了，有詩門最深。',48,'全唐诗/poet.tang.46000.json','["萬事皆可了，有詩門最深。", "古人難得志，吾子苦留心。", "野疊涼雲朵，苔重怪木陰。", "他年立名字，笑我老雙林。"]'),
('5b720442-c06f-4d1c-9bd6-b77fe6b8f866','遊橘洲','齊己','唐','唐诗','tang','','[]','春日上芳洲，經春蘭杜幽。',48,'全唐诗/poet.tang.46000.json','["春日上芳洲，經春蘭杜幽。", "此時尋橘岸，昨日在城樓。", "鷺立青楓杪，沙沈白浪頭。", "漁家好生計，簷底繫扁舟。"]'),
('80fbef34-d9af-46b6-a956-eae7d192aa37','寄武陵道友','齊己','唐','唐诗','tang','','[]','阮肇迷仙處，禪門接紫霞。',48,'全唐诗/poet.tang.46000.json','["阮肇迷仙處，禪門接紫霞。", "不知尋鶴路，幾里入桃花。", "晚樹陰搖蘚，春潭影弄砂。", "何當見招我，乞與片生涯。"]'),
('6a150b95-ea6a-4072-9e97-7a5df29a24e9','謝人惠藥','齊己','唐','唐诗','tang','','[]','五金元造化，九鍊更精新。',48,'全唐诗/poet.tang.46000.json','["五金元造化，九鍊更精新。", "敢謂長生客，將遺必死人。", "久餐應換骨，一服已通神。", "終逐淮王去，永拋浮世塵。"]'),
('1c50308e-e896-4d0b-94eb-20eaf22548f8','還族弟卷','齊己','唐','唐诗','tang','','[]','豈要私相許，君詩自入神。',48,'全唐诗/poet.tang.46000.json','["豈要私相許，君詩自入神。", "風騷何句出，瀑布一聯新。", "□若長如此，名須遠逐身。", "閑齋舒復卷，留滯忽經旬。"]'),
('d9b02980-23c1-4110-a92c-1f079197b3a9','送周秀遊峽','齊己','唐','唐诗','tang','','[]','又向夔城去，知難動旅魂。',48,'全唐诗/poet.tang.46000.json','["又向夔城去，知難動旅魂。", "自非亡國客，何慮斷腸猨。", "灩澦分高仞，瞿塘露淺痕。", "明年期此約，平穩到荆門。"]'),
('130b988b-2ffd-46bc-8118-410a3dd0fdb6','荆門夏日寄洞山節公','齊己','唐','唐诗','tang','','[]','湖光搖翠木，靈洞疊雲深。',48,'全唐诗/poet.tang.46000.json','["湖光搖翠木，靈洞疊雲深。", "五月經行處，千秋檜栢陰。", "山形臨北渚，僧格繼東林。", "莫惜相招信，余心是此心。"]'),
('27250571-0a5b-4ec5-8f65-ed85059d204d','再經蔣山與諸長老夜話','齊己','唐','唐诗','tang','','[]','遠迹都如雁，南行又北迴。',48,'全唐诗/poet.tang.46000.json','["遠迹都如雁，南行又北迴。", "老僧猶記得，往歲已曾來。", "話遍名山境，燒殘黑櫟灰。", "無因伴師往，歸思在天台。"]'),
('48312d91-56b2-4efc-af18-64b74d089427','寄當陽張明府','齊己','唐','唐诗','tang','','[]','玉泉神運寺，寒磬徹琴堂。',48,'全唐诗/poet.tang.46000.json','["玉泉神運寺，寒磬徹琴堂。", "有境靈如此，爲官興亦長。", "吏愁清白甚，民樂賦輸忘。", "聞說巴山縣，今來尚憶張。"]'),
('653dc6c0-5bd2-4925-9463-9f981126e6b2','遊三覺山','齊己','唐','唐诗','tang','','[]','白石路重重，縈紆勢忽窮。',48,'全唐诗/poet.tang.46000.json','["白石路重重，縈紆勢忽窮。", "孤峯擎像閣，萬木蔽星空。", "世論隨時變，禪懷歷劫同。", "良宵正冥目，海日上窗紅。"]'),
('41f6bd08-177e-484c-9bd5-60fd076528ed','庭際晚菊上主人','齊己','唐','唐诗','tang','','[]','九月將欲盡，幽叢始綻芳。',48,'全唐诗/poet.tang.46000.json','["九月將欲盡，幽叢始綻芳。", "都緣含正氣，不是背重陽。", "採去蜂聲遠，尋來蝶路長。", "王孫歸未晚，猶得泛金觴。"]'),
('a7b7ebab-e5f7-48c9-8eef-0cfc1b6a6a88','送趙長史歸閩川','齊己','唐','唐诗','tang','','[]','荆門與閩越，關戍隔三千。',48,'全唐诗/poet.tang.46000.json','["荆門與閩越，關戍隔三千。", "風雪揚帆去，臺隍指海邊。", "客情消旅火，王化似堯年。", "莫失春迴約，江城穀雨前。"]'),
('ae2faebf-6c7b-483e-b114-e21a162bf02f','擬嵇康絕交寄湘中貫微','齊己','唐','唐诗','tang','','[]','何處同嵇懶，吾徒道異諸。',48,'全唐诗/poet.tang.46000.json','["何處同嵇懶，吾徒道異諸。", "本無文字學，何有往來書。", "嶽寺逍遙夢，侯門勉強居。", "相知在玄契，莫訝八行疎。"]'),
('377f8157-763c-4911-9620-67afa7ac5ae8','寄許州清古','齊己','唐','唐诗','tang','','[]','北來儒士說，許下有吟僧。',48,'全唐诗/poet.tang.46000.json','["北來儒士說，許下有吟僧。", "白日身長倚，清秋塔上層。", "言雖依景得，理要入無徵。", "敢望多相示，孱微老不勝。"]'),
('a5c0ef43-fd52-4e7a-b7c7-6af4f527c806','謝丁秀才見示賦卷','齊己','唐','唐诗','tang','','[]','五首新裁翦，搜羅盡指歸。',48,'全唐诗/poet.tang.46000.json','["五首新裁翦，搜羅盡指歸。", "誰曾師古律，君自負天機。", "聖后求賢久，明公得雋稀。", "乘秋好攜去，直望九霄飛。"]'),
('5c74f141-7829-4aa1-8531-733b28cccef8','驚秋','齊己','唐','唐诗','tang','','[]','褰簾聽秋信，晚傍竹聲歸。',48,'全唐诗/poet.tang.46000.json','["褰簾聽秋信，晚傍竹聲歸。", "多故堪傷骨，孤峯好拂衣。", "梧桐凋綠盡，菡萏墮紅稀。", "却恐吾形影，嫌心與口違。"]'),
('9ddb23fd-e5bf-4b01-bd37-cc986da31a75','夏日雨中寄幕中知己','齊己','唐','唐诗','tang','','[]','北風吹夏雨，和竹亞南軒。',48,'全唐诗/poet.tang.46000.json','["北風吹夏雨，和竹亞南軒。", "豆枕欹涼冷，蓮峯入夢魂。", "窗多斜迸濕，庭徧瀑流痕。", "清興知無限，晴來示一言。"]'),
('b90db8fa-9e35-4fa5-90b4-5a2848728e66','夜次湘陰','齊己','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','風濤出洞庭，帆影入澄清。',48,'全唐诗/poet.tang.46000.json','["風濤出洞庭，帆影入澄清。", "何處驚鴻起，孤舟趂月行。", "時難多戰地，野闊絕春耕。", "骨肉知存否，林園近郡城。"]'),
('e1757c5c-b293-4c17-8e4b-3c431000c59c','寄唐稟正字','齊己','唐','唐诗','tang','','[]','疎野還如舊，何曾稱在城。',48,'全唐诗/poet.tang.46000.json','["疎野還如舊，何曾稱在城。", "水邊無伴立，天際有山橫。", "落日雲霞赤，高窗筆硯明。", "鮑昭多所得，時憶寄湯生。"]'),
('4b6048fa-3de7-4fa4-a705-554f25cc8d68','宿舒湖希上人房','齊己','唐','唐诗','tang','','[]','入寺先來此，經窗半在湖。',48,'全唐诗/poet.tang.46000.json','["入寺先來此，經窗半在湖。", "秋風新菡萏，暮雨老菰蒲。", "任聽浮生速，能消默坐無。", "語來燈焰短，嘒唳發高梧。"]'),
('eb8708d4-9150-4e59-95ae-0cea61f098dc','戊辰歲江南感懷','齊己','唐','唐诗','tang','','[]','忽忽動中私，人間何所之。',48,'全唐诗/poet.tang.46000.json','["忽忽動中私，人間何所之。", "老過離亂世，生在太平時。", "桃李春無主，杉松寺有期。", "曾吟子山賦，何啻舊凌遲。"]'),
('b99dc438-cfdf-4e8a-b890-7fd9311608a4','送林上人歸永嘉舊居','齊己','唐','唐诗','tang','','[]','東越常懸思，山門在永嘉。',48,'全唐诗/poet.tang.46000.json','["東越常懸思，山門在永嘉。", "秋光浮楚水，帆影背長沙。", "城黑天台雨，村明海嶠霞。", "時尋謝公跡，春草有瑤花。"]'),
('db3f5064-de5e-462c-81f2-d4cef62027a9','荅友生山居寄示','齊己','唐','唐诗','tang','','[]','嘉遁有新吟，因僧寄竹林。',48,'全唐诗/poet.tang.46000.json','["嘉遁有新吟，因僧寄竹林。", "靜思來鳥外，閑味遶松陰。", "兵寇憑凌甚，溪山幾許深。", "休爲反招隱，攜取一相尋。"]'),
('868d338b-f7f2-42b8-a5ba-3e1ccbf159d8','新秋霽後晚眺懷先公','齊己','唐','唐诗','tang','','[]','雨霽湘楚晚，水涼天亦澄。',48,'全唐诗/poet.tang.46000.json','["雨霽湘楚晚，水涼天亦澄。", "山中應解夏，渡口有行僧。", "鳥列滄洲隊，雲排碧落層。", "孤峯磬聲絕，一點石龕燈。"]'),
('948ca68b-3617-4024-ae29-dbc18fe6c9b7','池上感興','齊己','唐','唐诗','tang','','[]','所向似無端，風前吟凭欄。',48,'全唐诗/poet.tang.46000.json','["所向似無端，風前吟凭欄。", "旁人應悶見，片水自閑看。", "碧底紅鱗鬣，澄邊白羽翰。", "南山衆木葉，飄著竹聲乾。"]'),
('44e94f48-009f-4fb2-adc0-b1d00643e339','和曇域上人寄贈之什','齊己','唐','唐诗','tang','','[]','百病煎衰朽，栖遲戰國中。',48,'全唐诗/poet.tang.46000.json','["百病煎衰朽，栖遲戰國中。", "思量青壁寺，行坐赤松風。", "道寄虛無合，書傳往復空。", "可憐禪月子，香火國門東。"]'),
('6e1d9deb-7fc0-48cc-a171-49c863272e7f','弔雙泉大師真塔','齊己','唐','唐诗','tang','','[]','塔聳層峯後，碑鐫巨石新。',48,'全唐诗/poet.tang.46000.json','["塔聳層峯後，碑鐫巨石新。", "不知將一句，分付與何人。", "靜坐雲生衲，空山月照真。", "後徒遊禮者，猶認指迷津。"]'),
('1794b283-41e7-4702-88e1-5c860a22a789','暮冬送璘上人歸華容','齊己','唐','唐诗','tang','','[]','故園雖不遠，那免愴行思。',48,'全唐诗/poet.tang.46000.json','["故園雖不遠，那免愴行思。", "莽蒼平湖路，霏微過雪時。", "全無山阻隔，或有客相隨。", "得見交親後，春風動柳絲。"]'),
('152831ca-dab0-4b8a-b7ed-8d20355baf49','秋夜聽業上人彈琴','齊己','唐','唐诗','tang','','[]','萬物都寂寂，堪聞彈正聲。',48,'全唐诗/poet.tang.46000.json','["萬物都寂寂，堪聞彈正聲。", "人心盡如此，天下自和平。", "湘水瀉秋碧，古風吹太清。", "往年廬岳奏，今夕更分明。"]'),
('2fb49f22-8daa-4b6e-8cd8-23d72739097d','謝人惠丹藥','齊己','唐','唐诗','tang','','[]','別後聞餐餌，相逢訝道情。',48,'全唐诗/poet.tang.46000.json','["別後聞餐餌，相逢訝道情。", "肌膚紅色透，髭髮黑光生。", "仙洞誰傳與，松房自鍊成。", "常蒙遠分惠，亦覺骨毛輕。"]'),
('392d77ac-1557-47b7-805a-dc99da4709c4','荆門病中寄懷貫微上人','齊己','唐','唐诗','tang','','[]','我衰君亦老，相憶更何言。',48,'全唐诗/poet.tang.46000.json','["我衰君亦老，相憶更何言。", "除泥安禪力，難醫必死根。", "梅寒爭雪彩，日冷讓冰痕。", "早晚東歸去，同尋入石門。"]'),
('74c0a9a1-1ba2-4818-94da-b5ec78b987d2','荅孔秀才','齊己','唐','唐诗','tang','','[]','早向文章裏，能降少壯心。',48,'全唐诗/poet.tang.46000.json','["早向文章裏，能降少壯心。", "不愁人不愛，閑處自閑吟。", "水國雲雷闊，僧園竹樹深。", "無嫌我衰颯，時此一相尋。"]'),
('fa544607-7279-4af0-9c66-d2e6fea02338','秋江','齊己','唐','唐诗','tang','','[]','兩岸山青映，中流一櫂聲。',48,'全唐诗/poet.tang.46000.json','["兩岸山青映，中流一櫂聲。", "遠無風浪動，正向夕陽橫。", "島嶼蟬分宿，沙洲客獨行。", "浩然心自合，何必濯吾纓。"]'),
('cce648a4-bcec-4232-a9bf-75e9634228ed','船窗','齊己','唐','唐诗','tang','','[]','孤舸凭幽窗，清波逼面涼。',48,'全唐诗/poet.tang.46000.json','["孤舸凭幽窗，清波逼面涼。", "舉頭還有礙，低眼即無妨。", "瞥過沙禽翠，斜分夕照光。", "何時到山寺，上閣看江鄉。"]'),
('22ebe39f-2753-4b30-a85e-e56ca9811756','永夜','齊己','唐','唐诗','tang','','[]','永日還欹枕，良宵亦曲肱。',48,'全唐诗/poet.tang.46000.json','["永日還欹枕，良宵亦曲肱。", "神閑無萬慮，壁冷有殘燈。", "香影浮龕象，瓶聲著井冰。", "尋思到何處，海上斷崖僧。"]'),
('b7b91fd7-4e72-4b2b-ab60-6be500d1d4eb','中春愴懷寄二三知己','齊己','唐','唐诗','tang','','[]','眼暗心還白，逢春強凭欄。',48,'全唐诗/poet.tang.46000.json','["眼暗心還白，逢春強凭欄。", "因聞積雨夜，却憶舊山寒。", "竹撼煙叢滑，花燒露朵乾。", "故人相會處，應話此衰殘。"]'),
('e92c4c40-9641-43d1-b9cc-11fc47b7b6ad','自遣','齊己','唐','唐诗','tang','','[]','了然知是夢，既覺更何求。',48,'全唐诗/poet.tang.46000.json','["了然知是夢，既覺更何求。", "死入孤峯去，灰飛一燼休。", "雲無空碧在，天靜月華流。", "免有諸徒弟，時來弔石頭。"]'),
('bff83ec9-9cc9-44a9-bba2-8259bb620777','送陳霸歸閩','齊己','唐','唐诗','tang','','[]','涼風動行興，含笑話臨途。',48,'全唐诗/poet.tang.46000.json','["涼風動行興，含笑話臨途。", "已得身名了，全忘客道孤。", "鄉程過百越，帆影遶重湖。", "家在飛鴻外，音書可寄無。"]'),
('4fd69186-f20c-4167-a41b-664f52ccf641','寄孫闢呈鄭谷郎中','齊己','唐','唐诗','tang','','[]','衡岳去都忘，清吟戀省郎。',48,'全唐诗/poet.tang.46000.json','["衡岳去都忘，清吟戀省郎。", "淹留才半月，詶唱頗盈箱。", "雪長松檉格，茶添語話香。", "因論樂安子，年少老篇章。"]'),
('96f14a05-6a78-4201-b3d9-87338e18f5fc','荆門送人自峨嵋游南岳','齊己','唐','唐诗','tang','','[]','峨嵋來已遠，衡岳去猶賒。',48,'全唐诗/poet.tang.46000.json','["峨嵋來已遠，衡岳去猶賒。", "南浦懸帆影，西風亂荻花。", "天涯遙夢澤，山衆近長沙。", "有興多新作，攜將大府誇。"]'),
('82ff5bbe-c3a1-4023-81df-a370a1af1d02','謝主人石筍','齊己','唐','唐诗','tang','','[]','西園罷宴遊，東閣念林丘。',48,'全唐诗/poet.tang.46000.json','["西園罷宴遊，東閣念林丘。", "特減花邊峭，來添竹裏幽。", "憶過陽朔見，曾記大湖求。", "從此頻吟遶，歸山意亦休。"]'),
('669c9314-fa46-408b-96f8-2317c6f9c236','經安公寺','齊己','唐','唐诗','tang','','[]','大聖威靈地，安公宴坐蹤。',48,'全唐诗/poet.tang.46000.json','["大聖威靈地，安公宴坐蹤。", "未知長寂默，不見久從容。", "塔影高羣木，江聲壓暮鐘。", "此遊幽勝後，來夢亦應重。"]'),
('67cd8fb5-67b3-41b4-b574-3f75822417e2','秋夕寄諸姪','齊己','唐','唐诗','tang','','[]','每到秋殘夜，燈前憶故鄉。',48,'全唐诗/poet.tang.46000.json','["每到秋殘夜，燈前憶故鄉。", "園林紅橘柚，窗戶碧瀟湘。", "離別身垂老，艱難路去長。", "弟兄應健在，兵火裏耕桑。"]'),
('bbdaba64-df70-46b8-8d8b-182386c9bb5e','謝炭','齊己','唐','唐诗','tang','','[]','正擁寒灰次，何當惠寂寥。',48,'全唐诗/poet.tang.46000.json','["正擁寒灰次，何當惠寂寥。", "且留連夜向，未敢滿爐燒。", "必恐吞難盡，唯愁撥易消。", "豪家揑爲獸，紅迸錦茵焦。"]'),
('648c2705-316b-470c-b16b-6ddb45d96b05','夏滿日偶作寄孫支使','齊己','唐','唐诗','tang','','[]','一百二十日，煎熬幾不勝。',48,'全唐诗/poet.tang.46000.json','["一百二十日，煎熬幾不勝。", "憶歸滄海寺，冷倚翠崖稜。", "舊扇猶操執，新秋更鬱蒸。", "何當見涼月，擁衲訪詩朋。"]'),
('23c54279-e6c7-4ada-a770-a98fc35fcef9','寄清溪道友','齊己','唐','唐诗','tang','','[]','山門搖落空，霜霰滿杉松。',48,'全唐诗/poet.tang.46000.json','["山門搖落空，霜霰滿杉松。", "明月行禪處，青苔遶石重。", "泉聲喧萬壑，鐘韻遍千峯。", "終去焚香老，同師大士蹤。"]'),
('ba2501bc-0f53-4b64-abae-ab3a569981f9','謝重緣舊山水障子','齊己','唐','唐诗','tang','','[]','敢望重緣飾，微茫洞壑春。',48,'全唐诗/poet.tang.46000.json','["敢望重緣飾，微茫洞壑春。", "坐看終未是，歸臥始應真。", "已覺心中朽，猶憐四面新。", "不因公子鑒，零落幾成塵。"]'),
('6701e0f4-a46d-4db4-91d0-e76d7d653eaf','寺居','齊己','唐','唐诗','tang','','[]','鄰井雙梧上，一蟬鳴隔牆。',48,'全唐诗/poet.tang.46000.json','["鄰井雙梧上，一蟬鳴隔牆。", "依稀舊林日，撩亂遶山堂。", "難嘿吟風口，終清飲露腸。", "老僧加護物，應任噪殘陽。"]'),
('d324f8f0-34f3-4a6f-994c-f53f79ccec07','剃髮','齊己','唐','唐诗','tang','','[]','金刀閃冷光，一剃一清涼。',48,'全唐诗/poet.tang.46000.json','["金刀閃冷光，一剃一清涼。", "未免隨朝夕，依前長雪霜。", "夏林欹石膩，春澗水泉香。", "向老凋疎盡，寒天不出房。"]'),
('4e723e3e-07c8-425e-b28f-2d12a7276728','謝高輦先輩寄新唱和集','齊己','唐','唐诗','tang','','[]','敢謂神仙手，多懷老比丘。',48,'全唐诗/poet.tang.46000.json','["敢謂神仙手，多懷老比丘。", "編聯來鹿野，酬唱在龍樓。", "洛浦精靈懾，邙山鬼魅愁。", "二南風雅道，從此化東周。"]'),
('8abd48a4-f65e-4fbe-a8fa-28e44ed11f51','送徐秀才遊吳國','齊己','唐','唐诗','tang','','[]','西江東注急，孤櫂若流星。',48,'全唐诗/poet.tang.46000.json','["西江東注急，孤櫂若流星。", "風浪相隨白，雲中獨過青。", "他時誰共說，此路我曾經。", "好向吳朝看，衣冠盡漢庭。"]'),
('45361806-b765-4352-b4dc-1ed6c8270756','憶在匡廬日','齊己','唐','唐诗','tang','','["\u5e90\u5c71"]','憶在匡廬日，秋風八月時。',48,'全唐诗/poet.tang.46000.json','["憶在匡廬日，秋風八月時。", "松聲虎溪寺，塔影雁門師。", "步碧葳蕤徑，吟香菡萏池。", "何當舊泉石，歸去洗心脾。"]'),
('c30560bc-7750-4783-9978-e8e89f1c27e2','寄三覺山從益上人','齊己','唐','唐诗','tang','','[]','山下人來說，多時不下山。',48,'全唐诗/poet.tang.46000.json','["山下人來說，多時不下山。", "是應終未是，閑得且須閑。", "海面雲歸竇，猿邊月上關。", "尋思亂峯頂，空送衲僧還。"]'),
('01d5570f-d796-4845-a25d-d730a11edd8c','殘秋感愴','齊己','唐','唐诗','tang','','[]','日日加衰病，心心趣寂寥。',48,'全唐诗/poet.tang.46000.json','["日日加衰病，心心趣寂寥。", "殘陽起閑望，萬木聳寒條。", "楚寺新爲客，吳江舊看潮。", "此懷何以寄，風雨暮蕭蕭。"]'),
('1581cbba-e5bf-442a-99c0-6b32b460d156','寄南徐劉員外二首 一','齊己','唐','唐诗','tang','','[]','竟陵兵革際，歸復舊園林。',48,'全唐诗/poet.tang.46000.json','["竟陵兵革際，歸復舊園林。", "早歲爲官苦，常聞說此心。", "海邊山夜上，城外寺秋尋。", "應訝嵩峯約，蹉跎直到今。"]'),
('f502be35-ca22-462c-964c-886f013e83a6','寄南徐劉員外二首 二','齊己','唐','唐诗','tang','','[]','晝公評衆製，姚監選諸文。',48,'全唐诗/poet.tang.46000.json','["晝公評衆製，姚監選諸文。", "風雅誰收我，編聯獨有君。", "餘生終此道，萬事盡浮雲。", "爭得重攜手，探幽楚水濆。"]'),
('03ef0aad-9a57-4c64-8df5-fdf43435f902','貽王秀才','齊己','唐','唐诗','tang','','[]','功到難搜處，知難始是詩。',48,'全唐诗/poet.tang.46000.json','["功到難搜處，知難始是詩。", "自能探虎子，何慮屈男兒。", "此道真清氣，前賢早白髭。", "須教至公手，不惜付丹枝。"]'),
('599a982e-ea9a-48fb-8746-f377418bb0bd','贈孫生','齊己','唐','唐诗','tang','','[]','見君詩自別，君是繼詩人。',48,'全唐诗/poet.tang.46000.json','["見君詩自別，君是繼詩人。", "道出千途外，功爭一字新。", "寂寥中影跡，霜雪裏精神。", "待折東堂桂，歸來更苦辛。"]'),
('1b05d5f8-7ee4-4a3b-a078-dbad34de57c9','酬元員外','齊己','唐','唐诗','tang','','[]','清洛碧嵩根，寒流白照門。',48,'全唐诗/poet.tang.46000.json','["清洛碧嵩根，寒流白照門。", "園林經難別，桃李幾株存。", "衰老江南日，淒涼海上村。", "閑來曬朱紱，淚滴舊朝恩。"]'),
('7273a215-4def-4ca0-8c64-8ccc88f8c9d9','與楊秀才話別','齊己','唐','唐诗','tang','','[]','庾信哀何極，仲宣悲苦多。',48,'全唐诗/poet.tang.46000.json','["庾信哀何極，仲宣悲苦多。", "因思學文賦，不勝弄干戈。", "自古有如此，於今終若何。", "到頭重策蹇，歸去舊煙蘿。"]'),
('dd9dbb48-520e-4ca8-9862-61096cac69ab','寄何崇丘員外','齊己','唐','唐诗','tang','','[]','門底桃源水，涵空復映山。',48,'全唐诗/poet.tang.46000.json','["門底桃源水，涵空復映山。", "高吟煙雨霽，殘日郡樓間。", "變俗真無事，分題是不閑。", "尋思章岸見，全未有年顏。"]'),
('e0a29abb-56b7-4f93-b3d5-4c9f3ca1099f','贈劉五經','齊己','唐','唐诗','tang','','[]','往年長白山，發憤忍飢寒。',48,'全唐诗/poet.tang.46000.json','["往年長白山，發憤忍飢寒。", "埽葉雪霜濕，讀書脣齒乾。", "羣經通講解，八十尚輕安。", "今日江南寺，相逢話世難。"]'),
('ce8b068d-a17f-426f-9378-d2e18c286121','送游山道者','齊己','唐','唐诗','tang','','[]','我亦遊山者，常經舊所經。',48,'全唐诗/poet.tang.46000.json','["我亦遊山者，常經舊所經。", "雪消天外碧，春曉海中青。", "可見亂離世，況臨衰病形。", "憐君此行興，獨入白雲屏。"]'),
('fd55629a-3965-48d8-a6be-0cc313488900','舟中江上望玉梁山懷李尊師','齊己','唐','唐诗','tang','','[]','殘照玉梁巔，峨峨遠櫂前。',48,'全唐诗/poet.tang.46000.json','["殘照玉梁巔，峨峨遠櫂前。", "古來傳勝異，人去學神仙。", "白鹿老碧壑，黃猨啼紫煙。", "誰心共無事，局上度流年。"]'),
('36f66970-f369-4a07-bbe4-aabe9be62d75','角','齊己','唐','唐诗','tang','','[]','聞說征人說，嗚嗚何處邊。',48,'全唐诗/poet.tang.46000.json','["聞說征人說，嗚嗚何處邊。", "孤城沙塞地，殘月雪霜天。", "會轉胡風急，吹長磧雁連。", "應傷漢車騎，名未勒燕然。"]'),
('82e63e98-5564-4742-8810-f902ad1555ff','言詩','齊己','唐','唐诗','tang','','[]','畢竟將何狀，根元在正思。',48,'全唐诗/poet.tang.46000.json','["畢竟將何狀，根元在正思。", "達人皆一貫，迷者自多岐。", "觸類風騷遠，懷賢肺腑衰。", "河橋送別者，二子好相知。"]'),
('055c6836-9f71-479c-a5c3-a6135bc0b616','詶王秀才','齊己','唐','唐诗','tang','','[]','離亂幾時休，儒生厄遠遊。',48,'全唐诗/poet.tang.46000.json','["離亂幾時休，儒生厄遠遊。", "亡家非漢代，何處覓荆州？", "旅夢寒燈屋，鄉懷晝雨樓。", "相逢話相殺，誰復念風流。"]'),
('8812736e-d0b8-4afb-abff-bc004ae316b5','春居寄友生','齊己','唐','唐诗','tang','','[]','莎徑荒蕪甚，君應共此情。',48,'全唐诗/poet.tang.46000.json','["莎徑荒蕪甚，君應共此情。", "江村雷雨發，竹屋夢魂驚。", "社過多來燕，花繁漸老鶯。", "相思意何切，新作未曾評。"]'),
('f7ddb088-42f3-4eb4-ab5a-598a104bafd0','寄荅武陵幕中何支使二首 一','齊己','唐','唐诗','tang','','[]','十萬雄軍幕，三千上客才。',48,'全唐诗/poet.tang.46000.json','["十萬雄軍幕，三千上客才。", "何當談笑外，遠慰寂寥來。", "騷雅鏘金擲，風流醉玉頹。", "爭知江雪寺，老病向寒灰。"]'),
('fec96228-ff9b-4e87-81d9-28f379ca5ae4','寄荅武陵幕中何支使二首 二','齊己','唐','唐诗','tang','','[]','南州無百戰，北地有長征。',48,'全唐诗/poet.tang.46000.json','["南州無百戰，北地有長征。", "閑殺何從事，傷哉蘇子卿。", "江樓聯雪句，野寺看春耕。", "門外滄浪水，風波雜雨聲。"]'),
('d51da6c9-30dc-4a0d-82e1-9a6aac04d656','浙江晚渡','齊己','唐','唐诗','tang','','[]','去年曾到此，久立滯前程。',48,'全唐诗/poet.tang.46000.json','["去年曾到此，久立滯前程。", "岐路時難處，風濤晚未平。", "汀蟬含老韻，岸荻簇枯聲。", "莫泥關河險，多遊自遠行。"]'),
('f1a6e436-4bcc-44f5-9319-98896320e8f4','送人下第東歸再謁舊主人','齊己','唐','唐诗','tang','','[]','一戰偶不捷，東歸計未空。',48,'全唐诗/poet.tang.46000.json','["一戰偶不捷，東歸計未空。", "還攜故書劒，去謁舊英雄。", "楚雪連吳樹，西江正北風。", "男兒藝若是，會合值明公。"]'),
('8c0b7acb-8cbb-403d-8771-2514a59e6a8e','寄謝高先輩見寄二首 一','齊己','唐','唐诗','tang','','[]','穿鑿堪傷骨，風騷久痛心。',48,'全唐诗/poet.tang.46000.json','["穿鑿堪傷骨，風騷久痛心。", "永言無絕唱，忽此惠希音。", "楊柳江湖晚，芙蓉島嶼深。", "何因會仙手，臨水一披襟。"]'),
('f2dffbed-74b9-43b3-95d1-2ac08382a0bf','寄謝高先輩見寄二首 二','齊己','唐','唐诗','tang','','[]','詩在混茫前，難搜到極玄。',48,'全唐诗/poet.tang.46000.json','["詩在混茫前，難搜到極玄。", "有時還積思，度歲未終篇。", "片月雙松際，高樓闊水邊。", "前賢多此得，風味若爲傳。"]'),
('0899174e-5bcd-4da2-b165-61f707eaaa2d','寄仰山光味長者','齊己','唐','唐诗','tang','','[]','大仰禪棲處，杉松到頂陰。',48,'全唐诗/poet.tang.46000.json','["大仰禪棲處，杉松到頂陰。", "下來雖有路，歸去每無心。", "鳥道峯形直，龍湫石影深。", "徑行誰得見，半夜老猨吟。"]'),
('ee460ced-cba8-476e-aaa1-59cd7c7cc6cf','貽廬岳陳沆秀才','齊己','唐','唐诗','tang','','[]','爲儒老雙鬢，勤苦竟何如。',48,'全唐诗/poet.tang.46000.json','["爲儒老雙鬢，勤苦竟何如。", "四海方磨劒，空山自讀書。", "石圍泉眼碧，秋落洞門虛。", "莫慮搜賢僻，徵君舊此居。"]'),
('926183c4-574b-44ff-9670-7c1c25309e5a','邊上','齊己','唐','唐诗','tang','','[]','漢地從休馬，胡家自牧羊。',48,'全唐诗/poet.tang.46000.json','["漢地從休馬，胡家自牧羊。", "都來銷帝道，渾不用兵防。", "草上孤城白，沙翻大漠黃。", "秋風起邊雁，一一向瀟湘。"]'),
('e0079db9-14ed-40cf-8baf-8f51a34942b2','蟋蟀','齊己','唐','唐诗','tang','','[]','聲異蟪蛄聲，聽須是正聽。',48,'全唐诗/poet.tang.46000.json','["聲異蟪蛄聲，聽須是正聽。", "無風來竹院，有月在莎庭。", "雖不妨調瑟，多堪伴誦經。", "誰人向秋夕，爲爾欲忘形。"]'),
('281ac260-3a09-4e4f-8b31-3b33d1e2c824','寄西山鄭谷神','齊己','唐','唐诗','tang','','[]','西望鄭先生，焚修在杳冥。',48,'全唐诗/poet.tang.46000.json','["西望鄭先生，焚修在杳冥。", "幾番松骨朽，未換鬢根青。", "石闕涼調瑟，秋壇夜拜星。", "俗人應撫掌，閑處誦黃庭。"]'),
('c8b8a440-0ea9-48e7-a815-55f9e3d7c601','讀參同契','齊己','唐','唐诗','tang','','[]','堪笑修仙侶，燒金覓大還。',48,'全唐诗/poet.tang.46000.json','["堪笑修仙侶，燒金覓大還。", "不知消息火，只在寂寥關。", "鬢白爐中術，魂飛海上山。", "悲哉五千字，無用在人間。"]'),
('9e371c3f-ccb6-46df-8612-3db2b1c33649','聞落葉','齊己','唐','唐诗','tang','','[]','楚樹雪晴後，蕭蕭落晚風。',48,'全唐诗/poet.tang.46000.json','["楚樹雪晴後，蕭蕭落晚風。", "因思故國夜，臨水幾株空。", "煮茗燒乾脆，行苔踏爛紅。", "來年未離此，還見碧叢叢。"]'),
('c90bf8d3-9cf6-4526-a406-8f76cc3afb11','謝王先輩昆弟遊湘中迴各見示新詩','齊己','唐','唐诗','tang','','[]','瀟湘多勝異，宗社久裴回。',48,'全唐诗/poet.tang.46000.json','["瀟湘多勝異，宗社久裴回。", "兄弟同遊去，幽奇盡采來。", "只應求妙唱，何以示寒灰。", "上國攜歸後，唯呈不世才。"]');
